const DATA =[{"id": 1, "set": 1, "opdracht_in_set": 1, "title": "‘s Avonds werken", "situatie": "U werkt in een winkel.\nEén keer in de week moet u een avond werken.\nUw baas wil dat u op vrijdagavond komt werken.\nU wilt het liefst op maandagavond werken.\nOvertuig uw baas ervan dat u op maandagavond wilt werken.\nGeef twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw baas en reageer.", "vraag": "WAAROM WIL JIJ PER SE OP MAANDAGAVOND WERKEN?", "antwoord": "Ik heb op vrijdagavond mijn sport.\nIk moet op vrijdagavond vroeg thuis zijn voor mijn kinderen.", "pages": [1, 2], "image": null}, {"id": 2, "set": 1, "opdracht_in_set": 2, "title": "Aan de beurt", "situatie": "U staat bij de bakker.\nNa u is een vrouw binnengekomen.\nDe verkoopster vraagt wie er aan de beurt is.\nDe vrouw zegt dat zij aan de beurt is.\nU bent het daar niet mee eens.\nWat zegt u tegen de vrouw?", "vraag": "", "antwoord": "Sorry, ik was eerst.", "pages": [3, 4], "image": null}, {"id": 3, "set": 1, "opdracht_in_set": 3, "title": "Activiteit schoolfeest", "situatie": "U werkt op een basisschool.\nDe school bestaat twintig jaar en viert feest.\nSamen met uw collega’s bedenkt u activiteiten voor het feest.\nU heeft een leuk idee voor het feest.\nKijk naar het plaatje.\nDoe een voorstel voor een activiteit voor op het feest.\nGebruik daarbij het plaatje.\nU hoort eerst een collega.", "vraag": "WAT STEL JIJ VOOR ACTIVITEIT VOOR?", "antwoord": "We kunnen de kinderen schminken.", "pages": [5, 6], "image": "images/img_003.png"}, {"id": 4, "set": 1, "opdracht_in_set": 4, "title": "Advies examen", "situatie": "U volgt een opleiding tot verzorgende.\nMorgen is er een examen.\nUw medestudent weet niet wat zij vanavond het best\nkan doen: vroeg naar bed gaan of studeren voor het examen.\nVertel uw medestudent wat zij volgens u het beste kan doen.\nVertel ook waarom u dat vindt.\nU hoort eerst uw medestudent.", "vraag": "WAT ZAL IK DOEN? ZAL IK VROEG GAAN SLAPEN OF ZAL IK NOG GAAN STUDEREN?", "antwoord": "Je kunt het beste vroeg naar bed gaan. Je moet morgen fit zijn.", "pages": [7, 8], "image": null}, {"id": 5, "set": 1, "opdracht_in_set": 5, "title": "Advies over studie", "situatie": "Een vriendin van u wil een mbo-opleiding voor\ntandartsassistent gaan volgen.\nZe twijfelt of ze deze opleiding thuis op de computer of in een\nklas op school wil volgen.\nGeef uw vriendin advies over hoe zij de opleiding het best kan\ngaan volgen.\nNoem hierbij twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw vriendin en reageer.", "vraag": "HOE KAN IK HET BESTE DE OPLEIOING TANDARTSASSISTENTE GAAN VOLGEN? THUIS OF IN EEN KLAS?", "antwoord": "Je kunt het beste de opieiding online doen.\nJe hebt geen reistijd. En het is ook goedkoper.", "pages": [9, 10], "image": null}, {"id": 6, "set": 1, "opdracht_in_set": 6, "title": "Agenda", "situatie": "U gaat starten met een nieuwe opleiding.\nU hebt voor uw opleiding een agenda nodig.\nU kunt een papieren agenda kopen of de agenda op uw telefoon\ngebruiken.\nEen medestudent vraagt wat u kiest.\nVertel uw medestudent welk soort agenda u kiest.\nVertel ook waarom u die agenda kiest.\nU hoort eerst uw medestudent.", "vraag": "WAT KIES JIJ? EEN PAPIEREN AGENDA OF DE AGENDA OP JE TELEFOON?", "antwoord": "Ik kies de agenda op mijn telefoon. Ik heb mijn telefoon\naltijd bij mij.", "pages": [11, 12], "image": null}, {"id": 7, "set": 1, "opdracht_in_set": 7, "title": "Andere afdeling", "situatie": "U werkt in een ziekenhuis.\nU moet op een andere afdeling gaan werken.\nUw leidinggevende vraagt aan u op welke afdeling u het liefst\nwilt werken.\nKijk naar de plaatjes.\nVertel uw leidinggevende op welke afdeling u het liefst wilt\nwerken.\nVertel ook waarom.", "vraag": "WIJ HEBBEN NOG EEN FUNCTIE OP DE KINDERAFDELING EN OP DE EERSTE HULP. WAAR WIL JIJ HET LIEFSTE WERKEN?", "antwoord": "Ik wil het liefst werken op de kinderafdeling.\nIk houd van kinderen.", "pages": [13, 14], "image": "images/img_007.png"}, {"id": 8, "set": 1, "opdracht_in_set": 8, "title": "Auto en werk", "situatie": "Het is in Nederland vaak druk op de snelwegen.\nToch gaan veel mensen met de auto naar hun werk.\nWat vindt u ervan dat mensen met de auto naar hun werk gaan?\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind het stom dat mensen met de auto naar hun werk gaan.\nZij verliezen tijd in de file.", "pages": [15, 16], "image": null}, {"id": 9, "set": 1, "opdracht_in_set": 9, "title": "Auto kopen", "situatie": "U wilt een nieuwe auto kopen.\nU praat met de verkoper.\nHij wil weten wat u belangrijk vindt bij een nieuwe auto.\nVertel wat u belangrijk vindt.\nNoem drie dingen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar de verkoper en reageer.", "vraag": "WAT VINDT U BELANGRIJK VOOR UW NIEUWE AUTO?", "antwoord": "Ik vind de kleur belangrijk. Ik vind de prijs ook belangrijk.\nEn de auto moet elektrisch zijn.", "pages": [17, 18], "image": null}, {"id": 10, "set": 1, "opdracht_in_set": 10, "title": "Auto met reclame", "situatie": "U werkt in groentewinkel De groentespecialist.\nUw baas wil graag meer reclame maken.\nDaarvoor wil hij de eigen auto's van de medewerkers gebruiken.\nUw collega vraagt wat u van dit plan vindt.\nKijk naar het plaatje.\nVertel uw collega wat u van dit plan vindt.", "vraag": "WAT VIND JIJ VAN HET NIEUWE PLAN VAN DE BAAS?", "antwoord": "Ik vind het plan van de baas prima. De auto wordt heel mooi.\nEn wil krijgen ook extra geld van de baas.", "pages": [19, 20], "image": "images/img_010.png"}, {"id": 11, "set": 1, "opdracht_in_set": 11, "title": "Auto of trein", "situatie": "Hoe reist u liever, met de auto of met de trein?\nVertel hoe u liever reist.\nGeef één reden.", "vraag": "", "antwoord": "Ik rels liever met de trein. Dat is beter voor het milieu.", "pages": [21, 22], "image": null}, {"id": 12, "set": 1, "opdracht_in_set": 12, "title": "Auto of vliegtuig?", "situatie": "Uw buurman wil met zijn gezin op vakantie naar Marokko.\nHij weet niet of hij met de auto zal gaan of met het vliegtuig.\nHij vraagt uw advies.\nVertel uw buurman wat hij volgens u het beste kan doen.\nVertel ook waarom u dat vindt.\nGeef tenminste twee redenen.\nU krijgt eerst tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw buurman en reageer.", "vraag": "WAT LIJKT JOU HET BESTE? MET DE AUTO GAAN, OF MET HET VLIEGTUIG?", "antwoord": "Je kunt beter met het vliegtuig.\nHet vliegtuig is snel en vliegen naar Marokko is niet duur.", "pages": [23, 24], "image": null}, {"id": 13, "set": 2, "opdracht_in_set": 1, "title": "Baan aangeboden", "situatie": "Uw medestudent loopt stage bij een bouwbedrijf.\nZijn opleiding duurt nog een jaar.\nZijn baas biedt hem een baan aan.\nUw medestudent vraagt wat hij zal doen: de baan aannemen of\neerst zijn opleiding afmaken.\nVertel uw medestudent wat hij volgens u het beste kan doen.\nVertel ook waarom u dat vindt.\nU hoort eerst uw medestudent.", "vraag": "MIJN STAGEBEDRIJF HEEFT MIJ EEN BAAN AANGEBODEN. ZAL IK HEM AANNEMEN OF ZAL IK EERST MIJN OPLEIDING AFMAKEN?", "antwoord": "Je kunt het beste de opleiding afmaken.\nJe kunt later een goele baan krijgen.", "pages": [25, 26], "image": null}, {"id": 14, "set": 2, "opdracht_in_set": 2, "title": "Baby’s knippen", "situatie": "U volgt een mbo-opleiding voor kapper.\nVorige week hebt u geoefend met het knippen van baby’s.\nDe docent heeft adviezen gegeven om baby’s stil te laten zitten\ntijdens het knippen.\nUw medestudent heeft de les van vorige week gemist.\nZij vraagt hoe ze kan zorgen dat baby’s stilzitten tijdens het\nknippen.\nKijk naar de plaatjes.\nVertel uw medestudent hoe ze kan zorgen dat baby’s stilzitten\nGebruik hierbij alle plaatjes.\nU hoort eerst uw medestudent.", "vraag": "LIJKT ME LASTIG HOOR, BABY’S KNIPPEN. HOE KUN JE ERVOOR ZORGEN DAT ZE STIL BLIJVEN ZITTEN?", "antwoord": "Je kunt een baby in een speciale stoel zetten.\nJe kunt de baby naar een filmpje laten kijken.\nJe kunt de baby op de schoot van de moeder zetten.", "pages": [27, 28], "image": "images/img_014.png"}, {"id": 15, "set": 2, "opdracht_in_set": 3, "title": "Badmeester", "situatie": "U bent badmeester.\nVandaag komt er een nieuwe collega.\nDe collega vraagt wat hij moet doen.\nKijk naar het plaatje.\nLeg aan uw collega uit wat hij moet doen.\nU hoort eerst uw collega.", "vraag": "WAAR MOET IK MEE BEGINNEN?", "antwoord": "Je moet eerst de bladeren ult het zwembad halen.", "pages": [29, 30], "image": "images/img_015.png"}, {"id": 16, "set": 2, "opdracht_in_set": 4, "title": "Bakkersopleiding", "situatie": "U volgt een opleiding tot bakker.\nAls huiswerk voor vandaag moest u een taart bakken.\nU hebt de taart niet mee naar school genomen.\nKijk naar het plaatje.\nLuister naar uw docent en reageer.", "vraag": "WAAROM HEB JE GEEN TAART MEEGENOMEN?", "antwoord": "Mijn kind heeft van de taart gegeten.", "pages": [31, 32], "image": "images/img_016.png"}, {"id": 17, "set": 2, "opdracht_in_set": 5, "title": "Bedrijfsbezoek mode-opleiding", "situatie": "U volgt een modeopleiding.\nVoor het vak ‘Leren in de praktijk’ moet u samen met een\nmedestudent een bedrijfsbezoek organiseren voor de hele klas.\nU stelt voor om een werkplaats van een modeontwerper te\nbezoeken.\nUw medestudent twijfelt of dat een goed idee is.\nOvertuig uw medestudent ervan om voor het bedrijfsbezoek\nnaar een werkplaats van een modeontwerper te gaan.\nGeef twee argumenten.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medestudent en reageer.", "vraag": "WAAROM VIND JE EEN WERKPLAATS VAN EEN MODEONTWERPER GESCHIKT?", "antwoord": "We kunnen in de werkplaats zien hoe mensen werken.\nWe kunnen daar zelf ook werk zoeken.", "pages": [33, 34], "image": null}, {"id": 18, "set": 2, "opdracht_in_set": 6, "title": "Bedrijfspand verlaten", "situatie": "U geeft trainingen in bedrijfsbeveiliging.\nU gaat vandaag aan de werknemers van een bedrijf uitleggen\nhoe mensen een bedrijfspand moeten verlaten als er brand is.\nKijk naar de plaatjes.\nLeg de cursisten uit wat ze moeten doen als er brand is in hun\nbedrijf.", "vraag": "", "antwoord": "Je moet 1-1-2 bellen. Je moet via de trap naar beneden gaan.\nJe moet rustig naar een nooduitgang gaan.", "pages": [35, 36], "image": "images/img_018.png"}, {"id": 19, "set": 2, "opdracht_in_set": 7, "title": "Begeleider jongerencentrum", "situatie": "U werkt als begeleider in een jongerencentrum.\nEen kennis vraagt welke taken u daar hebt.\nKijk naar de plaatjes.\nVertel de kennis welk soort taken u doet.\nU moet daarbij alle plaatjes gebruiken.\nU hoort eerst de kennis.", "vraag": "EEN JONGERENCENTRUM, WAT INTERESSANT, WAT DOE JE DAAR PRECIES?", "antwoord": "Ik geef kooklessen. Ik help met bankzaken op de computer.\nIk leer hoe je de was moet doen.", "pages": [37, 38], "image": "images/img_019.png"}, {"id": 20, "set": 2, "opdracht_in_set": 8, "title": "Beginnende werknemers", "situatie": "Bedrijven in Nederland klagen vaak over beginnende\nwerknemers.\nZe vinden dat nieuwe werknemers niet goed zijn voorbereid\nop het werk.\nHoe kan dit probleem volgens u het beste worden opgelost?\nNoem twee oplossingen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Scholen moeten de opleiding verbeteren. Werknemers moeten\nIn het begin meer begeleiding krijgen van oudere werknemers\nmet ervaring.", "pages": [39, 40], "image": null}, {"id": 21, "set": 2, "opdracht_in_set": 9, "title": "Belangrijk aan een opleiding", "situatie": "U volgt een opleiding in de zorg.\nUw school wil de opleiding verbeteren.\nDe directeur vraagt daarom aan alle studenten wat ze\nbelangrijk vinden aan een opleiding.\nBeschrijf aan de directeur wat u belangrijk vindt aan een\nopleiding.\nBeschrijf twee dingen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar de directeur en reageer.", "vraag": "WAT VIND JIJ BELANGRIJK AAN EEN OPLEIDING?", "antwoord": "De docenten moeten goed zijn. Er moet ook een goede\nstageperiode zijn.", "pages": [41, 42], "image": null}, {"id": 22, "set": 2, "opdracht_in_set": 10, "title": "Belangrijk bij een huis", "situatie": "U woont in een oud huurhuis.\nUw huurbaas wil al zijn oude huurhuizen vervangen door\nnieuwe huurhuizen.\nHij wil graag van de bewoners weten wat ze belangrijk vinden\nbij een nieuw huis.\nVertel uw huurbaas wat u belangrijk vindt bij een huis.\nNoem drie dingen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar de huurbaas en reageer.", "vraag": "WAT VIND JIJ BELANGRIJK BIJ EEN HUIS?", "antwoord": "Het dak mag niet lek zijn. De ramen en deuren moeten goed\nstuiten. De verwarming moet zonder aardgas zijn.", "pages": [43, 44], "image": null}, {"id": 23, "set": 2, "opdracht_in_set": 11, "title": "Belangrijk in een buurt", "situatie": "U praat met een vriend over de buurt waar u woont.\nU bent niet zo tevreden met de buurt.\nU wilt graag verhuizen.\nUw vriend vraagt wat u belangrijk vindt in een buurt.\nVertel uw vriend wat u belangrijk vindt in een buurt.\nNoem twee dingen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw vriend en reageer.", "vraag": "WAT VIND JE BELANGRIJK IN EEN BUURT?", "antwoord": "Oe buurt moet kindvrlendelijk zijn. Er moeten winkels in\nde buurt zijn.", "pages": [45, 46], "image": null}, {"id": 24, "set": 2, "opdracht_in_set": 12, "title": "Beschrijving buurt", "situatie": "U praat met een vriend die u lang niet hebt gezien.\nUw vriend vraagt in wat voor soort buurt u nu woont.\nBeschrijf de buurt waarin u woont.\nBeschrijf drie dingen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw vriend en reageer.", "vraag": "IN WAT VOOR SOORT BUURT WOON JE NU?", "antwoord": "In mijn buurt wonen veel gezinnen met kleine kinderen.\nIn mijn buurt zijn veel auto's. In mijn buurt zijn niet veel\nwinkels.", "pages": [47, 48], "image": null}, {"id": 25, "set": 3, "opdracht_in_set": 1, "title": "Beveiliger vliegveld", "situatie": "U werkt als beveiliger op een vliegveld.\nU begeleidt een nieuwe collega op zijn eerste werkdag.\nU vertelt hem wat hij vandaag gaat doen.\nKijk naar de plaatjes.\nVertel uw collega wat hij vandaag gaat doen.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw collega.", "vraag": "NOU, IK HEB ER ZIN IN. WAT MOET IK VANDAAG DOEN?", "antwoord": "Je moet alle flessen ult de bagage halen.\nJe moet de bagage scannen.\nJe moet de koffers controleren.", "pages": [49, 50], "image": "images/img_025.png"}, {"id": 26, "set": 3, "opdracht_in_set": 2, "title": "Bewaker in museum", "situatie": "U werkt als bewaker in een museum.\nU zorgt ervoor dat bezoekers zich aan de regels houden.\nEen nieuwe collega vraagt waar hij op moet letten.\nKijk naar de plaatjes.\nVertel de collega waar hij op moet letten.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw collega.", "vraag": "WAAR MOET IK OP LETTEN, HIER IN HET MUSEUM?", "antwoord": "Oe bezoekers mogen niets aanraken.\nDe bezoekers mogen niet eten in het museum.\nDe bezoekers mogen niets op de grond gooien.", "pages": [51, 52], "image": "images/img_026.png"}, {"id": 27, "set": 3, "opdracht_in_set": 3, "title": "Bibliotheek", "situatie": "U volgt een opleiding.\nVandaag hebt u in de bibliotheek gewerkt.\nKijk naar het plaatje.\nLuister naar uw vriend en reageer.", "vraag": "HOE ZIET DIE BIBLIOTHEEK ER DAN UIT?", "antwoord": "Ja, in de bibliotheek zijn veel boeken.\nBezoekers kunnen daar aan tafels zitten.\nBezoekers kunnen daar ook computers gebrulken.", "pages": [53, 54], "image": "images/img_027.png"}, {"id": 28, "set": 3, "opdracht_in_set": 4, "title": "Bijeenkomst politiek", "situatie": "U volgt een mbo-opleiding.\nBinnenkort zijn er verkiezingen in uw gemeente.\nVoor het vak Politieke betrekkingen hebt u een opdracht\ngekregen over deze verkiezingen.\nUw medestudent was niet bij de les aanwezig.\nHij vraagt wat hij moet doen.\nKijk naar het plaatje.\nVertel uw medestudent wat hij moet doen.\nU hoort eerst uw medestudent.", "vraag": "WAT MOET IK VOOR DIE OPDRACHT OVER POLITIEK DOENT", "antwoord": "Je moet een verslag maken van een politieke meeting.", "pages": [55, 56], "image": "images/img_028.png"}, {"id": 29, "set": 3, "opdracht_in_set": 5, "title": "Binnen of buiten spelen", "situatie": "In Nederland spelen kinderen tegenwoordig vaak binnen.\nZe kijken veel TV of spelen met de computer.\nZe spelen niet zo vaak buiten.\nVertel wat u van deze ontwikkeling vindt.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind het prima, dat kinderen binnen spelen.\nBuiten zijn veel auto's, binnen is het veilig.", "pages": [57, 58], "image": null}, {"id": 30, "set": 3, "opdracht_in_set": 6, "title": "Bioscoop", "situatie": "In veel bioscopen in Nederland is er geen pauze tijdens de film.\nWat vindt u ervan dat er geen pauze is tijdens een film?\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind dat prima. Ik kan zonder eten en drinken naar\neen film kijken.", "pages": [59, 60], "image": null}, {"id": 31, "set": 3, "opdracht_in_set": 7, "title": "Bloemenwinkel", "situatie": "U werkt in een bloemenwinkel.\nVandaag komt er een nieuwe collega.\nU moet haar uitleggen wat ze moet doen.\nKijk naar de plaatjes.\nLuister naar uw collega en vertel haar welke drie dingen ze\nmoet doen.", "vraag": "NOU, ZEG MAAR WAT IK MOET DOEN.", "antwoord": "Je moet de bloemen afknippen.\nJe moet de bloemen inpakken.\nEn je moet de bloemen in een emmer zetten.", "pages": [61, 62], "image": "images/img_031.png"}, {"id": 32, "set": 3, "opdracht_in_set": 8, "title": "Boek niet aanwezig", "situatie": "U volgt een opleiding techniek.\nU moet als huiswerk het boek Basistechniek deel 2 bekijken.\nIn de bibliotheek is dat boek niet aanwezig.\nU gaat naar uw docente.\nLuister naar de docente en reageer.", "vraag": "JA, WAT IS ER? WIL JE IETS VRAGEN?", "antwoord": "Het boek Basistechniek is niet in de bibliotheek.\nWaar kan ik dat boek vinden?", "pages": [63, 64], "image": null}, {"id": 33, "set": 3, "opdracht_in_set": 9, "title": "Boek of geld?", "situatie": "U gaat naar een feest van een vriend.\nUw vriendin stelt voor om samen een cadeau te kopen.\nUw vriendin vraagt wat u het beste idee vindt: een boek geven\naan uw vriend of geld geven.\nVertel wat u het beste idee vindt.\nVertel ook waarom u dat vindt.\nU hoort eerst uw vriendin.", "vraag": "WAT ZULLEN WE DOEN? ZULLEN WE EEN BOEK GEVEN, OF GELD?", "antwoord": "We kunnen beter geld geven.\nOnze vriend leest geen boeken.", "pages": [65, 66], "image": null}, {"id": 34, "set": 3, "opdracht_in_set": 10, "title": "Boerderij", "situatie": "U werkt op een boerderij.\nUw buurjongen helpt in zijn vakantie mee op de boerderij.\nU vertelt hem wat hij moet doen.\nKijk naar de plaatjes.\nLuister naar uw buurjongen en reageer.\nGebruik de plaatjes.\nU hoort eerst uw buurjongen.", "vraag": "WAT MOET IK VANDAAG DOEN?", "antwoord": "Je moet de koeien eten geven.\nEn je moet de stal schoonmaken.", "pages": [67, 68], "image": "images/img_034.png"}, {"id": 35, "set": 3, "opdracht_in_set": 11, "title": "Boodschappen gedaan", "situatie": "Gisteren deed u boodschappen.\nEr gebeurde iets vervelends.\nU praat hierover met een vriendin.\nKijk naar het plaatje.\nVertel uw vriendin wat er gisteren gebeurd is.\nU hoort eerst uw vriendin.", "vraag": "WAT IS ER GISTEREN GEBEURD?", "antwoord": "De tas is kapot gegaan.\nDe boodschappen zijn op de grond gevalien.", "pages": [69, 70], "image": "images/img_035.png"}, {"id": 36, "set": 3, "opdracht_in_set": 12, "title": "Brandalarm", "situatie": "U volgt een opleiding.\nTijdens de les gaat het brandalarm af.\nIedereen moet het gebouw verlaten.\nUw medestudent weet niet wat hij moet doen.\nKijk naar de plaatjes.\nVertel uw medestudent wat hij moet doen.\nGebruik hierbij beide plaatjes.\nLuister naar uw medestudent en reageer.", "vraag": "OJEE, HET ALARM! WAT MOETEN WE DOEN?", "antwoord": "Je moet rustig naar beneden lopen.\nEn Je moet naar het verzamelpunt gaan.", "pages": [71, 72], "image": "images/img_036.png"}, {"id": 37, "set": 4, "opdracht_in_set": 1, "title": "Brommer gestolen", "situatie": "Uw brommer is gestolen.\nU meldt het bij de politie.\nDe politieagent vraagt hoe de brommer eruitziet.\nKijk naar het plaatje.\nVertel de politieagent hoe uw brommer eruitziet.\nNoem minstens twee dingen.\nU hoort eerst de politieagent.", "vraag": "HOE ZIET UW BROMMER ERUIT?", "antwoord": "De brommer is rood. De fietstassen zijn blauw.", "pages": [73, 74], "image": "images/img_037.png"}, {"id": 38, "set": 4, "opdracht_in_set": 2, "title": "Broodjes bestellen", "situatie": "U werkt bij een bakker.\nEen klant wil broodjes bestellen.\nKijk naar het plaatje.\nLuister naar de klant en reageer.", "vraag": "GOEDEMORGEN, IK WIL GRAAG TWEE BRUINE", "antwoord": "BROODJES MET KAAS EN 1 WIT BROODJE MET El.\nMijn collega heeft de belegde broodjes.", "pages": [75, 76], "image": "images/img_038.png"}, {"id": 39, "set": 4, "opdracht_in_set": 3, "title": "Broodjeszaak", "situatie": "U werkt in een broodjeszaak.\nU moet onverwacht weg.\nEen collega komt een uurtje voor u invallen.\nHij zal de klanten helpen.\nHij vraagt aan u wat hij nog meer moet doen.\nKijk naar de plaatjes.\nVertel de collega wat hij moet doen.\nU moet daarbij alle plaatjes gebruiken.\nU hoort eerst de collega.", "vraag": "OKE, WAT MOET IK NOG MEER DOEN, BEHALVE DE KLANTEN HELPEN?", "antwoord": "Je moet kaas op de broodjes doen. Je moet broden sorteren.\nEn je moet afval weggoolen.", "pages": [77, 78], "image": "images/img_039.png"}, {"id": 40, "set": 4, "opdracht_in_set": 4, "title": "Bruiloft", "situatie": "U was gisteren op een bruiloft.\nEr gingen een paar dingen niet goed.\nEen vriendin vraagt wat er niet goed ging.\nKijk naar de plaatjes.\nVertel uw vriendin wat er niet goed ging.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw vriendin", "vraag": "WAT VERVELEND ZEG, WAT GING ER DAN NIET GOED?", "antwoord": "Twee honden maakten de versiering kapot.\nHet eten viel op de grond. En er kwam veel regen en wind.", "pages": [79, 80], "image": "images/img_040.png"}, {"id": 41, "set": 4, "opdracht_in_set": 5, "title": "Buiten sporten", "situatie": "U bent op school.\nVandaag gaat u met de klas buiten sporten.\nBuiten regent het.\nEen medestudent kijkt niet blij.\nHij hoopt dat de les niet doorgaat.\nU vindt dat het buiten sporten door moet gaan.\nOvertuig uw medestudent ervan dat het buiten sporten wel\ndoor moet gaan.\nGeef hiervoor twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medestudent en reageer.", "vraag": "HET REGENT. IK HOOP DAT DE LES NIET DOORGAAT.", "antwoord": "Buiten sporten is altijd gezond.\nNa het sporten kun Je droge kleding aandoen.", "pages": [81, 82], "image": null}, {"id": 42, "set": 4, "opdracht_in_set": 6, "title": "Café afsluiten", "situatie": "U werkt in een café.\nU hebt een nieuwe collega.\nAan het eind van de dag sluit u samen met de collega het café af.\nKijk naar het plaatje.\nVertel uw nieuwe collega wat hij moet doen.\nU hoort eerst uw collega.", "vraag": "WAT MOET IK DOEN?", "antwoord": "Jij moet de vioer vegen, dat is alles.", "pages": [83, 84], "image": "images/img_042.png"}, {"id": 43, "set": 4, "opdracht_in_set": 7, "title": "Cement", "situatie": "U werkt in de bouw.\nU hebt een nieuwe collega.\nHij helpt u vandaag.\nKijk naar de plaatjes.\nVertel uw collega wat hij moet doen\nU moet daarbij alle plaatjes gebruiken.\nLuister eerst naar uw collega en reageer.", "vraag": "WAT MOET IK DOEN?", "antwoord": "We moeten samen het cement mengen met water.\nJij moet het cement roeren. En daarna moet je de muur maken.", "pages": [85, 86], "image": "images/img_043.png"}, {"id": 44, "set": 4, "opdracht_in_set": 8, "title": "Collega bellen", "situatie": "U heeft net gehoord dat uw collega een zoon heeft gekregen.\nU vindt dat erg leuk en belt haar daarom op.\nWat zegt u tegen haar?\nU hoort eerst uw collega.", "vraag": "HALLO MET KLAARTJE WIJNEN", "antwoord": "Hol, gefeliciteerd met de geboorte van Je zoon.", "pages": [87, 88], "image": null}, {"id": 45, "set": 4, "opdracht_in_set": 9, "title": "Collega te laat", "situatie": "U werkt op een kantoor.\nUw collega komt met de auto naar het werk.\nHet is vaak druk op de snelweg.\nDaardoor komt ze vaak te laat.\nZe wil voortaan op tijd komen.\nZe vraagt u om advies.\nVertel uw collega wat ze kan doen om op tijd te komen.\nNoem twee dingen die ze kan doen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw collega en reageer.", "vraag": "IK KOM STEEDS TE LAAT DOOR DIE DRUKTE OP DE SNELWEG. WAT KAN IK DOEN OM OP TIJD TE KOMEN?", "antwoord": "Je kunt met een elektrische fiets komen.\nOf je moet heel vroeg komen.", "pages": [89, 90], "image": null}, {"id": 46, "set": 4, "opdracht_in_set": 10, "title": "Computer kiezen", "situatie": "U kunt via uw werk een computer kopen.\nU kunt dan twee jaar lang elke maand 50 euro betalen.\nU betaalt dan 1200 euro voor de computer.\nOf u kunt de computer in één keer kopen voor 1000 euro.\nU wilt graag een computer kopen.\nUw baas wil weten hoe u de computer wilt betalen, en waarom.\nLuister naar uw baas en reageer.", "vraag": "HOE GA JE DE COMPUTER BETALEN? IN 2 JAAR OF IN 1 KEER?", "antwoord": "Ik betaal de computer in 1 keer. Dat is veel goedkoper.", "pages": [91, 92], "image": null}, {"id": 47, "set": 4, "opdracht_in_set": 11, "title": "Computercursus", "situatie": "U wilt een computercursus doen.\nU kunt kiezen uit twee cursussen.\nKijk naar de plaatjes.\nVertel welke cursus u wilt doen.\nVertel ook waarom.\nGeef twee redenen.", "vraag": "", "antwoord": "Ik kies de computercursus “Computer voor u!*.\nOp andere dagen moet ik werken. En op zaterdag heb ik geen\nandere afspraken.", "pages": [93, 94], "image": "images/img_047.png"}, {"id": 48, "set": 4, "opdracht_in_set": 12, "title": "Concert kiezen", "situatie": "Een vriend wil met u naar een concert.\nEr zijn twee concerten die hem leuk lijken: een groot concert\nvan een beroemde band waar 4000 mensen naartoe komen,\nof een concert van een onbekende band in een kleine zaal\nvoor 150 mensen.\nUw vriend vraagt wat u wilt.\nVertel wat u kiest.\nVertel ook waarom u dat kiest.\nLuister naar uw vriend en reageer.", "vraag": "WAAR ZULLEN WE NAARTOE GAAN? HET GROTE CONCERT, OF HET KLEINE?", "antwoord": "Ik kies voor het grote concert.\nIk wil die beroemde band graag zien.", "pages": [95, 96], "image": null}, {"id": 49, "set": 5, "opdracht_in_set": 1, "title": "Cursus muziek of taal", "situatie": "U volgt een cursus in een buurthuis.\nUw vriendin wil ook een cursus volgen.\nZe twijfelt tussen een muziekcursus en een taalcursus.\nZe vraagt welke cursus u zou kiezen.\nVertel uw vriendin welke cursus u zou kiezen: een muziekcursus\nof een taalcursus.\nVertel ook waarom.\nGeef hierbij twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw vriendin en reageer.", "vraag": "WELKE CURSUS ZOU JIJ KIEZEN, EEN MUZIEKCURSUS OF EEN TAALCURSUS?", "antwoord": "Ik zou een taalcursus kiezen. Ik weet niets van muziek. En ik\nhoud van taal.", "pages": [97, 98], "image": null}, {"id": 50, "set": 5, "opdracht_in_set": 2, "title": "Cursus tekenen en schilderen", "situatie": "U volgt een avondcursus Tekenen en Schilderen.\nUw medecursist is zijn schildersmateriaal vergeten.\nU hebt genoeg bij u.\nWat zegt u tegen uw medecursist?", "vraag": "", "antwoord": "Je kunt mijn materiaal gebruiken.", "pages": [99, 100], "image": null}, {"id": 51, "set": 5, "opdracht_in_set": 3, "title": "Dagje Rotterdam", "situatie": "U wilt een dagje met een vriend naar Rotterdam.\nIn een folder leest u wat u allemaal kunt doen.\nBekijk de informatie.\nKies één ding dat u graag wilt doen.\nVertel ook waarom u dat wilt.", "vraag": "", "antwoord": "Ik wil een boottocht maken. De haven van Rotterdam is heel\ngroot en interessant.", "pages": [101, 102], "image": null}, {"id": 52, "set": 5, "opdracht_in_set": 4, "title": "Dagje uit", "situatie": "U bent een dagje naar de dierentuin geweest.\nU vertelt een vriend hoe uw dag was.\nKijk naar het plaatje.\nVertel uw vriend hoe uw dag in de dierentuin was.\nU hoort eerst uw vriend.", "vraag": "HEJ! HOE WAS HET IN DE DIERENTUIN?", "antwoord": "Nou, helemaal niet goed.\nEr was veel regen en ik had geen paraplu.", "pages": [103, 104], "image": "images/img_052.png"}, {"id": 53, "set": 5, "opdracht_in_set": 5, "title": "Decembercadeau", "situatie": "U werkt als administratief medewerker op een kantoor.\nElk jaar in december krijgen de medewerkers een cadeau.\nUw manager twijfelt tussen twee cadeaus.\nHet eerste idee is kaartjes voor de bioscoop.\nHet tweede is een doos met eten en drinken.\nZe vraagt welk idee u beter vindt en waarom.\nVertel uw manager welk idee u beter vindt.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw manager en reageer.", "vraag": "WAT VIND JIJ EEN BETER CADEAU VOOR DE MEDEWERKERS? KAARTJES VOOR DE BIOSCOOP OF EEN DOOS MET ETEN EN DRINKEN?", "antwoord": "Ik kies voor kaartjes voor de bioscoop. In december eet en\ndrinkt iedereen erg veel. Uitgaan naar de bioscoop is altijd\nleuk..", "pages": [105, 106], "image": null}, {"id": 54, "set": 5, "opdracht_in_set": 6, "title": "Deelname studentenraad", "situatie": "U volgt een mbo-opleiding.\nU zit ook in de studentenraad van uw school.\nDe studentenraad adviseert de schoolleiding bij belangrijke\nbeslissingen.\nDe studentenraad heeft een nieuw lid nodig.\nU denkt dat uw studiegenoot heel geschikt zou zijn voor de\nstudentenraad.\nUw studiegenoot twijfelt of hij wil deelnemen aan de\nOvertuig uw studiegenoot ervan dat hij moet deelnemen\naan de studentenraad.\nGeef twee argumenten.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw studiegenoot en reageer.", "vraag": "MAAR WAAROM ZOU IK DEELNEMEN AAN DE STUDENTENRAAD?", "antwoord": "Orndat jij de opleiding wilt verbeteren en orndat jij ook\ngoede ideeén hebt.", "pages": [107, 108], "image": null}, {"id": 55, "set": 5, "opdracht_in_set": 7, "title": "Dierenasiel", "situatie": "U volgt een opleiding tot dierverzorger.\nU loopt samen met een medestudent stage bij een dierenasiel.\nUw medestudent is te laat en heeft de uitleg van de\nstagebegeleider gemist.\nHij vraagt aan u wat hij moet doen.\nKijk naar de plaatjes.\nLuister naar uw medestudent en reageer.\nGebruik daarbij alle plaatjes.\nU hoort eerst uw medestudent.", "vraag": "KAN JIJ MIJ VERTELLEN WAT IK VANDAAG MOET DOEN?", "antwoord": "Ja. Je moet de katten eten geven. En je moet met de honden\nwandelen.", "pages": [109, 110], "image": "images/img_055.png"}, {"id": 56, "set": 5, "opdracht_in_set": 8, "title": "Dierverzorger", "situatie": "U hebt een nieuwe baan als dierverzorger in een dierentuin.\nVroeger werkte u als dierverzorger bij mensen thuis.\nU spreekt met uw buurvrouw over uw beroep.\nZij wil graag weten wat het verschil is tussen uw nieuwe werk en\nuw oude werk.\nKijk naar de plaatjes.\nLeg uit wat het verschil is tussen uw nieuwe en uw oude werk.\nU hoort eerst uw buurvrouw.", "vraag": "WAT IS HET VERSCHIL TUSSEN JE NIEUWE EN JE OUDE WERK?", "antwoord": "Eerder moest ik met de hond wandelen. Nu moet ik eten geven\naan olifanten.", "pages": [111, 112], "image": "images/img_056.png"}, {"id": 57, "set": 5, "opdracht_in_set": 9, "title": "Dingen vervangen", "situatie": "U werkt op een kantoor.\nU mag van uw baas twee dingen vervangen of laten repareren\nop uw kamer.\nKijk naar de plaatjes.\nVertel welke twee dingen u wilt vervangen of laten repareren.\nVertel ook waarom u die dingen wilt vervangen of laten\nrepareren.\nGebruik hierbij beide plaatjes.\nLuister eerst naar uw baas en reageer. |", "vraag": "WELKE TWEE DINGEN WIL JIJ VERVANGEN OF LATEN REPAREREN, EN WAAROM?", "antwoord": "Ik wil graag een nieuwe lamp en een nieuwe bureaustoel. De\nlamp en de stoel zijn oud en kapot.", "pages": [113, 114], "image": "images/img_057.png"}, {"id": 58, "set": 5, "opdracht_in_set": 10, "title": "Driedaagse schoolweek", "situatie": "De school van uw kind heeft te weinig leraren.\nDaarom wil de school voortaan drie dagen lesgeven, in\nplaats van vijf dagen.\nU vindt dat geen goed idee.\nVertel waarom u een schoolweek van drie dagen geen\ngoed idee vindt.", "vraag": "", "antwoord": "Een schoolweek van drie dagen is geen goed idee, want\nde kinderen moeten niet zo vaak thuisblijven.", "pages": [115, 116], "image": null}, {"id": 59, "set": 5, "opdracht_in_set": 11, "title": "Drukkerij", "situatie": "U werkt bij een drukkerij.\nEris iets misgegaan met het drukken van een boek voor een\nuitgever.\nDe uitgever heeft u een boze e-mail gestuurd.\nUw collega weet niet wat hij zal doen: de uitgever een e-mail\nterugsturen of bellen.\nHij vraagt u om advies.\nVertel uw collega wat u zou doen: de uitgever een e-mail\nVertel ook waarom.\nU hoort eerst uw collega.", "vraag": "IK HEB EEN BOZE E-MAIL ONTVANGEN VAN DE UITGEVER. ZAL IK HEM EEN E-MAIL TERUGSTUREN OF KAN IK BETER BELLEN?", "antwoord": "Je kunt beter bellen. Bellen is snetler.", "pages": [117, 118], "image": null}, {"id": 60, "set": 5, "opdracht_in_set": 12, "title": "Drukte in de supermarkt", "situatie": "U werkt in een supermarkt.\nHet is heel druk in de supermarkt.\nDaarom komt een collega u helpen.\nUw collega vraagt wat hij moet doen.\nKijk naar de plaatjes.\nLeg uw collega uit wat hij moet gaan doen.\nGebruik daarbij alle plaatjes.\nU hoort eerst uw collega.", "vraag": "WAT KAN IK DOEN IN DE WINKEL?", "antwoord": "Oké. Je kunt bij de kassa werken.\nJe kunt de karren schoonmaken. En je kunt vakken vullen.", "pages": [119, 120], "image": "images/img_060.png"}, {"id": 61, "set": 6, "opdracht_in_set": 1, "title": "Edutel", "situatie": "U wilt een opleiding gaan volgen.\nU ziet een advertentie in de krant.\nBekijk de informatie.\nVertel waarom u wel of niet bij Edutel zou willen studeren.", "vraag": "", "antwoord": "Ik wil graag bij Edutel studeren. Ik wil graag thuis studeren in\nmijn eigen tijd.", "pages": [121, 122], "image": null}, {"id": 62, "set": 6, "opdracht_in_set": 2, "title": "Een concert", "situatie": "U hebt twee kaartjes gekocht voor een concert op\nzaterdagavond.\nEen vriend van u heeft gezegd dat hij graag mee wil.\nOp zaterdagmiddag belt uw vriend op.\nHij gaat toch niet mee naar het concert.\nVertel uw vriend waarom u vindt dat hij toch mee moet gaan.\nU hoort eerst uw vriend.", "vraag": "JA, SORRY, MAAR IK GA VANAVOND TOCH NIET MEE NAAR HET CONCERT.", "antwoord": "Kom op, ga mee. Ik heb kaartjes, ik wil niet alleen gaan ...", "pages": [123, 124], "image": null}, {"id": 63, "set": 6, "opdracht_in_set": 3, "title": "Een dag bij de kinderboerderij", "situatie": "U werkt op een kinderboerderij.\nEris een vacature.\nU praat met een vrouw die interesse heeft in de vacature.\nDe vrouw vraagt wat u op een werkdag bij de kinderboerderij\ndoet.\nKijk naar de plaatjes.\nVertel de vrouw hoe een dag werken bij de kinderboerderij\neruitziet.\nGebruik hierbij alle plaatjes.\nU hoort eerst de vrouw.", "vraag": "HOE ZIET EEN DAG WERKEN OP DE KINDERBOERDERIJ", "antwoord": "ERuUIT?\nOm 8 uur moet je de dieren eten geven. Om 10 uur moet je\nde stal schoonmaken. Om 1 uur in de middag moet je\nkinderen informatie geven over de kinderboerderij.", "pages": [125, 126], "image": "images/img_063.png"}, {"id": 64, "set": 6, "opdracht_in_set": 4, "title": "Een dagje uit", "situatie": "U volgt een opleiding tot juf.\nU loopt stage op een basisschool.\nU bent gisteren een dagje uit geweest met een groep jongens\nen meisjes.\nVandaag moet u op uw opleiding iets vertellen over het dagje\nuit.\nKijk naar de plaatjes.\nVertel wat u met de jongens en meisjes gedaan hebt.\nGebruik hierbij alle plaatjes.\n10.00 uur 12.30 uur 14.00 uur", "vraag": "", "antwoord": "We zijn met de fiets naar het park gegaan. We hebben een\npicknick gehad. Daarna zijn we naar de dierentuin gegaan.", "pages": [127, 128], "image": "images/img_064.png"}, {"id": 65, "set": 6, "opdracht_in_set": 5, "title": "Een dubbele afspraak", "situatie": "U bent op school in de taalles.\nOm half twaalf hebt u een afspraak met uw tandarts.\nDe taalles is pas om half één afgelopen.\nWat vraagt u aan uw docent?", "vraag": "", "antwoord": "Ik moet om half twaalf naar de tandarts.\nMag ik eerder weggaan?", "pages": [129, 130], "image": null}, {"id": 66, "set": 6, "opdracht_in_set": 6, "title": "Een eigen bedrijf", "situatie": "U wilt een eigen bedrijf beginnen.\nU praat met uw buurman over uw plannen.\nKijk naar het plaatje.\nLuister naar uw buurman en reageer.", "vraag": "DUS JE WILT EEN BEDRIJF BEGINNEN. WAT BEN JE DAN PRECIES VAN PLAN?", "antwoord": "Ik wil een pizzeria beginnen.", "pages": [131, 132], "image": "images/img_066.png"}, {"id": 67, "set": 6, "opdracht_in_set": 7, "title": "Een gezicht tekenen", "situatie": "U volgt een tekencursus.\nDe vorige les hebt u geleerd hoe u het beste een gezicht kunt\ntekenen.\nUw medecursist heeft deze les gemist.\nU legt haar uit wat u hebt geleerd.\nKijk naar de plaatjes.\nVertel uw medecursist hoe zij het beste een gezicht kan", "vraag": "WAT IS DE BESTE MANIER OM EEN GEZICHT TE TEKENEN?", "antwoord": "Je moet eerst het hoofd tekenen. Daarna moet je de ogen\ntekenen. En daarna moet je de neus en de mond tekenen.", "pages": [133, 134], "image": "images/img_067.png"}, {"id": 68, "set": 6, "opdracht_in_set": 8, "title": "Een nieuwe collega", "situatie": "U werkt in een hotel.\nVandaag moet u een nieuwe collega vertellen wat ze\nvanochtend moet doen.\nKijk naar de plaatjes.\nVertel uw collega wat ze moet doen.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw nieuwe collega.", "vraag": "NOV, IK HEB ER ZIN IN. WAT KAN IK DOEN?", "antwoord": "Je moet de vieze was verzamelen. Je moet stofzuigen.\nEn je moet het bed opmaken.", "pages": [135, 136], "image": "images/img_068.png"}, {"id": 69, "set": 6, "opdracht_in_set": 9, "title": "Een ui snijden", "situatie": "U volgt een kookcursus.\nDe vorige les hebt u geleerd hoe u het best een ui kunt snijden.\nUw medecursist heeft deze les gemist.\nU legt hem uit wat u hebt geleerd.\nKijk naar de plaatjes.\nVertel uw medecursist hoe hij het best een ui kan snijden.", "vraag": "WAT IS DE BESTE MANIER OM EEN UI TE SNIJDEN?", "antwoord": "Eerst moet je de ul doorsnijden. Dan moet je de schil eraf\nhalen. Tenslotte moet je de ui in kleine stukjes snijden.", "pages": [137, 138], "image": "images/img_069.png"}, {"id": 70, "set": 6, "opdracht_in_set": 10, "title": "Een uur langer werken", "situatie": "U werkt op een kantoor.\nHet wordt volgende maand erg druk.\nUw chef stelt voor dat iedereen volgende maand elke dag een\nuur langer werkt.\nVertel uw chef wat u van het idee vindt.\nVertel ook waarom u dat vindt.", "vraag": "", "antwoord": "Ik vind dat geen goed idee. Ik heb ook andere afspraken.", "pages": [139, 140], "image": null}, {"id": 71, "set": 6, "opdracht_in_set": 11, "title": "Eigen kamer", "situatie": "U werkt op een kantoor.\nU hebt een nieuwe baan op een andere afdeling.\nU moet uw kamer nu delen met twee collega’s.\nEerst had u een kamer voor u alleen.\nVertel uw leidinggevende dat u liever een eigen kamer hebt.\nGeef twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw leidinggevende en reageer.", "vraag": "VIND JE HET LEUK DAT JE NU EEN NIEUWE KAMER HEBT MET TWEE COLLEGA’S?", "antwoord": "Nee, ik wil mijn eigen kamer. Mijn 2 collega’s maken veel\nlawaal. En de kamer is ook te klein voor drie mensen.", "pages": [141, 142], "image": null}, {"id": 72, "set": 6, "opdracht_in_set": 12, "title": "Eigen zaak of blijven", "situatie": "U werkt in een kledingwinkel.\nU wilt misschien uw eigen zaak beginnen.\nUw baas wil liever dat u niet weggaat.\nHij biedt u daarom een hoger salaris.\nEen vriendin vraagt wat u kiest: een eigen zaak beginnen of\nblijven voor een hoger salaris.\nVertel uw vriendin wat u kiest.\nVertel ook waarom u dit kiest.\nGeef hiervoor twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw vriendin en reageer.", "vraag": "EN, WEET JE AL WAT JE GAAT KIEZEN?", "antwoord": "Ja, ik kies voor mijn eigen zaak. Ik vind mijn baas niet aardig. Ik\nwil over mijn werk alles zelf beslissen.", "pages": [143, 144], "image": null}, {"id": 73, "set": 7, "opdracht_in_set": 1, "title": "Even wachten", "situatie": "U gaat met een vriendin naar de markt.\nUw vriendin wil nu weggaan, maar u moet nog een paar dingen\ndoen.\nKijk naar de plaatjes.\nLuister naar uw vriendin en vertel haar wat u nog moet doen\nvoor u naar de markt kunt gaan.\nGebruik hierbij alle plaatijes.\nU hoort eerst uw vriendin.", "vraag": "KUN JE NOG NIET MEE NAAR DE MARKT? WAT MOET JE DAN NOG DOEN?", "antwoord": "Ik moet eerst nog wat eten. En ik moet mijn schoenen\naandoen. En ik moet geld pinnen.", "pages": [145, 146], "image": "images/img_073.png"}, {"id": 74, "set": 7, "opdracht_in_set": 2, "title": "Examen", "situatie": "U hebt een examen gemaakt.\nErging iets helemaal fout.\nKijk naar het plaatje.\nOvertuig uw docente ervan dat u het examen opnieuw mag", "vraag": "JE EXAMEN OPNIEUW MAKEN? WAAROM WIL JE DAT?", "antwoord": "De computer is kapotgegaan.", "pages": [147, 148], "image": "images/img_074.png"}, {"id": 75, "set": 7, "opdracht_in_set": 3, "title": "Extra geld", "situatie": "U werkt op een kantoor.\nUw baas vertelt dat de werknemers dit jaar 500 euro extra\nkrijgen, omdat het bedrijf zestig jaar bestaat.\nUw baas wil van alle werknemers weten wanneer zij het\nextra geld het liefst ontvangen: in mei of in december.\nZij vraagt dit ook aan u.\nVertel aan uw baas wat u het liefste wilt: het extra geld\nontvangen in mei of in december.\nVertel ook waarom.\nLuister eerst naar uw baas.", "vraag": "WANNEER ZOU JIJ HET EXTRA GELD HET LIEFST", "antwoord": "ONTVANGEN7 IN MEi OF IN DECEMBER?\nIk heb het geld liever in mei. Ik wil een grote reis maken in\nde zomer.", "pages": [149, 150], "image": null}, {"id": 76, "set": 7, "opdracht_in_set": 4, "title": "Extra werken", "situatie": "U werkt bij de administratie van een groot bedrijf.\nUw collega heeft het erg druk deze week.\nHij twijfelt wat hij het beste kan doen: een dag extra komen\nwerken of elke dag een uur langer werken.\nVertel uw collega wat hij volgens u het beste kan doen.\nVertel ook waarom u dat vindt.\nGeef daarvoor ten minste twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw collega en reageer.", "vraag": "WAT ZAL IK DOEN? EEN DAG EXTRA KOMEN OF ELKE DAG EEN UURTJE LANGER BLIJVEN?", "antwoord": "Je kunt beter een dag extra werken. Als je extra lang werkt\nop 1 dag, maak je veel fouten. Als je elke dag op tijd naar\nhuls gaat, heb je elke dag een vrije avond.", "pages": [151, 152], "image": null}, {"id": 77, "set": 7, "opdracht_in_set": 5, "title": "Feest met gekke kleding", "situatie": "In het buurthuis is een feest.\nHet is de bedoeling dat iedereen gekke kleding aantrekt.\nU wilt geen gekke kleding aantrekken.\nU praat hierover met uw buurman.\nVertel uw buurman waarom u niet in gekke kleren naar\nhet feest wilt gaan.\nU hoort eerst uw buurman.", "vraag": "IEDEREEN DOET GEKKE KLEREN AAN. WAAROM WIL JIJ DAT NIET?", "antwoord": "Omdat ik niet gek ben.", "pages": [153, 154], "image": null}, {"id": 78, "set": 7, "opdracht_in_set": 6, "title": "Feestavond in de buurt", "situatie": "Bij u in de buurt is een feestavond.\nU wilt die avond bezoeken maar u gaat liever niet alleen.\nU komt in uw straat iemand tegen die u kent.\nWat zegt u tegen uw kennis?", "vraag": "", "antwoord": "Hol, ga je mee naar de feestavond?", "pages": [155, 156], "image": null}, {"id": 79, "set": 7, "opdracht_in_set": 7, "title": "Fietsenmaker", "situatie": "U wilt een opleiding tot fietsenmaker volgen.\nU wilt meer informatie over de opleiding tot fietsenmaker.\nU belt een school voor beroepsonderwijs.\nStel een vraag over de opleiding.\nLuister naar de medewerker van de school en reageer.", "vraag": "HALLO, KAN IK U HELPEN?", "antwoord": "Hoe lang duurt de opleiding tot fietsenmaker precies?", "pages": [157, 158], "image": null}, {"id": 80, "set": 7, "opdracht_in_set": 8, "title": "Film kijken", "situatie": "Veel mensen vinden het leuk om naar de bioscoop te gaan.\nAnderen kijken liever thuis naar een film.\nVertel wat u liever doet: naar de bioscoop gaan of thuis naar een\nfilm kijken.\nVertel ook waarom.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik kijk liever thuts naar een film. Dat is relaxed en goedkoop.", "pages": [159, 160], "image": null}, {"id": 81, "set": 7, "opdracht_in_set": 9, "title": "Foto's van een huwelijk", "situatie": "U bent fotograaf.\nU maakt mooie foto's van een huwelijk.\nU moet de man en de vrouw vertellen waar zij moeten gaan\nstaan.\nKijk naar het plaatje.\nLeg de man en de vrouw uit waar zij moeten gaan staan.", "vraag": "", "antwoord": "Jullie moeten midden op de brug gaan staan.", "pages": [161, 162], "image": "images/img_081.png"}, {"id": 82, "set": 7, "opdracht_in_set": 10, "title": "Functie van chauffeur", "situatie": "U zoekt een baan.\nU gaat daarom naar het uitzendbureau.\nZij helpen u met het zoeken naar een baan.\nDe medewerker van het uitzendbureau vraagt of de functie van\nchauffeur geschikt is voor u.\nVertel de medewerker of deze functie geschikt is voor u.\nGeef hiervoor twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar de medewerker en reageer.", "vraag": "ER IS OP DIT MOMENT VEEL VRAAG NAAR CHAUFFEURS. IS DAT WAT VOOR U?", "antwoord": "Nee, chauffeur is niets voor mij. Ik vind het te druk op de weg.\nEn ik houd helemaal niet van autorijden.", "pages": [163, 164], "image": null}, {"id": 83, "set": 7, "opdracht_in_set": 11, "title": "Geen laptops inde les", "situatie": "U volgt de opleiding Bedrijfsadministratie.\nUw docent vertelt dat studenten tijdens de les geen laptop\nmogen gebruiken.\nZe mogen alleen op papier schrijven.\nU wilt liever uw laptop gebruiken.\nOvertuig uw docent ervan dat hij laptops moet toestaan tijdens\nde les.\nGebruik hiervoor twee argumenten.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw docent en reageer.", "vraag": "WAAROM ZOU IK LAPTOPS MOETEN TOESTAAN TIJDENS OE LES?", "antwoord": "Ik kan sneller schrijven op de computer. En ik kan niet duldelijk\nschrijven met een pen op papier.", "pages": [165, 166], "image": null}, {"id": 84, "set": 7, "opdracht_in_set": 12, "title": "Geen stage", "situatie": "U zit in het eerste jaar van de opleiding tot bakker.\nIn het eerste jaar moeten alle studenten een week stage lopen.\nEris dit jaar een tekort aan stageplaatsen.\nDaarom gaan de stages dit jaar niet door.\nVertel uw studiebegeleider wat u hiervan vindt.\nVertel ook waarom u dat vindt.\nU hoort eerst uw studiebegeleider.", "vraag": "ER ZIJN DIT JAAR DUS GEEN STAGES.", "antwoord": "Oat vind ik heel jammer. Ik wil graag dingen in de praktijk\nleren.", "pages": [167, 168], "image": null}, {"id": 85, "set": 8, "opdracht_in_set": 1, "title": "Gereedschap meubelcursus", "situatie": "U volgt een cursus meubels maken.\nUw medecursist gebruikt elke les uw spullen.\nDit vindt u vervelend.\nVertel tegen uw medecursist wat u wilt.\nVertel ook waarom u dit wilt.\nGeef hiervoor twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medecursist en reageer.", "vraag": "WAT WILDE JE ZEGGEN OVER JE SPULLEN?", "antwoord": "Jij moet jouw eigen spullen kopen. Ik heb mijn eigen spullen\nnodig. En jij maakt mijn spullen soms kapot.", "pages": [169, 170], "image": null}, {"id": 86, "set": 8, "opdracht_in_set": 2, "title": "Geschrokken tijdens de les", "situatie": "U bent op school en hebt les.\nPlotseling gebeurt er iets waar u van schrikt.\nKijk naar het plaatje.\nLuister naar uw vriendin en geef antwoord.", "vraag": "BEN JE GESCHROKKEN? HOE KWAM DAT DAN?", "antwoord": "Een voetbal vloog door het open raam naar binnen.", "pages": [171, 172], "image": "images/img_086.png"}, {"id": 87, "set": 8, "opdracht_in_set": 3, "title": "Gesprek op school", "situatie": "U hebt op school een gesprek met de leerkracht van uw kind.\nZe wil weten wat uw kind in haar vrije tijd doet.\nKijk naar de plaatjes.\nVertel wat uw kind doet in een week.\nGebruik hierbij beide plaatjes.\nU hoort eerst de leerkracht.", "vraag": "EN WAT DOET UW KIND NA SCHOOL IN HAAR VRIJE TIJD?", "antwoord": "Mijn kind zit op woensdag op muziek en mijn kind zit op\nzaterdag op zwemmen.", "pages": [173, 174], "image": "images/img_087.png"}, {"id": 88, "set": 8, "opdracht_in_set": 4, "title": "Gesprek zorgopleiding", "situatie": "U wilt een opleiding in de zorg gaan doen.\nVandaag hebt u een gesprek met een docent van de opleiding.\nDe docent wil weten of u goed hebt nagedacht over de\nopleiding.\nHij vraagt wat u moeilijk lijkt aan werken in de zorg.\nVertel twee dingen die u moeilijk lijken aan werken in de zorg.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw studiebegeleider en geef antwoord.", "vraag": "WAT LIJKT JE MOEILIJK AAN WERKEN IN DE ZORG?", "antwoord": "Mensen helpen met douchen lijkt me moeilijk. Mensen naar\nbed brengen lijkt me ook moeilijk.", "pages": [175, 176], "image": null}, {"id": 89, "set": 8, "opdracht_in_set": 5, "title": "Gezellige inrichting", "situatie": "U hebt een nieuw huis gekocht.\nU vindt het huis nog niet gezellig.\nEen vriend komt u helpen met inrichten.\nU hebt een aantal ideeén.\nKijk naar de plaatjes.\nVertel uw vriend wat hij kan doen.\nU moet daarbij alle plaatjes gebruiken.\nU hoort eerst uw vriend.", "vraag": "ZEG HET MAAR, WAT MOET IK DOEN?", "antwoord": "Oké - je moet de lamp in de hoek van de kamer zetten.\nJe moet bloemen op tafel zetten. En je moet een paar foto's\naan de muur hangen.", "pages": [177, 178], "image": "images/img_089.png"}, {"id": 90, "set": 8, "opdracht_in_set": 6, "title": "Glazenwasser", "situatie": "U wilt graag een baan als glazenwasser.\nEen glazenwasser wast ramen bij woonhuizen, maar ook\nbij hoge gebouwen.\nU hebt een sollicitatiegesprek.\nDe chef vraagt waar u liever ramen wast, bij woonhuizen of\nKijk naar de plaatjes.", "vraag": "", "antwoord": "Ik was liever de ramen bij gewone woonhuizen. Ik vind werken\nbij een hoog gebouw gevaarlijk.", "pages": [179, 180], "image": "images/img_090.png"}, {"id": 91, "set": 8, "opdracht_in_set": 7, "title": "Goed doel", "situatie": "U werkt op een kantoor.\nMet Kerstmis wordt altijd geld opgehaald voor een goed doel.\nUw baas heeft dit jaar twee organisaties voor goede doelen\nuitgekozen: het Wereld Natuurfonds en Monumentenzorg.\nHet Wereld Natuurfonds probeert de natuur te behouden,\nMonumentenzorg probeert oude gebouwen mooi te houden.\nDe medewerkers mogen kiezen aan welk goed doel ze geld\nwillen geven.\nVertel welk goed doel u het beste vindt.\nVertel ook waarom.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw baas en geef antwoord.", "vraag": "WELK GOED DOEL VIND JIJ HET BESTE?", "antwoord": "Ik vind het Wereld Natuurfonds het beste. De natuur en het\nmilieu zijn erg belangrijk voor de toekomst.", "pages": [181, 182], "image": null}, {"id": 92, "set": 8, "opdracht_in_set": 8, "title": "Goed vakantieweer", "situatie": "Sommige mensen willen in hun vakantie altijd goed weer\nhebben.\nZe gaan daarom naar landen waar de zon altijd schijnt.\nVertel of u het belangrijk vindt dat het tijdens de vakantie\ngoed weer is.\nVertel ook waarom u dat wel of niet belangrijk vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind goed weer heel belangrijk. Ik wil in de vakantie in zee\nzwemmen en op het strand liggen.", "pages": [183, 184], "image": null}, {"id": 93, "set": 8, "opdracht_in_set": 9, "title": "Grote parkeergarages", "situatie": "In een grote stad zijn vaak weinig parkeerplaatsen.\nEr worden daarom vaak grote parkeergarages gebouwd buiten\nde stad.\nMensen kunnen dan met de bus naar het centrum van de stad\nreizen.\nWat vindt u van deze grote parkeergarages buiten de stad?\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind dat niet fijn. Ik wil mijn auto parkeren in het centrum.\nIk wil niet met volle tassen in een bus reizen.", "pages": [185, 186], "image": null}, {"id": 94, "set": 8, "opdracht_in_set": 10, "title": "Grote plant", "situatie": "Voor het huis van uw buurman staat een grote plant.\nDe plant is te groot en veroorzaakt daardoor een probleem.\nKijk naar het plaatje.\nLuister naar uw buurman en geef antwoord.", "vraag": "DIE PLANT WEGHALEN? HOEZO HEB JE DAAR LAST VAN?", "antwoord": "Ja, ik heb er last van. Ik kan niet goed naar buiten kijken.", "pages": [187, 188], "image": "images/img_094.png"}, {"id": 95, "set": 8, "opdracht_in_set": 11, "title": "Hardlopen", "situatie": "Een vriendin vertelt dat ze erg van hardlopen houdt.\nZe vraagt of u daar ook van houdt.\nVertel of u van hardlopen houdt.\nVertel ook waarom wel of niet.", "vraag": "", "antwoord": "Ja, ik houd ook van hardlopen. Ik wil graag fit en gezond zijn.", "pages": [189, 190], "image": null}, {"id": 96, "set": 8, "opdracht_in_set": 12, "title": "Heftruckchauffeur in fabriek", "situatie": "U werkt als chauffeur in een fabriek.\nVandaag is er iets vervelends gebeurd.\nUw collega wil weten wat er is gebeurd.\nKijk naar de plaatjes.\nVertel uw collega wat er is gebeurd.\nGebruik hierbij alle plaatijes.\nU hoort eerst uw collega.", "vraag": "WAT IS ER DAN PRECIES GEBEURD VANDAAG?", "antwoord": "Ik had de heftruck vol met dozen. Ik had een ongelukje en\nalle dozen vielen op de grond. De chef was heel boos.", "pages": [191, 192], "image": "images/img_096.png"}, {"id": 97, "set": 9, "opdracht_in_set": 1, "title": "hHeipeninae tuin", "situatie": "U bent aan het werk in uw tuin.\nEen vriendin vraagt of ze kan helpen.\nKijk naar het plaatje.\nVertel uw vriendin wat zij kan doen.\nU hoort eerst uw vriendin.", "vraag": "WAAR KAN IK JE MEE HELPEN?", "antwoord": "Je kunt helpen met appels plukken.", "pages": [193, 194], "image": "images/img_097.png"}, {"id": 98, "set": 9, "opdracht_in_set": 2, "title": "Hoe vaak boodschappen doen?", "situatie": "Sommige mensen doen maar één keer per week boodschappen,\nanderen kopen iedere dag wat ze nodig hebben.\nVertel wat u het prettigst vindt: iedere dag boodschappen doen\nof één keer per week.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik kies voor elke dag boodschappen doen.\nMijn supermarkt is dichtbij.", "pages": [195, 196], "image": null}, {"id": 99, "set": 9, "opdracht_in_set": 3, "title": "Hondenpoep op straat", "situatie": "In uw buurt hebben veel mensen een hond.\nDoor al die honden ligt er veel poep op straat.\nUw buurman vraagt of u een idee heeft voor een oplossing.\nReageer op uw buurman.\nNoem één idee.\nU hoort eerst uw buurman.", "vraag": "HEB JIJ EEN IDEE VOOR EEN OPLOSSING?", "antwoord": "Ja, honden moeten poepen op een speciaal terrein,\nbijvoorbeeld in een bos.", "pages": [197, 198], "image": null}, {"id": 100, "set": 9, "opdracht_in_set": 4, "title": "Hotelmanager", "situatie": "U volgt de opleiding voor hotelmanager.\nNa uw opleiding kunt u verschillende dingen doen.\nU kunt bijvoorbeeld manager worden in een bestaand\nhotel of zelf een hotel beginnen.\nZou u liever zelf een hotel beginnen of in een bestaand hotel\nwerken?\nGeef ten minste twee redenen,\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik kies voor een eigen hotel. Ik heb liever geen baas. Ik wil\nalles zelf beslissen.", "pages": [199, 200], "image": null}, {"id": 101, "set": 9, "opdracht_in_set": 5, "title": "Huizen verkopen", "situatie": "U bent makelaar: u verkoopt huizen.\nEr komt een huis in de verkoop.\nU vertelt een nieuwe collega wat hij moet doen bij het huis.\nKijk naar de plaatjes.\nVertel uw nieuwe collega wat hij moet doen.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw collega.", "vraag": "NOU, VERTEL MAAR, WAT MOET IK DOEN BIJ HET HUIS?", "antwoord": "Je moet foto's maken van de woonkamer. Je moet meten hoe\ngroot de woonkamer is. En je moet een bord in de tuln zetten.", "pages": [201, 202], "image": "images/img_101.png"}, {"id": 102, "set": 9, "opdracht_in_set": 6, "title": "Hulp van de buurvrouw", "situatie": "U bent gevallen op straat.\nU moet naar het ziekenhuis om een foto te laten maken van uw\nbeen.\nU kunt uw kind van drie jaar niet meenemen.\nUw buurvrouw biedt haar hulp aan.\nVertel uw buurvrouw wat zij kan doen.\nU hoort eerst uw buurvrouw.", "vraag": "KAN IK JE MISSCHIEN HELPEN?", "antwoord": "Ja, graag. Kun jij op mijn kind passen?\nIk moet naar het ziekenhuls.", "pages": [203, 204], "image": null}, {"id": 103, "set": 9, "opdracht_in_set": 7, "title": "Huurbaas", "situatie": "Uw vriend woont in een huurhuis.\nUw vriend vindt dat de huurbaas haar werk niet goed doet.\nHij heeft hierover niet gesproken met de huurbaas.\nU vindt dat hij dit wel moet doen.\nVertel uw vriend wat hij volgens u moet doen.\nVertel ook waarom.\nU hoort eerst uw vriend.", "vraag": "IK BEN ECHT NIET TEVREDEN OVER DE HUURBAAS. ERIS VAN ALLES KAPOT IN HUIS EN ZE REPAREERT NIETS.", "antwoord": "Je moet met je huurbaas praten. Je moet de huurbaas\nvertellen wat er kapot is.", "pages": [205, 206], "image": null}, {"id": 104, "set": 9, "opdracht_in_set": 8, "title": "Informatie over kappersopleiding", "situatie": "U volgt een opleiding voor kapper.\nUw vriendin wil dezelfde opleiding gaan volgen.\nZe vraagt aan u informatie over de opleiding.\nKijk naar de plaatjes.\nGeef uw vriendin informatie over de kappersopleiding.\nGebruik hierbij alle plaatjes.\nLuister naar uw vriendin en reageer.", "vraag": "ZEG, IK GA MISSCHIEN OOK DE KAPPERSOPLEIDING DOEN. VERTEL ER EENS IETS OVER?", "antwoord": "Je krijgt theorieles van een docent. Je krijgt praktijklessen\nmet poppen. En je krijgt praktijkiessen met echte mensen.", "pages": [207, 208], "image": "images/img_104.png"}, {"id": 105, "set": 9, "opdracht_in_set": 9, "title": "Informeren opleiding ziekenverzorgster", "situatie": "U wilt misschien een opleiding voor ziekenverzorger gaan\nvolgen.\nEen vriendin van u is bijna klaar met deze opleiding.\nU belt haar op.\nStel een vraag over de opleiding.\nBekijk de informatie.\nLuister naar uw vriendin en reageer.", "vraag": "NATUURLIJK WIL IK JE IETS OVER DE OPLEIDING VERTELLEN. WAT WIL JE WETEN?", "antwoord": "Ik wil dit weten: Is er bij de opleiding ook een stage?", "pages": [209, 210], "image": null}, {"id": 106, "set": 9, "opdracht_in_set": 10, "title": "Inloggen", "situatie": "U volgt een opleiding tot administratief medewerker.\nVandaag start een nieuwe medestudent met de opleiding.\nHij weet niet hoe je op het schoolnetwerk op internet kan\nkomen.\nKijk naar de plaatjes.\nVertel uw medestudent hoe hij op het schoolnetwerk kan\nU hoort eerst uw medestudent.", "vraag": "HOE KAN IK OP HET SCHOOLNETWERK KOMEN?", "antwoord": "Je hebt een brief gekregen van het ROC. In de brief staan\nJe gebruikersnaam en je wachtwoord.", "pages": [211, 212], "image": "images/img_106.png"}, {"id": 107, "set": 9, "opdracht_in_set": 11, "title": "Inrichten nieuwe tuin", "situatie": "Een kennis heeft een nieuw huis gekocht.\nHij heeft een gezin met kinderen van drie en vijf jaar oud.\nDe tuin bij het huis is nog erg leeg.\nKijk naar het plaatje.\nGeef uw kennis ten minste twee adviezen voor het inrichten\nvan de tuin. U hoort eerst de kennis.", "vraag": "DE TUIN IS WEL ERG KAAL. WAT ZAL IK ERMEE DOEN?", "antwoord": "Je moet gras in de tuin nemen. En je moet de vijver vervangen\ndoor een trampoline.", "pages": [213, 214], "image": "images/img_107.png"}, {"id": 108, "set": 9, "opdracht_in_set": 12, "title": "Inrichting winkel", "situatie": "U loopt stage in een winkel.\nU hebt de inrichting van de winkel veranderd.\nKijk naar de plaatjes.\nVertel uw stagebegeleider wat u gedaan hebt.\nU moet daarbij alle plaatjes gebruiken.\nU hoort eerst uw stagebegeleider.", "vraag": "DE INRICHTING ZIET ER MOOI UIT. WAT HEB JE PRECIES GEDAAN?", "antwoord": "Ik heb eerst met de elgenaar van de winkel gesproken. Ik heb\nook een plattegrond gemaakt. En daarna heb ik met anderen\nnieuwe tafels en kasten in de winkel gezet.", "pages": [215, 216], "image": "images/img_108.png"}, {"id": 109, "set": 10, "opdracht_in_set": 1, "title": "Introductiedag", "situatie": "U volgt een sportopleiding.\nU helpt mee aan een introductiedag voor nieuwe studenten.\nEen studente vraagt wat het programma is.\nKijk naar de plaatjes.\nVertel de studente wat het programma is.\nU moet daarbij alle plaatjes gebruiken.\nU hoort eerst de studente.", "vraag": "KUN JIJ ME VERTELLEN WAT HET PROGRAMMA VAN DE INTRODUCTIEDAG IS?", "antwoord": "In de ochtend krijgen we veel informatie over de oplelding.\nIn de middag gaan we veel sporten doen. En daarna krijgen\nwe onze studieboeken.", "pages": [217, 218], "image": "images/img_109.png"}, {"id": 110, "set": 10, "opdracht_in_set": 2, "title": "Jubileum bedrijf", "situatie": "U heeft een eigen autobedrijf.\nUw bedrijf bestaat vijf jaar.\nDaarom wilt u alle medewerkers trakteren op taart.\nU geeft opdracht aan een bakker om een speciale taart te\nmaken.\nKijk naar het plaatje.\nVertel de bakker hoe de taart eruit moet zien.", "vraag": "HOE MOET DE TAART ERUIT ZIEN?", "antwoord": "Ik wil graag een autootje op de taart. En ik wil graag\nde tekst:'5 jaar’ op de taart.", "pages": [219, 220], "image": "images/img_110.png"}, {"id": 111, "set": 10, "opdracht_in_set": 3, "title": "Kaas", "situatie": "U koopt kaas op de markt.\nDe verkoper legt de kaas voor u neer.\nU betaalt.\nDan stopt de vrouw naast u per ongeluk uw kaas in haar tas.\nWat zegt u tegen de vrouw?", "vraag": "", "antwoord": "Sorry, dat is mijn kaas.", "pages": [221, 222], "image": null}, {"id": 112, "set": 10, "opdracht_in_set": 4, "title": "Kaaswinkel", "situatie": "U werkt bij een kaaswinkel.\nUw baas vraagt wat u vandaag wilt doen.\nU kunt kiezen tussen werken in de winkel of kaas verkopen op\nde markt.\nVertel uw baas wat u liever wilt doen.\nVertel ook waarom.\nU hoort eerst uw baas.", "vraag": "WIL JE VANDAAG IN DE WINKEL WERKEN OF WIL JE KAAS VERKOPEN OP DE MARKT?", "antwoord": "Ik wil vandaag in de winkel werken. Het is koud op de markt.", "pages": [223, 224], "image": null}, {"id": 113, "set": 10, "opdracht_in_set": 5, "title": "Kamernummer", "situatie": "U werkt in een verzorgingshuis.\nEr komt iemand op bezoek voor mevrouw Adams.\nHij kan mevrouw Adams niet vinden.\nKijk in het boek met de kamernummers.\nLuister naar de bezoeker en geef hem uitleg.", "vraag": "IK BEN NET BL KAMER 32 GEWEEST. IK BEGRIJP ER NIETS VAN.", "antwoord": "DAT tS TOCH DE KAMER VAN MEVROUW ADAMS?\nMevrouw Adams is verhuisd naar kamer 14.", "pages": [225, 226], "image": null}, {"id": 114, "set": 10, "opdracht_in_set": 6, "title": "Kantine op het werk |", "situatie": "U werkt op een kantoor. |\nOp het kantoor is geen kantine.\nU vindt dat er een kantine moet komen. |\nU praat hierover met uw leidinggevende.\nVertel uw leidinggevende waarom u een kantine op uw werk\nwilt.\nU hoort eerst uw leidinggevende.", "vraag": "WAAROM WIL JE EEN KANTINE?", "antwoord": "Ik wil niet eten bij de computer, maar in een kantine. Ik wil in\nde kantine een lekker broodje kopen.", "pages": [227, 228], "image": null}, {"id": 115, "set": 10, "opdracht_in_set": 7, "title": "Kapotte ladder", "situatie": "U werkt bij een schildersbedrijf.\nU hebt vandaag een ladder gebruikt om het bovenste deel van\neen huis te kunnen schilderen.\nNu is de ladder kapot.\nUw baas wil weten wat er precies is gebeurd.\nKijk naar het plaatje:\nVertel uw baas wat er precies is gebeurd.", "vraag": "DUS DE LADDER IS STUK. HOE IS DAT GEBEURD?", "antwoord": "Mijn collega is met de auto tegen de ladder gereden.\nOe ladder is gevallen.", "pages": [229, 230], "image": "images/img_115.png"}, {"id": 116, "set": 10, "opdracht_in_set": 8, "title": "Kapotte trein", "situatie": "U reist met de trein naar uw werk.\nU hebt vandaag een belangrijk gesprek.\nOpeens stopt de trein.\nDe conducteur zegt: \"De trein is kapot. Iedereen moet\nU belt uw baas.\nLuister naar uw baas en reageer.", "vraag": "DE TREIN IS DUS KAPOT. WAT GA JE NU DOEN?", "antwoord": "Dat weet ik nog niet. Ik moet eerst uitstappen.", "pages": [231, 232], "image": null}, {"id": 117, "set": 10, "opdracht_in_set": 9, "title": "Kappersopleiding", "situatie": "U volgt de opleiding tot kapper.\nEen medestudente heeft lang haar.\nZe wil het kort laten knippen.\nKijk naar het plaatje.\nVertel uw medestudente wat u daarvan vindt.\nVertel ook waarom u dat vindt.\nLuister naar uw medestudente en reageer.", "vraag": "ZEG, IK HEB WEL ZIN OM MIJN HAREN EENS KORT TE LATEN KNIPPEN. WAT VIND JIJ DAARVAN?", "antwoord": "Ik vind dat stom. Het lange haar staat je goed.", "pages": [233, 234], "image": "images/img_117.png"}, {"id": 118, "set": 10, "opdracht_in_set": 10, "title": "Keuze baan", "situatie": "U zoekt voor een paar uur per dag werk via een uitzendbureau.\nHet uitzendbureau helpt u bij het zoeken naar werk.\nVandaag heeft een medewerker twee soorten werk voor u\ngevonden.\nKijk naar de informatie hieronder.\nVertel de medewerker van het uitzendbureau waar u het liefst\nwilt werken.\nGeef twee redenen voor uw keuze.", "vraag": "WAAR WILT U HET LIEFST WERKEN?", "antwoord": "Ik werk het liefst bij de bakkerij. Ik wil in de ochtend werken.\nEn ik heb ervaring als verkoopster.", "pages": [235, 236], "image": null}, {"id": 119, "set": 10, "opdracht_in_set": 11, "title": "Keuze computercursus", "situatie": "U wilt een computercursus volgen bij de bibliotheek.\nU praat hierover met een vriend.\nU kunt kiezen uit twee soorten cursussen.\nUw vriend vraagt welke cursus u kiest.\nKijk naar de tabel.\nVertel uw vriend welke cursus u wilt volgen.\nVertel ook waarom.", "vraag": "WELKE CURSUS WIL JE VOLGEN? DE INDIVIDUELE CURSUS OF DE GROEPSCURSUS?", "antwoord": "Ik kies voor cursus 1, de individuele cursus. Ik heb tlever\nprivéles. En het is niet duur.", "pages": [237, 238], "image": null}, {"id": 120, "set": 10, "opdracht_in_set": 12, "title": "Keuze opleiding of baan", "situatie": "Een vriend van u volgt een opleiding voor automonteur.\nEen autogarage wil hem nu voor één jaar een baan geven.\nHij moet dan wel stoppen met de opleiding.\nHij weet niet of hij moet kiezen voor de opleiding, óf voor\nde baan.\nHij vraagt uw advies.\nVertel uw vriend wat hij het beste kan doen.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw vriend en vertel hem wat hij het beste\nkan doen.", "vraag": "IK DOE DIE OPLEIDING. MAAR IK KAN BIJ DIE GARAGE GAAN WERKEN. ZAL IK DAT NOU DOEN?", "antwoord": "Je kunt beter de opleiding afmaken. Met een diploma krijg\nJe later een echt goede baan.", "pages": [239, 240], "image": null}, {"id": 121, "set": 11, "opdracht_in_set": 1, "title": "Keuze stage", "situatie": "U volgt een opleiding tot bakker.\nUw medestudent kan kiezen uit twee stages.\nDe ene stage is bij een kleine bakkerswinkel in haar woonplaats.\nDe andere stage is in een broodfabriek in een andere stad.\nZij weet niet welke stage zij moet kiezen.\nVertel uw medestudent welke stageplek zij volgens u het best\nkan kiezen.\nGeef daarvoor ten minste twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medestudent en reageer.", "vraag": "WAT ZAL IK KIEZEN, DE BAKKERSWINKEL OF DE BROODFABRIEK?", "antwoord": "Je moet de winkel kiezen. In een winkel kun je meer leren dan\nIn een fabriek. En fe blijft dichtbij huls.", "pages": [241, 242], "image": null}, {"id": 122, "set": 11, "opdracht_in_set": 2, "title": "Keuze taal", "situatie": "U volgt de opleiding Toerisme.\nU heeft Nederlands als verplicht vak.\nU moet nog een andere taal als verplicht vak kiezen.\nDeze taal mag u zelf kiezen.\nU praat hierover met uw docent.\nVertel uw docent welke extra taal u graag wilt leren.\nGeef hiervoor twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw docent en reageer.", "vraag": "JE MOET NOG EEN EXTRA TAAL KIEZEN. WELKE TAAL ZOU JE WILLEN LEREN?", "antwoord": "Ik kies voor Engels. Bijna iedereen in de wereld spreekt Engels.\nEn ik wil overal in de wereld gaan werken.", "pages": [243, 244], "image": null}, {"id": 123, "set": 11, "opdracht_in_set": 3, "title": "Keuze vakantie", "situatie": "Uw buurvrouw wil met haar man en kinderen op vakantie.\nZij twijfelt wat ze het best kunnen doen: naar een vakantiehuisje\nIn Nederland of naar een hotel in Spanje.\nVertel uw buurvrouw wat ze volgens u het best kunnen doen.\nVertel ook waarom u dat vindt.\nGeef daarvoor ten minste twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw buurvrouw en geef antwoord.", "vraag": "IK VIND HET HEEL LEUK OM NAAR EEN VAKANTIEHUISJE NAAR EEN HOTEL IN SPANJE TE GAAN. WAT ZOU JIJ DOEN?", "antwoord": "iN NEDERLAND TE GAAN. MAAR HET IS OOK LEUK OM\nIk kies voor een hulsje in Nederland. Ik houd niet van vliegen.\nEn de kinderen willen graag dichtbij huis op vakantle zijn.", "pages": [245, 246], "image": null}, {"id": 124, "set": 11, "opdracht_in_set": 4, "title": "Keuze voor opleiding", "situatie": "U wilt een opleiding volgen voor administratief medewerker.\nU kunt kiezen uit twee opleidingen op twee verschillende\nscholen in uw buurt.\nBekijk de informatie.\nWelke opleiding kiest u?\nGeef twee redenen.", "vraag": "", "antwoord": "Ik kies voor de Damschool. Ik wil graag ook een stage en het is\ngoedkoper.", "pages": [247, 248], "image": null}, {"id": 125, "set": 11, "opdracht_in_set": 5, "title": "Keuzevak koksopleiding", "situatie": "U volgt een koksopleiding.\nNaast de vaste vakken, moet iedere student een keuzevak\nvolgen.\nU kunt kiezen tussen Koken voor kinderen en Koken zonder\nviees.\nEen medestudent vraagt welk keuzevak u wilt volgen.\nVertel uw medestudent welk keuzevak u wilt volgen.\nVertel ook waarom.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medestudent en reageer.", "vraag": "WELK KEUZEVAK WIL JIJ VOLGEN? KOKEN VOOR KINDEREN OF KOKEN ZONDER VLEES?", "antwoord": "Ik kies voor ‘Koken zonder viees: Steeds meer mensen willen\nzonder viees eten.", "pages": [249, 250], "image": null}, {"id": 126, "set": 11, "opdracht_in_set": 6, "title": "Keuzevak opleiding Toerisme", "situatie": "U volgt de mbo-opleiding Toerisme.\nU moet een keuzevak doen.\nU kunt kiezen uit Duits of Rekenen.\nUw medestudent vraagt welk vak u kiest.\nVertel uw medestudent welk vak u kiest.\nVertel ook waarom u dat vak kiest.\nGeef hiervoor twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medestudent en reageer.", "vraag": "WELK KEUZEVAK LIJKT JOU BETER? DUITS OF REKENEN?", "antwoord": "Ik kies voor Duits. In het toerisme moet je veel talen kennen. En\nIk ben beter in talen dan in rekenen.", "pages": [251, 252], "image": null}, {"id": 127, "set": 11, "opdracht_in_set": 7, "title": "Kinderen in de gang", "situatie": "U werkt op een basisschool.\nDe kinderen hebben pauze.\nEr gebeurt iets in de gang.\nKijk naar het plaatje.", "vraag": "", "antwoord": "Jongens! Je mag hier niet voetballen.", "pages": [253, 254], "image": "images/img_127.png"}, {"id": 128, "set": 11, "opdracht_in_set": 8, "title": "Kinderfeest", "situatie": "U werkt in de kantine van een buurthuis.\nEr wordt vanmiddag een groot kinderfeest gehouden.\nUw nieuwe collega helpt u met het klaarmaken van broodjes\nvoor het feest.\nKijk naar de plaatjes.\nVertel uw collega wat zij moet doen.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw collega.", "vraag": "IK MOET DUS BROOOJES MAKEN. WAT MOET IK DAN PRECIES DOEN?", "antwoord": "Je moet eerst de broodjes snijden. Dan moet je kaas, jam of\nvlees op de broodjes doen. En je moet de broodjes in drie\nmanden doen.", "pages": [255, 256], "image": "images/img_128.png"}, {"id": 129, "set": 11, "opdracht_in_set": 9, "title": "Kinderwagen in de trein", "situatie": "U staat op het station met uw kindje in de kinderwagen.\nEr staan veel mensen.\nU kunt de kinderwagen niet alleen in de trein zetten.\nWat vraagt u aan één van de mensen?", "vraag": "", "antwoord": "Kunt u mij even helpen?", "pages": [257, 258], "image": null}, {"id": 130, "set": 11, "opdracht_in_set": 10, "title": "Klant opbellen", "situatie": "U werkt op een kantoor.\nU hebt een gesprek gehad met een klant.\nAls zij weg is, ziet u iets.\nKijk naar het plaatje.", "vraag": "JA, DAT KLOPT. IK BEN VANMORGEN BIJ U GEWEEST. IS ER NOG WAT?", "antwoord": "U bent uw tas vergeten.", "pages": [259, 260], "image": "images/img_130.png"}, {"id": 131, "set": 11, "opdracht_in_set": 11, "title": "Kledingwinkel", "situatie": "U werkt als verkoper in een kledingwinkel.\nVandaag was er een probleem in de winkel.\nU hebt dat opgelost.\nUw baas vraagt wat er precies is gebeurd.\nKijk naar de plaatjes.\nVertel uw baas wat er is gebeurd.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw baas.", "vraag": "WAT IS ER PRECIES GEBEURD?", "antwoord": "Twee klanten maakten ruzie over 1 jurk. Ik heb een tweede\njurk ult het magazijn gepakt. En de twee klanten waren bilj.", "pages": [261, 262], "image": "images/img_131.png"}, {"id": 132, "set": 11, "opdracht_in_set": 12, "title": "Kluisje", "situatie": "U gaat naar het zwembad.\nU gebruikt een kluisje om uw spullen in te doen.\nEen bezoeker vraagt aan u hoe het kluisje werkt.\nKijk naar de plaatjes.\nVertel de bezoeker wat hij moet doen.\nU moet daarbij alle plaatjes gebruiken.\nU hoort eerst de bezoeker.", "vraag": "HOE WERKT HET KLUISJE?", "antwoord": "Je moet de spullen in het kluisje leggen. Je moet een euro in\nhet slot doen. En je moet de sleutel van het kluisje pakken.", "pages": [263, 264], "image": "images/img_132.png"}, {"id": 133, "set": 12, "opdracht_in_set": 1, "title": "Klusjes bij mensen thuis", "situatie": "Op de school van uw kind is een actie.\nDe kinderen verdienen geld voor een goed doel.\nZe doen daarvoor klusjes bij mensen thuis.\nTwee kinderen komen bij u thuis.\nU weet wel iets wat ze kunnen doen.\nKijk naar het plaatje.\nLuister naar één van de kinderen en reageer.", "vraag": "FIJN DAT WE MOGEN HELPEN. WAT KUNNEN WE DOEN?", "antwoord": "Je kunt de bladeren uit de tuin in de groenbak gooien.", "pages": [265, 266], "image": "images/img_133.png"}, {"id": 134, "set": 12, "opdracht_in_set": 2, "title": "Koffie", "situatie": "Eris kritiek op de koffiemachine op uw werk.\nVeel collega’s vinden de koffie niet lekker.\nUw collega stelt voor om vanaf nu zelf koffie te zetten.\nU vindt dat geen goed idee.\nOvertuig uw collega ervan dat het geen goed idee is om zelf\nkoffie te zetten.\nU hoort eerst uw collega.", "vraag": "IK VIND DAT WE BETER ZELF KOFFIE KUNNEN GAAN ZETTEN. WAT VIND JIJ?", "antwoord": "Ik vind het geen goed idee. We hebben 1 automaat voor\ntedereen, dat is makkelijk.", "pages": [267, 268], "image": null}, {"id": 135, "set": 12, "opdracht_in_set": 3, "title": "Koffie drinken in de stad", "situatie": "Een vriend belt u op.\nHij wil koffie met u drinken in de stad.\nU moet eerst nog een paar dingen doen.\nKijk naar de plaatjes.\nVertel uw vriend wat u nog moet doen voor u in de stad kunt\nzijn.\nU moet daarbij alle plaatjes gebruiken.\nVertel ook hoeveel tijd u nog nodig hebt.\nU hoort eerst uw vriend.", "vraag": "KUN JIJ OVER TIEN MINUTEN KOFFIE DRINKEN MET MIJ IN DE STAD?", "antwoord": "Prima. Maar ik moet eerst even douchen en aankleden.\nIk korn op de fiets. Ik zie je over 30 minuten.", "pages": [269, 270], "image": "images/img_135.png"}, {"id": 136, "set": 12, "opdracht_in_set": 4, "title": "Koffie halen", "situatie": "U bent op school.\nU hebt dorst en u gaat een kopje koffie halen.\nEr gaat iets verkeerd.\nKijk naar het plaatje.\nLuister naar uw medecursist en reageer.", "vraag": "HE, JE ZIT ONDER DE KOFFIE. HOE KOMT DAT?", "antwoord": "Er zitten geen kopjes in de koffiemachine.", "pages": [271, 272], "image": "images/img_136.png"}, {"id": 137, "set": 12, "opdracht_in_set": 5, "title": "Koffiemachine kapot", "situatie": "U werkt in een café.\nU hebt vanochtend gewerkt.\nTijdens uw dienst ging de koffiemachine kapot.\nUw collega die vanmiddag werkt, vraagt wat er toen gebeurde.\nKijk naar het plaatje.\nVertel uw collega wat er gebeurde.\nU hoort eerst uw collega.", "vraag": "JEETJE, WAS DE KOFFIEMACHINE STUK? EN WAT GEBEURDE ER TOEN?", "antwoord": "Er was geen koffie. Alle klanten waren boos.", "pages": [273, 274], "image": "images/img_137.png"}, {"id": 138, "set": 12, "opdracht_in_set": 6, "title": "Kopen via internet", "situatie": "Een vriend wil een computer kopen.\nHij heeft op internet een advertentie gezien van iemand die zijn\ncomputer wil verkopen. U vindt dat geen goed idee.\nVertel uw vriend waarom u het geen goed idee vindt dat hij een\ncomputer via internet koopt.\nGeef twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Dat is geen goed idee. Je kent de verkoper niet. Je hebt\ngeen garantie. Een nieuwe computer uit de winkel is\nmisschien niet duur.", "pages": [275, 276], "image": null}, {"id": 139, "set": 12, "opdracht_in_set": 7, "title": "Krant", "situatie": "U werkt bij de klantenservice van een krant.\nU belt mensen om te vragen of ze een abonnement willen\nnemen op de krant.\nBij het abonnement betaal je maandelijks om de krant dagelijks\nte ontvangen.\nU krijgt een vrouw aan de telefoon.\nOvertuig de vrouw ervan om het abonnement te nemen.\nLuister naar de vrouw en reageer.", "vraag": "WAAROM ZOU IK EEN ABONNEMENT NEMEN OP DE KRANT?", "antwoord": "U krijgt dan automatisch de krant thuils. U hoeft de krant niet\nIn de winkel te kopen.", "pages": [277, 278], "image": null}, {"id": 140, "set": 12, "opdracht_in_set": 8, "title": "Kras op auto", "situatie": "Uw vriend is tegen de auto van een buurman gefietst.\nEr zit een grote kras op de auto.\nUw vriend vraagt hoe hij het probleem kan oplossen.\nVertel uw vriend hoe hij het probleem het best kan oplossen.\nU hoort eerst uw vriend.", "vraag": "TJA - ER ZIT EEN GROTE KRAS OP DE AUTO. WAT KAN [IK NU HET BESTE DOEN?", "antwoord": "Je moet even met de buurman praten. En je moet met jouw\nverzekering belien.", "pages": [279, 280], "image": null}, {"id": 141, "set": 12, "opdracht_in_set": 9, "title": "Laatste mode", "situatie": "U volgt een cursus kleding maken.\nAlle cursisten moeten een modern kledingstuk gaan maken.\nUw medestudent weet niet welke kleding nu in de mode is.\nU weet wel hoe hij dat kan onderzoeken.\nKijk naar de plaatjes.\nVertel uw medestudent hoe hij kan onderzoeken welke kleding\nnu in de mode is.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw medestudent.", "vraag": "HOE KAN IK ER NOU ACHTER KOMEN WAT ER NU IN DE MODE IS?", "antwoord": "Je moet in winkels kijken. Je moet ook in modebladen kijken.\nEn je moet bij een modeshow kijken.", "pages": [281, 282], "image": "images/img_141.png"}, {"id": 142, "set": 12, "opdracht_in_set": 10, "title": "Lang of kort?", "situatie": "In Nederland duurt de zomervakantie van de basisschool zes\nweken.\nIn andere landen hebben leerlingen van de basisschool soms\nwel drie maanden zomervakantie.\nDe schooldagen duren dan wel langer.\nVertel wat u beter vindt voor leerlingen van de basisschool:\neen lange of een korte zomervakantie.\nVertel ook waarom u dat beter vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind een korte zomervakantie beter. Ik heb zelf werk en\nmijn zomervakantie is ook kort.", "pages": [283, 284], "image": null}, {"id": 143, "set": 12, "opdracht_in_set": 11, "title": "Lange teksten", "situatie": "U werkt op een belastingkantoor.\nU moet vaak lange teksten lezen.\nDe teksten zijn documenten op de computer. Een collega print\nze uit om ze op papier te lezen. Hij vraagt wat u liever doet:\nde teksten op het computerscherm lezen of op papier.\nVertel wat u liever doet. Vertel ook waarom u dat liever doet.", "vraag": "", "antwoord": "Ik lees liever op papier. Ik kan mij dan beter concentreren.", "pages": [285, 286], "image": null}, {"id": 144, "set": 12, "opdracht_in_set": 12, "title": "Langer doorwerken", "situatie": "Vroeger mochten mensen in Nederland stoppen met werken\nals ze 65 jaar waren.\nNu moeten mensen steeds langer doorwerken.\nVertel wat u vindt van langer doorwerken.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Veel mensen blijven Langer gezond en fit.\nZij kunnen doorwerken, als zij 65 jaar zijn.", "pages": [287, 288], "image": null}, {"id": 145, "set": 13, "opdracht_in_set": 1, "title": "Laptop van de zaak", "situatie": "U heeft nieuw werk.\nU krijgt bij uw nieuwe werk een laptop.\nBij de laptop krijgt u een koptelefoon.\nDaarnaast mag u een ander product kiezen dat u bij de laptop\nkunt gebruiken.\nUw leidinggevende vraagt welk product u wilt.\nVertel uw leidinggevende welk product u kiest.\nVertel ook waarvoor u dit product nodig heeft.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw leidinggevende en reageer.", "vraag": "WELK PRODUCT KIES JIJ VOOR BIJ DE LAPTOP?", "antwoord": "Ik kies een goede tas bij deze laptop. Ik moet de laptop vellig\nkunnen vervoeren.", "pages": [289, 290], "image": null}, {"id": 146, "set": 13, "opdracht_in_set": 2, "title": "Laptops", "situatie": "Op scholen wordt steeds vaker lesgegeven met behulp van\nlaptops.\nVertel wat u ervan vindt dat leerlingen vaak met laptops moeten\nwerken.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind het goed dat kinderen met laptops op school werken.\nZij kunnen dan snel veel informatie vinden.", "pages": [291, 292], "image": null}, {"id": 147, "set": 13, "opdracht_in_set": 3, "title": "Leeg plastic flesje", "situatie": "U bent in uw tuin aan het werk.\nErloopt een jongen langs.\nHij gooit een leeg plastic flesje op straat.\nU vindt dat niet goed.\nVertel de jongen wat hij volgens u wel moet doen met het\nlege plastic flesje.\nLuister naar de jongen en reageer.", "vraag": "WAT IS ER?", "antwoord": "Je moet dat flesje in de prullenbak gooien.", "pages": [293, 294], "image": null}, {"id": 148, "set": 13, "opdracht_in_set": 4, "title": "Lekker eten maken", "situatie": "Uw buurvrouw is volgende week jarig.\nZij wil graag lekker eten maken voor haar feestje.\nZij vraagt aan u wat ze zal maken.\nVertel uw buurvrouw wat voor lekker eten ze kan maken.\nU hoort eerst uw buurvrouw.", "vraag": "IK BEN VOLGENDE WEEK JARIG, MAAR IK WEET ECHT NIET WAT VOOR ETEN IK MOET MAKEN. HEB JIJ EEN IDEE?", "antwoord": "Je kunt een grote pan soep maken en verse broodjes erbij.\nDat is makkelijk en iedereen vindt het lekker.", "pages": [295, 296], "image": null}, {"id": 149, "set": 13, "opdracht_in_set": 5, "title": "Lestijden", "situatie": "U volgt de opleiding Verzorgende.\nEen medestudent gaat een keuzevak volgen: Eerste Hulp.\nZij kan kiezen uit twee tijdstippen voor het vak.\nKijk naar de plaatjes.\nVertel uw medestudent welk tijdstip ze het best kan kiezen.\nVertel ook waarom ze dat tijdstip het best kan kiezen.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw medestudent.", "vraag": "WAT VIND JIJ? WELKE LES MOET IK KIEZEN?", "antwoord": "Je kunt beter kiezen voor de avondies. In de avond zijn er\nminder studenten. En in de avond heb je les van een aardige\ndocent.", "pages": [297, 298], "image": "images/img_149.png"}, {"id": 150, "set": 13, "opdracht_in_set": 6, "title": "Leuk feest", "situatie": "In Nederland vinden veel mensen Kerstmis een leuk feest.\nWat vindt u een leuk feest?\nVertel wat u een leuk feest vindt.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind Sinterklaas een leuk feest.\nDan krijgt iedereen cadeautjes.", "pages": [299, 300], "image": null}, {"id": 151, "set": 13, "opdracht_in_set": 7, "title": "Lezen met muziek", "situatie": "Sommige mensen lezen graag met muziek aan.\nVertel of u graag met muziek aan leest of niet.\nVertel ook waarom u dat wel of niet graag doet.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik lees zonder muziek. Ik kan me niet concentreren met muziek\ntijdens het lezen.", "pages": [301, 302], "image": null}, {"id": 152, "set": 13, "opdracht_in_set": 8, "title": "Lid worden van een bibliotheek", "situatie": "U wilt lid worden van een bibliotheek.\nUw buurvrouw is al lid van een bibliotheek.\nU praat met uw buurvrouw.\nStel haar twee vragen over lid zijn van de bibliotheek.\nU krijgt eerst de tijd om uw vragen voor te bereiden.\nLuister daarna naar uw buurvrouw en reageer.", "vraag": "", "antwoord": "HOll!... WAT WILDE JE VRAGEN?\nWat kost het lidmaatschap van de bibliotheek? En op welke\ndagen is de bibliotheek open?", "pages": [303, 304], "image": null}, {"id": 153, "set": 13, "opdracht_in_set": 9, "title": "Lokaal 22", "situatie": "U bent schilder.\nU werkt vandaag in een school.\nU bent aan het schilderen in lokaal 22.\nEen leerling weet niet waar ze nu les heeft.\nKijk naar het plaatje.\nLuister naar de leerling en reageer.", "vraag": "OH... U BENT AAN HET SCHILDEREN. IK DACHT DAT WIJ HIER LES HADDEN.", "antwoord": "Nee, de les is vandaag in lokaal 26.", "pages": [305, 306], "image": "images/img_153.png"}, {"id": 154, "set": 13, "opdracht_in_set": 10, "title": "Loonstrookje", "situatie": "U werkt op een kantoor.\nU praat met een collega over het loonstrookje.\nDaarop staat hoeveel geld u iedere maand krijgt.\nUw collega vraagt wat u liever wilt: een papieren loonstrookje of\neen loonstrookje via de e-mail.\nVertel wat u liever wilt.\nVertel ook waarom u dat liever wilt.\nU hoort eerst uw collega.", "vraag": "WAT VIND JIJ? HEB JIJ LIEVER EEN PAPIEREN LOON- STROOKJE OF EEN LOONSTROONKJE VIA DE E-MAIL?", "antwoord": "Ik vind een loonstrookje via de e-malt beter. Ik kan de mails\ngoed bewaren.", "pages": [307, 308], "image": null}, {"id": 155, "set": 13, "opdracht_in_set": 11, "title": "Lopen met buurjongetije", "situatie": "U loopt in het park met uw buurjongetje.\nIn het park staat een bord.\nKijk naar het plaatje.", "vraag": "", "antwoord": "Je moet dat papier in de prullenbak goolen.", "pages": [309, 310], "image": "images/img_155.png"}, {"id": 156, "set": 13, "opdracht_in_set": 12, "title": "Lunch verzorgen", "situatie": "U volgt een mbo-opleiding tot kok.\nU moet samen met een medestudent als praktijkopdracht een\nlunch verzorgen.\nEr zijn twee mogelijkheden: op donderdagmiddag voor\ndocenten van een basisschool of op zaterdagmiddag bij een\nbuurtfeest.\nU wilt graag op donderdagmiddag een lunch verzorgen voor\nde docenten, maar uw medestudent wil liever een lunch maken\nvoor het buurtfeest.\nOvertuig uw medestudent ervan om een lunch te maken voor\ndocenten van de basisschool.\nGeef ten minste twee argumenten.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar de medestudent en geef antwoord.", "vraag": "NOU, IK WEET WEL WAT WE MOETEN KIEZEN. WE GAAN ZATERDAG EEN LUNCH MAKEN VOOR HET BUURTFEEST.", "antwoord": "We kunnen beter de lunch verzorgen op donderdag voor de\nleraren van de basisschool. We zullen de docenten blij maken.\nEn op zaterdag moet ik voetballen.", "pages": [311, 312], "image": null}, {"id": 157, "set": 14, "opdracht_in_set": 1, "title": "Lunchpauze", "situatie": "In Nederland hebben werknemers tijdens de lunch meestal\nmaar een half uur pauze.\nIn veel landen duurt de lunchpauze langer, soms wel twee uur.\nVertel wat u beter vindt: een korte of een lange lunchpauze.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "\\k vind een lange lunchpauze beter. Ik moet goed uitrusten.\n30 minuten is te weinig.", "pages": [313, 314], "image": null}, {"id": 158, "set": 14, "opdracht_in_set": 2, "title": "Machines", "situatie": "In steeds meer fabrieken wordt het werk van mensen\novergenomen door machines.\nWat vindt u hiervan?\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind dat prima. Dan kunnen mensen meer interessante\ndingen doen.", "pages": [315, 316], "image": null}, {"id": 159, "set": 14, "opdracht_in_set": 3, "title": "Meer bewegen", "situatie": "U praat met uw vriendin.\nZij wil graag meer bewegen, maar ze vindt de sportschool te\nduur.\nVertel uw vriendin welke twee dingen zij kan doen om toch\nmeer te bewegen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw vriendin en reageer.", "vraag": "IK WIL MEER BEWEGEN, MAAR IK VIND DE SPORTSCHOOL ZO DUUR. WEET JIJ WAT IK KAN DOEN?", "antwoord": "Je kunt gaan hardlopen, dat kun je dichtbij huis doen. En je\nkunt op je fiets naar Je werk gaan.", "pages": [317, 318], "image": null}, {"id": 160, "set": 14, "opdracht_in_set": 4, "title": "Meer theorie, minder praktijk", "situatie": "U volgt een opleiding tot automonteur.\nU heeft iedere week 10 uur theorieles en 20 uur praktijkles.\nDe opleiding wil dat volgend jaar anders doen: 20 uur theorieles\nen 10 uur praktijkles.\nU vindt dat een slecht idee.\nEen medestudent vraagt waarom u dat een slecht idee vindt.\nVertel de medestudent waarom u het plan van de schoolleiding\neen slecht idee vindt.\nU hoort eerst uw medestudent.", "vraag": "DUS WE KRIJGEN VOLGEND JAAR MEER THEORIE EN MINDER PRAKTIJKLESSEN. WAAROM VIND JE DAT EEN SLECHT IDEE?", "antwoord": "Een automonteur moet niet veel in boeken kijken.\nPraktijklessen zijn voor een automonteur heel belangrijk.", "pages": [319, 320], "image": null}, {"id": 161, "set": 14, "opdracht_in_set": 5, "title": "Met de bus mee", "situatie": "U werkt als buschauffeur.\nEen vrouw wil mee met de bus, maar er is een probleem.\nKijk naar het plaatje.\nVertel de vrouw wat zij het best kan doen.", "vraag": "OH NEE! ... DIT PAST NIETI", "antwoord": "U kunt aan de achterkant instappen. Daar is meer ruimte.", "pages": [321, 322], "image": "images/img_161.png"}, {"id": 162, "set": 14, "opdracht_in_set": 6, "title": "Met of zonder radio werken", "situatie": "U werkt op een kantoor.\nEen aantal collega’s wil tijdens het werk graag naar de radio\nluisteren.\nAndere collega’s willen dat juist niet.\nUw baas vraagt wat u liever wilt: werken met of zonder de radio\naan.\nVertel uw baas wat u liever wilt: werken met of zonder radio.\nVertel ook waarom u dat wilt.\nGeef twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw baas en reageer.", "vraag": "WAT WIL JIJ LIEVER? WERKEN MET OF ZONDER DE RADIO AAN? EN WAAROM?", "antwoord": "Ik wil zonder radio werken. Ik wil me goed concentreren.\nEn ik houd niet van Hollandse muziek.", "pages": [323, 324], "image": null}, {"id": 163, "set": 14, "opdracht_in_set": 7, "title": "Mobiele telefoon", "situatie": "Op veel middelbare scholen moeten mobiele telefoons tijdens\nde les uit.\nAls een leerling zijn telefoon toch gebruikt, moet hij de telefoon\naan de leraar geven.\nVertel wat u van deze regel vindt.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind dat een goede regel. De leerling heeft de telefoon niet\nnodig tijdens de les.", "pages": [325, 326], "image": null}, {"id": 164, "set": 14, "opdracht_in_set": 8, "title": "Mobiele telefoon ligt thuis", "situatie": "U reist elke dag met een collega met de trein naar uw werk.\nVandaag is de trein veel te laat.\nU wilt naar uw werk bellen om te zeggen dat u later komt maar\nuw mobiele telefoon ligt thuis.\nUw collega heeft wel een mobiele telefoon.\nWat vraagt u aan uw collega?", "vraag": "", "antwoord": "Mag ik jouw telefoon even gebruiken?", "pages": [327, 328], "image": null}, {"id": 165, "set": 14, "opdracht_in_set": 9, "title": "Modeshow", "situatie": "U werkt in een kledingzaak.\nKomend weekend organiseert u een modeshow in de winkel.\nEr moet nog veel geregeld worden.\nUw collega wil graag helpen.\nVertel haar wat ze kan doen.\nKijk naar uw aantekeningen.\n* Mierefoce HI!\n.", "vraag": "WAT EEN DRUKTE, HE? ALS JE WILT, KAN IK NOG WEL EEN PAAR DINGEN VAN JE OVERNEMEN.", "antwoord": "Ja, graag. Wil jij bloemen halen? Er moeten ook stoelen komen.\nEn wil jij een microfoon zoeken?", "pages": [329, 330], "image": null}, {"id": 166, "set": 14, "opdracht_in_set": 10, "title": "Moeite om de docent te verstaan", "situatie": "U volgt een mbo-opleiding.\nUw medestudent heeft moeite om de docent te verstaan.\nZe zit altijd op dezelfde plek.\nKijk naar het plaatje.\nVertel uw medestudent wat zij kan doen.\nU hoort eerst uw medestudent.", "vraag": "WAT HEB JIJ DAN VOOR OPLOSSING?", "antwoord": "Je moet voorin de klas gaan zitten.", "pages": [331, 332], "image": "images/img_166.png"}, {"id": 167, "set": 14, "opdracht_in_set": 11, "title": "Muntgeld", "situatie": "U bent bij de supermarkt.\nU hebt een munt van € 1,- nodig voor het winkelwagentje.\nU hebt alleen een munt van € 2,-.\nU gaat naar de klantenservice.\nWat vraagt u aan de medewerker?\nU hoort eerst de medewerker.", "vraag": "WAT KAN IK VOOR U DOEN?", "antwoord": "Kunt u deze munt wisselen?", "pages": [333, 334], "image": null}, {"id": 168, "set": 14, "opdracht_in_set": 12, "title": "Muziek in de trein", "situatie": "U bent conducteur en u werkt in de trein.\nEen jongen heeft zijn muziek heel hard staan.\nU ziet dat de andere mensen in de trein daar last van hebben.\nHet is uw werk om daar iets van te zeggen.\nWat zegt u tegen de jongen?", "vraag": "", "antwoord": "Wil je de muziek zachter zetten?", "pages": [335, 336], "image": null}, {"id": 169, "set": 15, "opdracht_in_set": 1, "title": "Muziekinstrument", "situatie": "Veel kinderen in Nederland moeten van hun ouders een\nmuziekinstrument leren bespelen.\nZe vinden dat dit bij de opvoeding hoort.\nAnderen vinden een muziekinstrument bespelen helemaal niet\nbelangrijk.\nVindt u dat kinderen een muziekinstrument moeten leren\nbespelen?\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind dat niet belangrijk. Kinderen kunnen ook andere\ndingen doen, zoals voetballen of iets anders.", "pages": [337, 338], "image": null}, {"id": 170, "set": 15, "opdracht_in_set": 2, "title": "Muziekles is belangrijk", "situatie": "U volgt de opleiding tot onderwijsassistent.\nU heeft een gesprek met een medestudent over muziekles op de\nbasisschool.\nDe medestudent vindt muziekles niet belangrijk op school.\nU vindt muziekles wel belangrijk.\nOvertuig uw medestudent ervan dat muziekles wel belangrijk is\nop school.\nGeef hiervoor drie redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medestudent en reageer.", "vraag": "IK VIND MUZIEKLES HELEMAAL NIET BELANGRIJK. WAAROM VIND JIJ HET WEL BELANGRIJK?", "antwoord": "Ik vind de muziekles wel belangrijk. Kinderen kunnen dingen\nleren over muziekinstrumenten. Zij kunnen dingen leren over\nklassieke muziek. En zij kunnen zelf muziek maken.", "pages": [339, 340], "image": null}, {"id": 171, "set": 15, "opdracht_in_set": 3, "title": "Naar de politie gaan", "situatie": "De tas van een vriendin van u is weg.\nHij is gestolen in het centrum van de stad.\nUw vriendin wil het niet aan de politie vertellen.\nU vindt dat zij dat wel moet doen.\nGeef uw vriendin twee redenen waarom zij naar de politie\nmoet gaan.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw vriendin en reageer.", "vraag": "WAAROM DAN?", "antwoord": "Ol DUS JE VINDT DAT IK NAAR DE POLITIE MOET GAAN.\nDe politie moet de dief zoeken. En misschien vindt de politie\njouw tas.", "pages": [341, 342], "image": null}, {"id": 172, "set": 15, "opdracht_in_set": 4, "title": "Naar school gaan", "situatie": "Uw vriendin heeft een zoon van twaalf jaar.\nHij gaat niet graag naar school.\nHij vraagt u hoe u het vroeger vond om naar school te gaan.\nLuister naar de jongen en geef antwoord.", "vraag": "HOE VOND U HET VROEGER EIGENLIJK OM NAAR SCHOOL TE GAAN?", "antwoord": "Ik vond het leuk ik heb veel geleerd op school.", "pages": [343, 344], "image": null}, {"id": 173, "set": 15, "opdracht_in_set": 5, "title": "Naar zee", "situatie": "U bent met de kinderen van uw buren een dagje naar zee\ngeweest.\nAan het eind van de dag brengt u de kinderen weer thuis.\nDe buurvrouw vraagt wat u vandaag gedaan hebt.\nKijk naar de plaatjes.\nVertel uw buurvrouw wat u en de kinderen vandaag gedaan\nhebben.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw buurvrouw.", "vraag": "EN... WAT HEBBEN JULLIE GEDAAN AAN ZEE?", "antwoord": "Ik heb met de kinderen in zee gezwommen. We hebben grote\nboten gezien. En we hebben een ijsje gegeten op het strand.", "pages": [345, 346], "image": "images/img_173.png"}, {"id": 174, "set": 15, "opdracht_in_set": 6, "title": "Nachtdienst", "situatie": "U werkt overdag in een ziekenhuis.\nUw baas vraagt of u ook nachtdiensten wilt gaan werken.\nWat vindt u daarvan?\nVertel ook waarom u dat vindt.\nU hoort eerst uw baas.", "vraag": "ZOU JE VOORTAAN OOK IN DE NACHTDIENST WILLEN WERKEN?", "antwoord": "Nee, ik vind dat niet fijn. Ik heb nachtrust nodig. Ik kan overdag\nniet slapen.", "pages": [347, 348], "image": null}, {"id": 175, "set": 15, "opdracht_in_set": 7, "title": "Nekklachten voorkomen", "situatie": "U studeert ICT.\nEen medestudent heeft vaak last van zijn nek.\nHij vraagt wat hij kan doen om nekpijn te voorkomen.\nKijk naar het plaatje.\nVertel uw medestudent wat hij kan doen om pijn in zijn nek te", "vraag": "WAT KAN IK DOEN OM PIJN IN MIJN NEK TE VOORKOMEN?", "antwoord": "De stoel en de computer moeten op de goede hoogte staan.", "pages": [349, 350], "image": "images/img_175.png"}, {"id": 176, "set": 15, "opdracht_in_set": 8, "title": "Niet kunnen sporten", "situatie": "U gaat twee keer per week met een vriend sporten.\nU kunt vanavond niet meedoen.\nU belt uw vriend.\nKijk naar het plaatje.\nVertel uw vriend waarom u vanavond niet mee kunt sporten.\nU hoort eerst uw vriend.", "vraag": "DUS JE SPORT NIET MEE VANAVOND. JAMMER. WAAROM NIET?", "antwoord": "Ik heb mijn been gebroken.", "pages": [351, 352], "image": "images/img_176.png"}, {"id": 177, "set": 15, "opdracht_in_set": 9, "title": "Niet naar de directeur", "situatie": "U volgt een opleiding voor automonteur.\nEen docent is heel vaak ziek.\nDaarom worden de lessen vaak verzet naar een ander moment.\nU vindt dat de directeur er wat aan moet doen.\nEen medecursist is het daar niet mee eens.\nVertel uw medecursist waarom u vindt dat de directeur er wat\naan moet doen.\nU hoort eerst uw medecursist.", "vraag": "MAAR WAAROM ZOUDEN WE NAAR DE DIRECTEUR GAAN?", "antwoord": "Ik vind het lastig, dat de les heel vaak verzet wordt.", "pages": [353, 354], "image": null}, {"id": 178, "set": 15, "opdracht_in_set": 10, "title": "Niet naar het feestje", "situatie": "U moet morgen met een medestudent een verslag inleveren.\nHet verslag is nog niet klaar.\nUw medestudent wil vanavond naar een feestje gaan.\nU vindt dat geen goed idee.\nOvertuig uw medestudent ervan om vanavond niet naar het\nfeestje te gaan.\nLuister naar uw medestudent en reageer.", "vraag": "IK HEB VANAVOND EEN FEESTJE ... IK WIL GAAN!", "antwoord": "Nee, dat kan niet. We moeten eerst het verslag afmaken.", "pages": [355, 356], "image": null}, {"id": 179, "set": 15, "opdracht_in_set": 11, "title": "Niet storen", "situatie": "U werkt in een garage.\nEen ontevreden klant wil uw chef spreken.\nU loopt naar het kantoor van de chef.\nOp de kamerdeur van uw chef hangt een briefje:\nWat zegt u tegen de klant?", "vraag": "", "antwoord": "Sorry, maar de chef is druk.", "pages": [357, 358], "image": null}, {"id": 180, "set": 15, "opdracht_in_set": 12, "title": "Niet tevreden over stage", "situatie": "U volgt een opleiding voor automonteur.\nU loopt stage bij een garage.\nU bent niet tevreden over uw stage.\nOp de plaaties ziet u wat u de hele dag doet.\nLuister naar uw begeleider en reageer.", "vraag": "WAAROM BEN JE DAN NIET TEVREDEN?", "antwoord": "Ik moet koffie halen voor de monteur en hij doet al het werk.\nIk doe niks en ik leer ook niks.", "pages": [359, 360], "image": null}, {"id": 181, "set": 16, "opdracht_in_set": 1, "title": "Nieuw gebouw", "situatie": "U werkt bij een groot bedrijf.\nHet bedrijf is verhuisd naar een nieuw gebouw.\nUw collega was vandaag niet aanwezig bij de opening van het\nnieuwe gebouw.\nU belt’s avonds met uw collega.\nUw collega vraagt hoe het nieuwe gebouw eruitziet.\nKijk naar de plaatjes.\nBeschrijf hoe het nieuwe gebouw eruitziet.\nUncen enti etieen oy eee ere ee |", "vraag": "HE! JIJ WAS VANDAAG IN HET NIEUWE GEBOUW. HOE ZIET HET ERUIT?", "antwoord": "Ja, mooi! Er zijn veel moote, grote planten. Er zijn nieuwe\nprinters. En er zijn goele kofiemachines.", "pages": [361, 362], "image": "images/img_181.png"}, {"id": 182, "set": 16, "opdracht_in_set": 2, "title": "Nieuw rooster", "situatie": "U volgt een opleiding.\nU hebt een nieuw lesrooster gekregen.\nU hebt soms's ochtends les, soms 's middags en soms 's avonds.\nUw medestudent vraagt wat u fijner vindt: 's morgens, 's\nmiddags of 's avonds les.\nVertel wat u het fijnst vindt.\nVertel ook waarom u dat vindt.\nU hoort eerst uw medestudent.", "vraag": "WIJ HEBBEN ‘S MORGENS, ‘S MIDDAGS EN ‘S AVONDS LES. WAT VIND JIJ HET FIJNSTE?", "antwoord": "Ik vind de les in de ochtend het fijnst. Dan ben ik fit. En ik kan\nIn de middag andere dingen doen.", "pages": [363, 364], "image": null}, {"id": 183, "set": 16, "opdracht_in_set": 3, "title": "Nieuwe auto", "situatie": "U wilt een nieuwe auto kopen.\nU praat met een autoverkoper.\nHij wil weten wat u belangrijk vindt bij een nieuwe auto.\nVertel wat u belangrijk vindt.\nNoem drie dingen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar de verkoper en reageer.", "vraag": "WAT VINDT U BELANGRIJK BIJ EEN AUTO?", "antwoord": "Ik vind de kleur belangrijk. Ik vind de prijs belangrijk. En de\nauto moet elektrisch zijn.", "pages": [365, 366], "image": null}, {"id": 184, "set": 16, "opdracht_in_set": 4, "title": "Nieuwe buurvrouw", "situatie": "U hebt een nieuwe buurvrouw.\nZij komt uit Zuid-Amerika.\nZe spreekt nog niet goed Nederlands.\nZe vraagt hoe zij het snelst Nederlands kan leren.\nVertel uw buurvrouw hoe ze volgens u het snelst Nederlands\nkan leren.\nGeef twee adviezen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Kirsten Verpaalen.", "pages": [367, 368], "image": null}, {"id": 185, "set": 16, "opdracht_in_set": 5, "title": "Nieuwe collega in pizzeria", "situatie": "U werkt in een Italiaans restaurant.\nHet restaurant verkoopt veel pizza's.\nVandaag is er een nieuwe collega.\nDe collega vraagt hoe hij de pizza’s moet bereiden.\nKijk naar de plaatjes.\nVertel uw collega wat hij moet doen.\nGebruik daarbij alle plaatjes.\nU hoort eerst uw collega.", "vraag": "WAT IK ALLEMAAL DOEN?", "antwoord": "Je moet tomatensaus en groente op de pizzabodem doen.\nDan moet je de pizza in de oven doen. En dan moet je de pizza\nIn stukken snijden.", "pages": [369, 370], "image": "images/img_185.png"}, {"id": 186, "set": 16, "opdracht_in_set": 6, "title": "Nieuwe medewerker", "situatie": "U werkt op een kantoor, op kamer 1.53.\nVanaf vandaag zit er een nieuwe medewerker bij u op de kamer.\nZij vraagt waar de kopieermachine staat.\nKijk naar het plaatje.\nLuister naar de nieuwe medewerker en geef antwoord.", "vraag": "KUN JE MIJ UITLEGGEN WAAR DE KOPIEERMACHINE STAAT?", "antwoord": "Ja, hoor. Op de gang rechtsaf en dan weer naar rechts. Aan het\neind staat de kopleermachine in een klein kamertje.", "pages": [371, 372], "image": "images/img_186.png"}, {"id": 187, "set": 16, "opdracht_in_set": 7, "title": "Nieuwe printer op kantoor", "situatie": "U werkt op een kantoor.\nHet kantoor heeft een nieuwe printer nodig.\nUw baas denkt dat de Printsmart de beste keus is.\nU denkt dat de Coolprint beter zou zijn.\nUw baas vraagt waarom de Coolprint beter zou zijn.\nBekijk het schema.\nOvertuig uw baas ervan dat de Coolprint een betere printer\nvoor het kantoor is.\nGeef twee argumenten.\n__Uhoort eerst uw baas.", "vraag": "WAAROM IS DE COOLPRINT EEN BETERE PRINTER VOOR ONS KANTOOR?", "antwoord": "Coolprint is beter, ja. De printer print in kleur. En Coolprint\ngebruikt minder stroom.", "pages": [373, 374], "image": null}, {"id": 188, "set": 16, "opdracht_in_set": 8, "title": "Nieuwe supermarktmedewerker", "situatie": "U werkt in een supermarkt.\nVandaag moet u aan een nieuwe medewerker uitleggen wat hij\nmoet doen.\nKijk naar de plaatjes.\nVertel de nieuwe medewerker wat hij moet doen.\nLuister naar de jongen en reageer.", "vraag": "NOU, DAN ZAL IK MAAR BEGINNEN. WAT MOET IK VANOAAG DOEN?", "antwoord": "Luister. Je moet eerst vakkenvulien. Dan moet je helpen bij de\nkaasafdeling. En daarna moet de bij de kassa helpen.", "pages": [375, 376], "image": "images/img_188.png"}, {"id": 189, "set": 16, "opdracht_in_set": 9, "title": "Nieuwe televisie", "situatie": "U wilt een nieuwe televisie kopen.\nU praat met de verkoper van de winkel.\nHij wil weten wat u belangrijk vindt bij een nieuwe televisie.\nVertel wat u belangrijk vindt.\nNoem twee dingen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar de verkoper en reageer.", "vraag": "WAT VINDT U BELANGRIJK BIJ EEN TELEVISIE?", "antwoord": "De televisie moet groot zijn. En de televisie moet niet z0\nduur zijn.", "pages": [377, 378], "image": null}, {"id": 190, "set": 16, "opdracht_in_set": 10, "title": "Nieuwe tuin", "situatie": "U woont in een flat.\nUw buurman wil graag een gezamenlijke tuin maken.\nDe tuin is dan voor alle flatbewoners.\nHij vraagt wat u van dat idee vindt.\nVertel uw buurman wat u van het idee vindt.\nVertel ook waarom u dat vindt.\nU hoort eerst uw buurman.", "vraag": "HET LIJKT ME LEUK OM 1 TUIN TE MAKEN VOOR ALLE FLATBEWONERS. WAT VIND JIJ DAARVAN?", "antwoord": "Heel goed idee. Onze buurt heeft nu te weinig groen.\nOat moet anders.", "pages": [379, 380], "image": null}, {"id": 191, "set": 16, "opdracht_in_set": 11, "title": "OV abonnement", "situatie": "U gaat binnenkort studeren.\nAls student mag u een deel van de week gratis met het\nopenbaar vervoer reizen.\nU kunt kiezen tussen gratis reizen op werkdagen of gratis reizen\nIn het weekend.\nUw vriend vraagt wat u gaat kiezen.\nVertel uw vriend waarvoor u gaat kiezen: gratis reizen op\nwerkdagen of gratis reizen in het weekend.\nVertel ook waarom u daarvoor kiest.\nU hoort eerst uw vriend.", "vraag": "WAAR GA JIJ VOOR KIEZEN? GRATIS REIZEN OP WERKDAGEN OF GRATIS REIZEN IN HET WEEKEND?", "antwoord": "Ik kies voor gratis reizen in het weekend. Ik wil elk weekend\nmet de trein naar mijn ouders.", "pages": [381, 382], "image": null}, {"id": 192, "set": 16, "opdracht_in_set": 12, "title": "Onderwijsassistent", "situatie": "U volgt de opleiding tot onderwijsassistent.\nU loopt stage op een basisschool.\nUw stagebegeleider vraagt wat u vandaag hebt gedaan.\nKijk naar de plaatjes.\nVertel uw stagebegeleider wat u hebt gedaan.\nGebruik hierbij alle plaatjes.\nLuister eerst naar uw stagebegeleider.", "vraag": "WAT HEB JE VANDAAG ALLEMAAL GEDAAN?", "antwoord": "Ik heb geholpen bij de sporties. Ik heb boeken voorgelezen.\nEn ik heb schriften gecontroleerd.", "pages": [383, 384], "image": "images/img_192.png"}, {"id": 193, "set": 17, "opdracht_in_set": 1, "title": "Ongeluk", "situatie": "U ziet op straat een ongeluk gebeuren met een fietser.\nU gaat snel naar de fietser toe.\nU vraagt een vrouw om hulp.\nKijk naar het plaatje.\nVertel de vrouw wat zij kan doen.\nLuister naar de vrouw en reageer.", "vraag": "OJEE, IK ZAG HET GEBEUREN. HOE KAN IK HELPEN?", "antwoord": "Kunt u de politie of de ambulance bellen?", "pages": [385, 386], "image": "images/img_193.png"}, {"id": 194, "set": 17, "opdracht_in_set": 2, "title": "Ontbijtservice", "situatie": "U werkt in een bakkerij.\nHet bedrijf wil een ontbijtservice gaan aanbieden.\nKlanten kunnen dan ‘s ochtends vroeg in de bakkerij eten\nvoordat ze gaan werken.\nEen collega vraagt wat u van het plan vindt.\nVertel wat u van het plan van de ontbijtservice vindt.\nVertel ook waarom u dat vindt.\nU hoort eerst uw collega.", "vraag": "WAT VIND JIJ VAN HET PLAN VAN DE ONTBIJTSERVICE IN ONZE BAKKER?", "antwoord": "Ja, leuk idee! Het is wel extra werk, maar ik vind het prima.", "pages": [387, 388], "image": null}, {"id": 195, "set": 17, "opdracht_in_set": 3, "title": "Op de stoel", "situatie": "U volgt een opleiding tot schilder.\nVandaag hebt u les.\nUw docent wil op een stoel gaan zitten.\nDat is geen goed idee!\nKijk naar het plaatje.", "vraag": "", "antwoord": "Pas op! Er staat verf op de stoel.", "pages": [389, 390], "image": "images/img_195.png"}, {"id": 196, "set": 17, "opdracht_in_set": 4, "title": "Opdracht", "situatie": "U volgt een opleiding.\nUw docent geeft een opdracht.\nKijk naar het plaatje.\nVertel uw medestudent wat hij moet doen.\nLuister naar uw medestudent en reageer.", "vraag": "EH ... WAT MOESTEN WE EIGENLIJK DOEN?", "antwoord": "We moeten pagina 34 lezen.", "pages": [391, 392], "image": "images/img_196.png"}, {"id": 197, "set": 17, "opdracht_in_set": 5, "title": "Opdracht inleveren", "situatie": "Voor uw opleiding moet u deze week een opdracht inleveren.\nU bent de hele week ziek.\nU belt uw docent.\nWat vraagt u aan uw docent?\nU hoort eerst uw docent.", "vraag": "HALLO, MET JAN VAN VEEN ...", "antwoord": "Met Kirsten Verpaalen. Ik ben ziek. Kan ik mijn opdracht\nvolgende week inleveren?", "pages": [393, 394], "image": null}, {"id": 198, "set": 17, "opdracht_in_set": 6, "title": "Opdracht mode-opleiding", "situatie": "U volgt een mode-opleiding.\nU hebt gisteren een nieuwe opdracht van uw docent gekregen.\nMaar uw medestudent was gisteren ziek.\nU belt uw medestudent om te vertellen wat hij moet doen.\nKijk naar de plaatjes.\nVertel uw medestudent wat hij moet doen.\nU moet daarbij alle plaatjes gebruiken.\nU hoort eerst de medestudent.", "vraag": "WAT IS DE NIEUWE OPDRACHT?", "antwoord": "Je moet een jurk maken op de naaimachine. Je moet een foto\nmaken van een vrouw in deze jurk. En je moet de foto op de\ncomputer zetten.", "pages": [395, 396], "image": "images/img_198.png"}, {"id": 199, "set": 17, "opdracht_in_set": 7, "title": "Opdracht over natuur", "situatie": "U volgt een opleiding tot onderwijsassistent.\nU moet samen met een medestudent een opdracht over natuur\nbedenken voor basisschoolleerlingen van negen en tien jaar.\nUw medestudent heeft twee ideeén.\nKijk naar de plaatjes.\nVertel uw medestudent wat u het beste idee vindt.\nVertel ook waarom.\nU hoort eerst uw medestudent.", "vraag": "WELKE VAN DEZE IDEEEN VIND JIJ HET BEST?", "antwoord": "We kunnen het best met de kinderen naar buiten gaan.\nZij kunnen dan bekijken wat er in de rivier zwemt.", "pages": [397, 398], "image": "images/img_199.png"}, {"id": 200, "set": 17, "opdracht_in_set": 8, "title": "Opdracht voor stagiaire", "situatie": "U werkt op een kantoor.\nEen stagiaire vraagt of ze iets voor u kan doen.\nKijk naar het plaatije.\nVertel de stagiaire wat ze voor u kan doen.\nU hoort eerst de stagiaire.", "vraag": "WAT KAN IK VOOR JE DOEN?", "antwoord": "Je kunt de brieven in de brievenbus doen.", "pages": [399, 400], "image": null}, {"id": 201, "set": 17, "opdracht_in_set": 9, "title": "Opdracht voor zomerfestival", "situatie": "U volgt een opleiding aan het Mediacollege.\nSamen met een medestudent moet u een opdracht doen voor\nschool voor een zomerfestival.\nUw medestudent was niet in de les, daarom vertelt u haar wat\njullie samen moeten doen.\nKijk naar de plaatjes.\nVertel uw medestudent wat jullie moeten doen.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw medestudent.", "vraag": "HEJ, WAT MOETEN WE DOEN VOOR DE OPDRACHT?", "antwoord": "We moeten een grote poster maken voor het zomerfestival.\nWe moeten de poster eerst laten zien aan andere studenten.\nEn daarna moeten we de poster printen.", "pages": [401, 402], "image": "images/img_201.png"}, {"id": 202, "set": 17, "opdracht_in_set": 10, "title": "Open op maandag", "situatie": "U werkt in een restaurant.\nHet restaurant is zes dagen in de week open, alleen op maandag\nIs het restaurant gesloten.\nUw baas is van plan om het bedrijf ook op maandag te openen.\nDit vindt u geen goed idee.\nOvertuig uw baas ervan dat het restaurant op maandag\ngesloten moet blijven.\nGeef hiervoor twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw baas en reageer.", "vraag": "WAAROM DENK JE DAT HET GEEN GOED IDEE IS OM OP MAANDAG OPEN TE ZIJN?", "antwoord": "Op maandag willen mensen niet naar een restaurant. En ik wil\nzelf ook elke week 1 dag vrij hebben.", "pages": [403, 404], "image": null}, {"id": 203, "set": 17, "opdracht_in_set": 11, "title": "Opleiding en geld", "situatie": "Mensen met een hbo-opleiding verdienen vaak meer geld dan\nmensen met een mbo-opleiding.\nWat vindt u daarvan?\nVertel ook waarom u dat vindt.\nGeef ten minste twee argumenten.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind dat niet goed. Mensen met een mbo-opleiding werken\nook en zij hebben ook een huis en andere dingen nodig.", "pages": [405, 406], "image": null}, {"id": 204, "set": 17, "opdracht_in_set": 12, "title": "Opleiding fotografie", "situatie": "U volgt een opleiding fotografie.\nAlle studenten hebben een familiefoto gemaakt.\nUw medestudent heeft een onvoldoende gehaald voor zijn foto.\nHij vraagt aan u wat hij de volgende keer anders moet doen.\nKijk naar het plaatje.\nVertel hem wat hij de volgende keer anders moet doen.\nNoem ten minste twee dingen.\nU hoort eerst uw medestudent.", "vraag": "WAT VIND JIJ? WAT MOET IK DE VOLGENDE KEER ANDERS DOEN, ZODAT IK WEL EEN VOLDOENDE HAAL?", "antwoord": "Iedereen moet naar de camera lachen. En iedereen moet naar\nde camera kijken.", "pages": [407, 408], "image": "images/img_204.png"}, {"id": 205, "set": 18, "opdracht_in_set": 1, "title": "Opleiding kapper", "situatie": "U volgt een opleiding voor kapper.\nVandaag gaat u het haar van een klant leren wassen.\nU verzoekt de klant te gaan zitten.\nKijk naar het plaatje.\nVertel hoe zij haar hoofd moet houden.\nU hoort eerst de klant.", "vraag": "HOE MOET IK GAAN ZITTEN?", "antwoord": "U moet uw hoofd achterover en onder de kraan leggen.", "pages": [409, 410], "image": "images/img_205.png"}, {"id": 206, "set": 18, "opdracht_in_set": 2, "title": "Opleiding kiezen", "situatie": "U wilt een opleiding volgen.\nU weet nog niet goed welke opleiding u wilt doen.\nU praat daarom met een studiebegeleider.\nZij vraagt welk profiel het best bij u past.\nKijk naar het lijstje.\nVertel welk profiel het best bij u past.\nVertel ook waarom dit profiel het best bij u past.\nU hoort eerst de begeleider.", "vraag": "ALS JE MOET KIEZEN UIT DEZE PROFIELEN, WELK PAST DAN HET BEST BY JOU? EN WAAROM VIND JE DAT?", "antwoord": "\\k kies voor het profiel ‘groen’ Ik vind het leuk om in de tuin\nte werken.", "pages": [411, 412], "image": null}, {"id": 207, "set": 18, "opdracht_in_set": 3, "title": "Pakje ophalen", "situatie": "U komt thuis.\nU vindt een briefje van uw postbode.\nBekijk het briefje:\nU gaat naar uw buren.\nLuister naar uw buurvrouw en reageer.", "vraag": "HOI, WAT KAN IK VOOR JE DOEN?", "antwoord": "Hol, buurvrouw. Heeft de postbode een pakje voor mij\nafgegeven?", "pages": [413, 414], "image": null}, {"id": 208, "set": 18, "opdracht_in_set": 4, "title": "Pakketjes", "situatie": "U werkt op een kantoor.\nU werkt op de afdeling die voor de post zorgt.\nU brengt vandaag pakketjes rond.\nU hebt een probleem.\nKijk naar het plaatje.", "vraag": "", "antwoord": "Wil je de deur voor mij opendoen?", "pages": [415, 416], "image": "images/img_208.png"}, {"id": 209, "set": 18, "opdracht_in_set": 5, "title": "Passende opleiding", "situatie": "Een kennis van u zoekt een opleiding die bij hem past.\nIn zijn vrije tijd is hij altijd druk bezig.\nKijk naar de plaatjes.\nVertel hem wat voor opleiding volgens u bij hem past.\nVertel ook waarom u dat vindt.\nLuister naar uw kennis en reageer.", "vraag": "IK MOET NOU ECHT GAAN BESLISSEN WAT IK VOLGEND OPLEIDING VOOR MIJ VINDEN?", "antwoord": "JAAR GA DOEN. WAT ZOU Ji NOU EEN GOEDE\nVolgens mij moet je een technische opleiding kiezen. Je bent\naltijd bezig met je handen.", "pages": [417, 418], "image": "images/img_209.png"}, {"id": 210, "set": 18, "opdracht_in_set": 6, "title": "Pauze in fabriek", "situatie": "U werkt in een fabriek.\nU en uw collega’s vinden dat er te weinig pauzes zijn.\nU gaat hierover in gesprek met uw baas.\nVertel aan uw baas wat u wilt.\nVertel ook waarom u dat wilt.\nGeef twee argumenten.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw baas en reageer.", "vraag": "WAT WIL JE ME VRAGEN OVER DE PAUZES?", "antwoord": "Ik wil graag meer pauze. Het werk is zwaar. En we hebben niet\ngenoeg tijd om te eten.", "pages": [419, 420], "image": null}, {"id": 211, "set": 18, "opdracht_in_set": 7, "title": "Persoon beschrijven", "situatie": "U bent in de stad.\nOpeens ziet u hoe iemand de tas van een oudere dame grijpt.\nU vertelt aan een politieagent wie het gedaan heeft.\nKijk naar het plaatje.\nLuister naar de politieagent en reageer.", "vraag": "U HEBT DUS GEZIEN WIE DIT GEDAAN HEEFT. KUNT U DEZE PERSOON BESCHRIJVEN?", "antwoord": "Het meisje heeft lang haar, een groene rok en roze schoenen.", "pages": [421, 422], "image": "images/img_211.png"}, {"id": 212, "set": 18, "opdracht_in_set": 8, "title": "Piano", "situatie": "Uw buurvrouw speelt vaak ‘s avonds op de piano.\nU hebt daar veel last van.\nU gaat met uw buurvrouw praten.\nDoe een voorstel voor een oplossing.\nU hoort eerst uw buurvrouw.", "vraag": "IK MOET WEL OEFENEN VOOR MIJN PIANOLES. HOE MOET IK DAT DAN DOEN?", "antwoord": "Ik begrijp het. Je kunt het beste oefenen tussen 5 uur en 8 uur\nIn de avond.", "pages": [423, 424], "image": null}, {"id": 213, "set": 18, "opdracht_in_set": 9, "title": "Plastic tassen", "situatie": "Uw vriend koopt bij elk bezoek aan de supermarkt een plastic\nboodschappentas.\nU bent het daar niet mee eens.\nVertel uw vriend waarom u het daar niet mee eens bent.\nU hoort eerst uw vriend.", "vraag": "WAAROM IS HET NOU ZO ERG DAT IK DIE PLASTIC TASSEN KOOP?", "antwoord": "Joh, plastic is heel slecht voor het milieu.", "pages": [425, 426], "image": null}, {"id": 214, "set": 18, "opdracht_in_set": 10, "title": "Postbezorger", "situatie": "U werkt als postbezorger.\nU brengt de post rond.\nEr ging vandaag veel fout tijdens uw werk.\nKijk naar de plaatjes.\nVertel uw leidinggevende wat er vandaag niet goed ging.\nU moet hierbij alle plaatjes gebruiken.\nU hoort eerst uw leidinggevende.", "vraag": "GING HET NIET GOED VANDAAG? WAT GING ER DAN FOUT?", "antwoord": "Ik kreeg een lekke band. Ik viel op de grond. En een hond heeft\nmij gebeten.", "pages": [427, 428], "image": "images/img_214.png"}, {"id": 215, "set": 18, "opdracht_in_set": 11, "title": "Praktijkdag dierentuin", "situatie": "U volgt de mbo-opleiding Dierverzorging.\nGisteren had u met uw klas een praktijkdag in de dierentuin.\nEen medestudent was ziek en kon niet meegaan.\nZe vraagt wat u gisteren in de dierentuin hebt gedaan.\nKijk naar de plaatjes.\nVertel uw medestudent wat u in de dierentuin hebt gedaan.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw medestudent.", "vraag": "WAT HEB JE GISTEREN IN DE DIERENTUIN GEDAAN?", "antwoord": "We hebben de poep van de olifanten opgeruimd. We hebben\nmedicijnen gegeven aan een aap. En we hebben de zebra's in\nhun hok gebracht.", "pages": [429, 430], "image": "images/img_215.png"}, {"id": 216, "set": 18, "opdracht_in_set": 12, "title": "Praktijkopdracht", "situatie": "U volgt een opleiding tot loodgieter.\nU hebt gisteren een praktijkopdracht uitgevoerd.\nEen vriend vraagt wat u precies gedaan hebt.\nKijk naar de plaatjes.\nVertel uw vriend wat voor opdracht u hebt gedaan.\nU moet hierbij alle plaatjes gebruiken. U hoort eerst uw vriend.", "vraag": "WAT VOOR OPORACHT HEB JE GISTEREN GEDAAN?", "antwoord": "Ik heb een wasbak geplaatst. Eerst heb ik de hoogte gemeten.\nDaama heb ik de afvoerpijp geplaatst. En toen heb ik de\nwasbak geplaatst.", "pages": [431, 432], "image": "images/img_216.png"}, {"id": 217, "set": 19, "opdracht_in_set": 1, "title": "Presentatie geven", "situatie": "U volgt een opleiding.\nVandaag moet u een presentatie geven.\nU wilt graag beginnen maar er is een probleem met uw\nmedestudenten.\nKijk naar het plaatje.", "vraag": "", "antwoord": "Hoi, allemaal. Luister, ik ga jullie iets vertellen.", "pages": [433, 434], "image": "images/img_217.png"}, {"id": 218, "set": 19, "opdracht_in_set": 2, "title": "Presentatietips", "situatie": "U volgt een mbo-opleiding.\nU heeft vorige week een presentatie gegeven voor uw\nmedestudenten.\nU heeft daarvoor een heel goed cijfer gekregen van de docent.\nEen medestudent moet volgende week zijn presentatie geven.\nHij vraagt aan u hoe hij dat het beste kan doen.\nVertel uw medestudent wat hij moet doen om een goede\npresentatie te geven.\nNoem daarbij drie dingen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medestudent en reageer.", "vraag": "WAT MOET IK DOEN OM EEN GOEDE PRESENTATIE TE GEVEN?", "antwoord": "Je moet je publiek in de eerste minuut nieuwsgierig maken.\nDe presentatie moet kort zijn. Je moet leuke dingen laten zien,\nbijvoorbeeld met foto's of filmpjes.", "pages": [435, 436], "image": null}, {"id": 219, "set": 19, "opdracht_in_set": 3, "title": "Probleem bij examen", "situatie": "U volgt een opleiding.\nVandaag moet u een examen maken.\nEris een probleem.\nKijk naar het plaatje.\nVertel hem wat het probleem is.", "vraag": "WAT IS ER?", "antwoord": "Er is te veel lawaai. De klusjesmannen moeten stoppen met\nwerken.", "pages": [437, 438], "image": "images/img_219.png"}, {"id": 220, "set": 19, "opdracht_in_set": 4, "title": "Probleem in nieuw kantoor", "situatie": "U werkt op een kantoor.\nU bent verhuisd naar een andere kamer, maar u bent niet\ntevreden.\nKijk naar het plaatje.\nLuister naar uw baas en vertel hem waarom u niet tevreden", "vraag": "KUN JE NIET GOED WERKEN OP JE NIEUWE KAMER? WAT IS ER DAN AAN DE HANO?", "antwoord": "Ja, de tafel is te laag.", "pages": [439, 440], "image": "images/img_220.png"}, {"id": 221, "set": 19, "opdracht_in_set": 5, "title": "Probleem", "situatie": "U gaat op bezoek bij een vriend.\nU hebt om 10.00 uur afgesproken.\nEris een probleem.\nKijk naar het plaatje.\nLeg het probleem uit.\nU hoort eerst uw vriend.", "vraag": "METTIM...", "antwoord": "Hoi, mijn auto heeft een lekke band, ik kom later.", "pages": [441, 442], "image": "images/img_221.png"}, {"id": 222, "set": 19, "opdracht_in_set": 6, "title": "Probleem telefoonwinkel", "situatie": "U bent de eigenaar van een telefoonwinkel.\nU wilt vandaag de winkel openen, maar er is een probleem.\nU belt met de politie.\nKijk naar het plaatje.\nVertel de politie wat het probleem is.\nU hoort eerst de agent.", "vraag": "WAT IS ER GEBEURD?", "antwoord": "Het raam van de winkel is vernield.", "pages": [443, 444], "image": "images/img_222.png"}, {"id": 223, "set": 19, "opdracht_in_set": 7, "title": "Probleem woonwinkel", "situatie": "U werkt in een woonwinkel.\nIn een woonwinkel kunnen klanten spullen kopen voor hun huis.\nEris iets vervelends gebeurd.\nKijk naar het plaatje.\nVertel uw baas wat er gebeurd is.\nGebruik daarbij het plaatje.\n\nU hoort eerst uw baas.", "vraag": "WAT IS ER GEBEURD?", "antwoord": "Een klant heeft een kat van glas op de grond laten vatlen.", "pages": [445, 446], "image": "images/img_223.png"}, {"id": 224, "set": 19, "opdracht_in_set": 8, "title": "Problemen met collega", "situatie": "U werkt op een kantoor.\nU hebt problemen met een collega.\nZe belt vaak met vrienden tijdens werktijd.\nU hebt al met haar gepraat, maar er is niets veranderd.\nUw vriend stelt voor dat u over haar gaat praten met uw baas.\nVertel uw vriend wat u van dit idee vindt.\nGeef hiervoor twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw vriend en reageer.", "vraag": "MISSCHIEN MOET JE EENS OVER HAAR GAAN PRATEN MET JE BAAS.", "antwoord": "Ik wil niet klagen over een collega. En mijn baas is heel blij met\nhaar...", "pages": [447, 448], "image": null}, {"id": 225, "set": 19, "opdracht_in_set": 9, "title": "Product in fles", "situatie": "U bent verkoper in een winkel voor huishoudelijke artikelen.\nEen klant kijkt naar een product in een fles.\nZe vraagt waar het product voor gebruikt wordt.\nKijk naar het plaatje.\nVertel de klant wat je met het product kunt doen.", "vraag": "", "antwoord": "U kunt met dit product ramen schoonmaken.", "pages": [449, 450], "image": "images/img_225.png"}, {"id": 226, "set": 19, "opdracht_in_set": 10, "title": "Radio bij studeren", "situatie": "U studeert samen met een medestudent voor een examen.\nZij wil graag de radio aanzetten.\nVertel uw medestudent wat u van het idee vindt.\nVertel ook waarom u dat vindt.\nU hoort eerst uw medestudent.", "vraag": "IK ZET EVEN DE RADIO AAN ... GOED?", "antwoord": "Nee, doe maar niet. Ik kan me niet concentreren met de radio\naan.", "pages": [451, 452], "image": null}, {"id": 227, "set": 19, "opdracht_in_set": 11, "title": "Receptionist", "situatie": "U volgt een opleiding voor receptionist in een hotel.\nIn de opleiding moeten de studenten kiezen voor een stage in\neen groot hotel waar vooral\nzakenmensen komen of een stage in een klein vakantiehotel\nwaar vooral toeristen komen.\nEen medestudent vraagt wat u zou kiezen.\nVertel hem wat u zou kiezen.\nVertel ook waarom u dat zou kiezen.\nU hoort eerst uw medestudent.", "vraag": "WAAR ZOU JIJ VOOR KIEZEN? EEN STAGE IN EEN GROOT HOTEL VOOR ZAKENMENSEN OF IN EEN KLEIN HOTEL VOOR TOERISTEN?", "antwoord": "Ik kies voor een klein hotel met toeristen. Ik vind dat gezelliger.", "pages": [453, 454], "image": null}, {"id": 228, "set": 19, "opdracht_in_set": 12, "title": "Regel in fabriek", "situatie": "U werkt in een fabriek.\nEr hangt een bord met een regel.\nKijk naar het plaatje.\nLuister naar uw collega en geef antwoord.", "vraag": "WAT BETEKENT DIT BORD PRECIES?", "antwoord": "Dat betekent: je moet goede schoenen aandoen.", "pages": [455, 456], "image": "images/img_228.png"}, {"id": 229, "set": 20, "opdracht_in_set": 1, "title": "Regels voor kleding", "situatie": "In sommige bedrijven gelden regels voor kleding.\nHet bedrijf bepaalt dan welke kleding je wel of niet mag dragen.\nVertel wat u hiervan vindt.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind dat prima. Je ziet dan snel wie welk werk doet. In het\nziekenhuis of in een fabriek, bijvoorbeeld.", "pages": [457, 458], "image": null}, {"id": 230, "set": 20, "opdracht_in_set": 2, "title": "Reisbureau", "situatie": "U wilt een vakantie boeken.\nU gaat naar een reisbureau.\nU praat met de medewerkster van het reisbureau.\nVertel wat u wilt doen als u op vakantie bent.\nNoem drie dingen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar de medewerkster en reageer.", "vraag": "WAT WILT U DOEN OP VAKANTIE?", "antwoord": "Ik wil zwemmen, ik wil wandelen en ik wil ook een museum\nbezoeken.", "pages": [459, 460], "image": null}, {"id": 231, "set": 20, "opdracht_in_set": 3, "title": "Reizen voor baan", "situatie": "U zoekt werk.\nHet uitzendbureau heeft voor u een baan gevonden.\nVoor deze baan moet u iedere dag twee uur reizen.\nVertel wat u hiervan vindt.\nVertel ook waarom u dat vindt.\nU hoort eerst de medewerker van het uitzendbureau.", "vraag": "IK HEB HIER EEN GESCHIKTE BAAN VOOR U, MAAR DAARVOOR MOET U IEDERE DAG TWEE UUR REIZEN. WAT VINDT U DAARVAN?", "antwoord": "Ik vind dat niet goed. Twee uur relstijd is te veel.", "pages": [461, 462], "image": null}, {"id": 232, "set": 20, "opdracht_in_set": 4, "title": "Rekenopdracht", "situatie": "U volgt een opleiding tot onderwijsassistent.\nU geeft vandaag een rekenopdracht aan een kind.\nKijk naar het plaatje.\nVertel het kind wat hij moet doen.\nU hoort eerst het kind.", "vraag": "WAT MOET IK DOEN?", "antwoord": "Kijk goed: je moet een lijn tekenen tussen 2 koelen en het\ncijfer 2.\nJe moet een lijn tekenen tussen 3 katten en het cijfer 3.\nEn je moet een lijn tekenen tussen 4 schapen en het cijfer 4.", "pages": [463, 464], "image": "images/img_232.png"}, {"id": 233, "set": 20, "opdracht_in_set": 5, "title": "Reparatiebedrijf", "situatie": "U werkt bij een reparatiebedrijf.\nAls een klant een kapot apparaat heeft, kan hij het bij uw bedrijf\nlaten maken.\nHet bedrijf maakt verschillende soorten apparaten.\nUw baas is van plan om vanaf nu alleen nog televisies te maken.\nEen collega vraagt wat u daarvan vindt.\nVertel uw collega wat u vindt van het plan van de baas.\nVertel ook waarom u dat vindt.\nGeef twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw collega en reageer.", "vraag": "WAT VIND JIJ VAN HET PLAN OM ALLEEN NOG MAAR TELEVISIES TE MAKEN, EN WAAROM?", "antwoord": "Ik vind het jammer. Mensen brengen veel apparaten, niet\nalleen televisies. Wij kunnen dus veel meer mensen helpen.\nEn alleen televisies repareren, dat is ook saai.", "pages": [465, 466], "image": null}, {"id": 234, "set": 20, "opdracht_in_set": 6, "title": "Rijles", "situatie": "U bent rij-instructeur.\nU leert leerlingen autorijden.\nU geeft een leerling een opdracht.\nKijk naar het plaatje.", "vraag": "", "antwoord": "Je moet achteruit rijden en parkeren.", "pages": [467, 468], "image": "images/img_234.png"}, {"id": 235, "set": 20, "opdracht_in_set": 7, "title": "Roken |", "situatie": "In Nederland mag je in een restaurant niet roken.\nEen restauranteigenaar kan een boete krijgen als mensen in\nzijn restaurant roken.\nWat vindt u ervan dat erin restaurants in Nederland niet gerookt\nmag worden?\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind dat prima. Roken in een restaurant is heel vies.", "pages": [469, 470], "image": null}, {"id": 236, "set": 20, "opdracht_in_set": 8, "title": "Saaie Engelse les", "situatie": "U volgt de opleiding Toerisme.\nU krijgt Engelse les van meneer Van Dijk.\nAlle studenten vinden de Engelse les erg saai.\nMeneer Van Dijk praat hierover met de studenten.\nHij vraagt hoe hij de les leuker kan maken.\nVertel meneer Van Dijk hoe hij zijn Engelse les leuker kan maken.\nNoem daarbij drie dingen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar meneer Van Dijk en reageer.", "vraag": "HOE KAN IK DE ENGELSE LES LEUKER MAKEN?", "antwoord": "U kunt leerlingen samen oefeningen laten maken. U kunt En-\ngelse films laten zien. U kunt Engelse muziek laten horen.", "pages": [471, 472], "image": null}, {"id": 237, "set": 20, "opdracht_in_set": 9, "title": "Samen sporten", "situatie": "Een vriendin wil met u gaan sporten op zaterdag.\nU kunt kiezen tussen oefeningen op muziek in de ochtend en\nfietsen in de middag.\nVertel wat u kiest.\nVertel ook waarom u dat kiest.\nU hoort eerst uw vriendin.", "vraag": "WAT WIL JE HET LIEFST, OEFENINGEN DOEN OP MUZIEK OF FIETSEN?", "antwoord": "Ik kies voor fietsen in de middag. Ik wil een actieve dag.", "pages": [473, 474], "image": null}, {"id": 238, "set": 20, "opdracht_in_set": 10, "title": "Schilder", "situatie": "U volgt een opleiding tot schilder.\nU moet een stageplaats kiezen.\nU kunt kiezen om te schilderen op een grote bouwplaats of bij\neen klein klusbedrijf.\nKijk naar de plaatjes.\nVertel welk bedrijf u kiest.\nVertel ook waarom u dit kiest.", "vraag": "", "antwoord": "Ik kies voor een klein klusbedrijf. Ik werk graag alleen.", "pages": [475, 476], "image": "images/img_238.png"}, {"id": 239, "set": 20, "opdracht_in_set": 11, "title": "Schilder een hond", "situatie": "U volgt een schildercursus.\nDe opdracht voor volgende week is: schilder een hond.\nU hebt geen hond, maar uw medecursist heeft drie honden.\nWat vraagt u aan uw medecursist?\nU hoort eerst uw medecursist.", "vraag": "WAT WILDE JE AAN ME VRAGEN?", "antwoord": "Ja. Ik heb geen hond ... kan ik 1 hond van jou\nschilderen?", "pages": [477, 478], "image": null}, {"id": 240, "set": 20, "opdracht_in_set": 12, "title": "Schildercursus", "situatie": "U volgt een cursus Schilderen.\nU hebt materiaal besteld via internet.\nKijk naar het plaatje.", "vraag": "GOEDEMORGEN, WAARMEE KAN IK U HELPEN?", "antwoord": "Ik heb materiaal besteld, maar ik moet nu al een week\nwachten.", "pages": [479, 480], "image": "images/img_240.png"}, {"id": 241, "set": 21, "opdracht_in_set": 1, "title": "School gezelliger", "situatie": "U volgt een mbo-opleiding.\nHet bestuur van de school wil dat de school er gezelliger uitziet.\nHet bestuur vraagt daarom aan alle studenten of zij adviezen\nhebben.\nU heeft wel een paar goede adviezen.\nKijk naar de plaatjes.\nVertel het bestuur welke adviezen u heeft.\nGebruik hierbij alle plaatjes.\nU hoort eerst een bestuurslid.", "vraag": "WELKE ADVIEZEN HEB JIJ VOOR ONS?", "antwoord": "We kunnen de muren een nieuwe kleur geven. We kunnen\nnieuwe stoelen kopen. En we kunnen bloemen en planten\nbij de ingang zetten.", "pages": [481, 482], "image": "images/img_241.png"}, {"id": 242, "set": 21, "opdracht_in_set": 2, "title": "Schooldag", "situatie": "Sommige mensen vinden dat een schooldag net zo lang moet\nduren als een werkdag.\nKinderen moeten dan naar school van 8.30 tot 17.00 uur.\nWat vindt u ervan als kinderen zo lang op school moeten zitten?\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind dat niet goed. Kinderen moeten ook buiten spelen.", "pages": [483, 484], "image": null}, {"id": 243, "set": 21, "opdracht_in_set": 3, "title": "Schoolkantine", "situatie": "U heeft in de schoolkantine gegeten samen met een nieuwe\nstudent.\nDe nieuwe student weet nog niet wat hij moet doen na het eten.\nKijk naar het plaatje.\nVertel de student wat hij moet doen,\nU hoort eerst de student.", "vraag": "EN ... WAT MOET IK NU DOEN?", "antwoord": "Je moet je bord leegmaken bij de afvalbak.", "pages": [485, 486], "image": "images/img_243.png"}, {"id": 244, "set": 21, "opdracht_in_set": 4, "title": "Schoolkeuze", "situatie": "U moet een nieuwe school kiezen voor uw kind.\nU praat hierover met uw buurvrouw.\nU vertelt haar welke school u kiest voor uw kind en waarom.\nKijk naar de plaatjes.\nVertel uw buurvrouw welke school u kiest.\nVertel ook waarom.\nGeef ten minste twee redenen.", "vraag": "", "antwoord": "Ik kies voor de Mondriaanschool. De kinderen kunnen daar\ngoed buiten spelen. En de school is niet zo supergroot.", "pages": [487, 488], "image": "images/img_244.png"}, {"id": 245, "set": 21, "opdracht_in_set": 5, "title": "Schoonmaakwerk", "situatie": "U zoekt werk als schoonmaker.\nU hebt een gesprek bij een schoonmaakbedrijf.\nDe medewerker geeft u de keuze uit twee banen.\nU kunt schoonmaken in een ziekenhuis of op een school.\nVertel de medewerker waar u liever werkt.\nVertel ook waarom.\nGeef hiervoor twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar de medewerker en reageer.", "vraag": "WAAR ZOU JE LIEVER WERKEN ... IN EEN ZIEKENHUIS OF OP EEN SCHOOL?", "antwoord": "Ik maak liever schoon op een school. Dat is minder groot dan\neen ziekenhuis en ik heb daar meer contact met mensen.", "pages": [489, 490], "image": null}, {"id": 246, "set": 21, "opdracht_in_set": 6, "title": "Schoonmaker", "situatie": "U bent schoonmaker.\nU moet bij een klant de ramen wassen.\nEris een probleem.\nKijk naar het plaatje.\nLeg uit wat de klant moet doen.\nU hoort eerst de klant.", "vraag": "WAT KAN IK VOOR U DOEN?", "antwoord": "U kunt de planten wegzetten.", "pages": [491, 492], "image": "images/img_246.png"}, {"id": 247, "set": 21, "opdracht_in_set": 7, "title": "Schuur", "situatie": "U hebt een schuur in uw tuin gebouwd.\nUw buurvrouw vraagt waar u de schuur voor gaat gebruiken.\nKijk naar het plaatje.\nVertel uw buurvrouw waar u de schuur voor gaat gebruiken.\nU hoort eerst uw buurvrouw.", "vraag": "WAT HANDIG ZEG, ZO’N SCHUUR ... WAAR GA JE HEM VOOR GEBRUIKEN?", "antwoord": "Ik ga mijn fietsen in de schuur zetten.", "pages": [493, 494], "image": "images/img_247.png"}, {"id": 248, "set": 21, "opdracht_in_set": 8, "title": "Sleutels kwijt", "situatie": "U bent op uw werk.\nU wilt naar huis gaan maar u kunt uw sleutels niet vinden.\nUw collega wil helpen zoeken.\nKijk naar het plaatje.\nVertel uw collega hoe uw sleutels eruit zien.\nU hoort eerst uw collega.", "vraag": "HOE ZIEN DIE SLEUTELS ERUIT, DAN?", "antwoord": "Er zitten 5 sleutels aan de sleutelhanger. De sleutelhanger is\neen groen schoentje.", "pages": [495, 496], "image": "images/img_248.png"}, {"id": 249, "set": 21, "opdracht_in_set": 9, "title": "Sollicitatie", "situatie": "Uw vriendin heeft morgen een sollicitatiegesprek.\nZe gaat solliciteren bij een bank.\nUw vriendin weet niet wat voor kleding ze moet aantrekken.\nKijk naar de plaatjes.\nVertel uw vriendin welke kleding zij het best kan aantrekken.\nVertel ook waarom u dat vindt.\nGeef ten minste twee redenen.\nU hoort eerst uw vriendin.", "vraag": "WAT MOET IK MORGEN AANTREKKEN?", "antwoord": "Je moet nette kleren aantrekken. Bij een bank werken alle\nmensen in nette kleding. En je voelt je ook goed in nette\nkleding.", "pages": [497, 498], "image": "images/img_249.png"}, {"id": 250, "set": 21, "opdracht_in_set": 10, "title": "Sollicitatie kledingwinkel", "situatie": "U zoekt een baan.\nU gaat solliciteren bij een kledingwinkel.\nU spreekt met de baas van de winkel.\nZij wil graag weten wat u leuk lijkt aan het werken in een\nkledingwinkel.\nU hoort eerst de baas.", "vraag": "WAT LIJKT JOU LEUK AAN HET WERKEN IN EEN KLEDINGWINKEL?", "antwoord": "Ik geef klanten graag advies over nieuwe kleding en nleuwe\nmode.", "pages": [499, 500], "image": null}, {"id": 251, "set": 21, "opdracht_in_set": 11, "title": "Sollicitatie tuincentrum", "situatie": "U zoekt een baan.\nU solliciteert als verkoper bij een tuincentrum.\nU spreekt met de baas van het tuincentrum.\nDe baas wil graag weten wat u leuk vindt aan het werken in een\ntuincentrum.\nU hoort eerst de baas.", "vraag": "EN, WAT VIND JE NOU LEUK AAN HET WERKEN IN EEN TUINCENTRUM?", "antwoord": "Ik geef klanten graag advies over bloemen en planten.", "pages": [501, 502], "image": null}, {"id": 252, "set": 21, "opdracht_in_set": 12, "title": "Solliciteren", "situatie": "U hebt een sollicitatiegesprek voor vrachtwagenchauffeur.\nDe chef vraagt naar uw ervaring als chauffeur.\nKijk naar de plaatjes.\nLuister naar de chef en geef antwoord.", "vraag": "KUNT U MIJ VERTELLEN WELKE WERKERVARING U PRECIES HEEFT?", "antwoord": "Ja, ik heb ervaring als taxichauffeur. Ik heb ervaring als\nvrachtwagenchauffeur. En ik ben ook buschauffeur geweest.", "pages": [503, 504], "image": "images/img_252.png"}, {"id": 253, "set": 22, "opdracht_in_set": 1, "title": "Speelgoedmarkt", "situatie": "Binnenkort is er een speelgoedmarkt bij u in de buurt.\nOp een speelgoedmarkt kunnen kinderen hun oude speelgoed\nverkopen.\nU helpt mee met de organisatie.\nUw buurvrouw vraagt wat u gaat doen.\nKijk naar de plaatjes.\nVertel uw buurvrouw wat u op de speelgoedmarkt gaat doen.\nU moet hierbij alle plaatjes gebruiken.\nU hoort eerst uw buurvrouw.", "vraag": "WAT GOED DAT JE GAAT HELPEN. WAT MOET JE DIE DAG ALLEMAAL DOEN?", "antwoord": "Ik ga limonade geven aan de kinderen. Ik ga foto's maken.\nEn ik ga aan het eind van de dag de rotzool opruimen.", "pages": [505, 506], "image": "images/img_253.png"}, {"id": 254, "set": 22, "opdracht_in_set": 2, "title": "Spelende kinderen in restaurant", "situatie": "U werkt in een restaurant.\nIn het restaurant is een gezin aan het eten.\nZe hebben drie kleine kinderen bij zich.\nDe kinderen rennen steeds de keuken in.\nU vindt dat niet goed.\nU gaat naar de vader van de kinderen.\nVertel de vader wat u wilt dat hij doet.\nLeg ook uit waarom u dit wilt.\nGeef hiervoor twee redenen,\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar de vader en geef antwoord.", "vraag": "WAT WILT U DAT IK DOE?", "antwoord": "De kinderen moeten bij u blijven. Het is erg onrustig voor\nandere gasten. In de keuken is het niet veilig voor kleine\nkinderen.", "pages": [507, 508], "image": null}, {"id": 255, "set": 22, "opdracht_in_set": 3, "title": "Spelletje op telefoon", "situatie": "U werkt als bewaker bij een bank.\nU werkt samen met een collega.\nU ziet dat de collega een spelletje op zijn telefoon speelt tijdens\nwerktijd.\nU bent het daar niet mee eens en wilt hem daarop aanspreken.\nVraag uw collega zijn gedrag te veranderen.\nLeg ook uit waarom u dat wilt.\nGeef twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw collega en reageer.", "vraag": "WAT IS ER?", "antwoord": "Je moet niet met je telefoon spelen. Je moet je concentreren\nop je werk. Je moet je telefoon gebruiken als er alarm is.", "pages": [509, 510], "image": null}, {"id": 256, "set": 22, "opdracht_in_set": 4, "title": "Sportdag op school", "situatie": "Op de school van uw kind is vandaag een sportdag.\nU helpt mee met de organisatie.\nEen moeder vraagt of zij kan helpen.\nU vertelt haar dat ze kan kiezen waarbij ze wil helpen.\nKijk naar de plaatjes.\nVertel de moeder waartussen ze kan kiezen.\nGebruik de plaatjes.\nU hoort eerst de moeder.", "vraag": "KAN IK JE MISSCHIEN ERGENS MEE HELPEN?", "antwoord": "Ja, Je kunt T-shirts uitdelen aan de kinderen. En je kunt\nlmonade schenken voor de kinderen.", "pages": [511, 512], "image": "images/img_256.png"}, {"id": 257, "set": 22, "opdracht_in_set": 5, "title": "Sportdag organiseren", "situatie": "U volgt de mbo-opleiding Sport en bewegen.\nVorganiseert samen met andere studenten een sportdag voor\neen basisschool.\nJullie moeten nog een paar dingen regelen.\nKijk naar de plaatjes.\nLeg uw medestudenten uit welke dingen jullie nog moeten\nregelen.\n= amma .", "vraag": "WAT MOETEN WE NOG REGELEN VOOR DE SPORTDAG?", "antwoord": "Es moeten 50 T-shirts zijn. Er moeten ballen komen.\nEn er moet limonade zijn en fruit.", "pages": [513, 514], "image": "images/img_257.png"}, {"id": 258, "set": 22, "opdracht_in_set": 6, "title": "Sportdocent", "situatie": "U volgt de opleiding voor sportdocent.\nEen medestudent moet een stage kiezen, maar hij heeft geen\nideeén.\nU wilt hem helpen.\nKijk naar het plaatje.\nVertel waar uw medestudent stage zou kunnen lopen.\nVertel ook waarom u dat een goede stageplek vindt.\nGeef daarvoor twee redenen.", "vraag": "WEET JIJ WAAR IK STAGE ZOU KUNNEN GAAN LOPEN?", "antwoord": "Je kunt stagelopen bij een zwembad. JIj houdt zelf ook van\nZTwemmen. En je kunt kinderen leren zwemmen.", "pages": [515, 516], "image": "images/img_258.png"}, {"id": 259, "set": 22, "opdracht_in_set": 7, "title": "Spullen laten liggen", "situatie": "U werkt op een kantoor.\nU hebt uw agenda en pen laten liggen in een vergaderruimte.\nKijk naar het plaatje.\nGeef uw collega een beschrijving van uw agenda en pen.\nLuister naar uw collega en reageer.", "vraag": "DUS JE BENT JE AGENDA EN PEN KWIJT. HOE ZIEN ZE ERUIT?", "antwoord": "De agenda heeft veel kleuren en de pen is zwart met groene\nbloemen.", "pages": [517, 518], "image": "images/img_259.png"}, {"id": 260, "set": 22, "opdracht_in_set": 8, "title": "Stadsbus- of touringcarchauffeur", "situatie": "U bent chauffeur op een stadsbus.\nU vervoert mensen met de bus in de stad.\nUw collega heeft een aanbod voor nieuw werk gekregen.\nHij kan gaan werken als buschauffeur voor een reisorganisatie.\nHij moet dan mensen naar hun vakantiebestemming in het\nbuitenland rijden.\nUw collega twijfelt wat hij moet doen: op de stadsbus blijven\nrijden of mensen naar het buitenland rijden.\nHij vraagt wat u zou doen,\nVertel uw collega wat u zou doen.\nVertel ook waarom u dat zou doen.\nGeef twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw collega en reageer.", "vraag": "WAT ZOU JIJ DOEN ... OP DE STADSBUS BLIJVEN RIJDEN OF NAAR VAKANTIEBESTEMMINGEN IN HET BUITENLAND RIJDEN? EN WAAROM?", "antwoord": "Ik zou die nieuwe baan nemen. Je kunt dan veel landen\nbezoeken. En je hebt altijd veel blije passaglers.", "pages": [519, 520], "image": null}, {"id": 261, "set": 22, "opdracht_in_set": 9, "title": "Stage dierverzorger", "situatie": "U volgt de opleiding tot Dierverzorger.\nU loopt samen met een medestudent stage op een\nkinderboerderij.\nHij weet niet goed wat jullie vandaag moeten doen.\nKijk naar de plaatjes.\nVertel uw medestudent wat hij moet doen.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw medestudent.", "vraag": "WAT MOET IK DOEN VANDAAG?", "antwoord": "Je moet de getten naar de wei sturen. Je moet de stal\nschoonmaken. En je moet de gelten eten geven.", "pages": [521, 522], "image": "images/img_261.png"}, {"id": 262, "set": 22, "opdracht_in_set": 10, "title": "Stage in Spanje", "situatie": "Uw buurmeisje is 20 jaar.\nZe studeert voor vertaler.\nVoor haar studie kan ze drie maanden stage lopen in Spanje.\nZe vraagt uw advies.\nGeef ten minste twee redenen waarom ze wel of niet naar\nSpanje moet gaan.\nU krijgt eerst de tijd om het antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik zou die stage in Spanje doen. Je gaat 3 maanden in een\nander land wonen. En je gaat heel veel Spaans oefenen.", "pages": [523, 524], "image": null}, {"id": 263, "set": 22, "opdracht_in_set": 11, "title": "Stage in buitenland?", "situatie": "Een vriend van u volgt een koksopleiding.\nHij kan drie maanden stage lopen in een restaurant in Italié.\nHij vraagt u of hij dat moet doen.\nVertel uw vriend wat hij volgens u moet doen en waarom.\nGeef twee redenen waarom hij wel of niet naar Italié moet gaan.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw vriend en reageer.", "vraag": "VIND JIJ DAT IK STAGE MOET GAAN LOPEN IN ITALIE?", "antwoord": "Ik zou die stage in Itallé doen. Je gaat 3 maanden in een ander\nland wonen. En je gaat heel veel pizza's bakken.", "pages": [525, 526], "image": null}, {"id": 264, "set": 22, "opdracht_in_set": 12, "title": "Stage in de keuken", "situatie": "U loopt stage in de keuken van een ziekenhuis.\nUw baas geeft u alleen heel makkelijk werk, zoals afwassen en\nschoonmaken.\nU wilt ook ander werk doen.\nKijk naar het plaatje.\nVertel uw baas wat u liever wilt doen in de keuken.\nLuister naar uw baas en reageer.", "vraag": "WILDE JE IETS ZEGGEN?", "antwoord": "Ja, ik wil niet alleen afwassen en schoonmaken. Ik wil ook eten\nkoken.", "pages": [527, 528], "image": "images/img_264.png"}, {"id": 265, "set": 23, "opdracht_in_set": 1, "title": "Stage in supermarkt", "situatie": "U werkt in een supermarkt.\nVandaag komt er een stagiaire.\nOp het plaatje ziet u wat de stagiaire moet doen.\nKijk naar het plaatje.\nVertel de stagiaire wat zij moet doen.\nU hoort eerst de stagiaire.", "vraag": "WAT MOET IK NU GAAN DOEN?", "antwoord": "Je moet nu vakken vullen.", "pages": [529, 530], "image": "images/img_265.png"}, {"id": 266, "set": 23, "opdracht_in_set": 2, "title": "Stage kappersopleiding", "situatie": "U volgt een opleiding tot kapper.\nU loopt stage.\nEen collega vraagt of u hulp nodig hebt.\nKijk naar het plaatje.\nVertel uw collega wat zij kan doen.\nU hoort eerst uw collega.", "vraag": "ZO, IK BEN KLAAR. KAN IK JOU NOG ERGENS MEE HELPEN?", "antwoord": "Ja, graag. Wil je mijn schort dichtdoen?", "pages": [531, 532], "image": "images/img_266.png"}, {"id": 267, "set": 23, "opdracht_in_set": 3, "title": "Stage winkel", "situatie": "U volgt de opleiding tot verkoper.\nU loopt stage in een winkel.\nEen medestudent werkt vandaag voor het eerst in de winkel.\nHij vraagt aan u wat hij moet doen.\nKijk naar de plaatjes.\nLuister naar uw medestudent en reageer.\nGebruik de plaatjes.\nU hoort eerst uw medestudent.", "vraag": "WAT MOET IK DOEN?", "antwoord": "Je moet vakken vullen. En je moet bij de kassa werken.", "pages": [533, 534], "image": "images/img_267.png"}, {"id": 268, "set": 23, "opdracht_in_set": 4, "title": "Stageplaats", "situatie": "U volgt een opleiding voor ziekenverzorger.\nVoor uw opleiding moet u drie maanden stage lopen.\nU moet zelf een stageplaats zoeken.\nDaarom belt u een verpleeghuis.\nLuister naar de medewerkster en reageer.", "vraag": "U HEBT EEN VERZOEK? NOU, ZEG HET MAAR...", "antwoord": "Kan ik bij u drie maanden stage lopen?", "pages": [535, 536], "image": null}, {"id": 269, "set": 23, "opdracht_in_set": 5, "title": "Stageplek kiezen", "situatie": "U volgt de opleiding Helpende Zorg en Welzijn.\nVoor uw stage kunt u kiezen uit twee stageplekken.\nU kunt gaan werken met ouderen of met lichamelijk\ngehandicapten.\nUw mentor vraagt welke stageplek u het leukst vindt.\nVertel uw mentor welke stageplek u het leukst vindt.\nVertel uw mentor ook waarom u die stageplek het leukst vindt.\nU hoort eerst uw mentor.", "vraag": "EN WELKE STAGEPLEK LIJKT JOU HET LEUKST?", "antwoord": "Ik heb het liefst een stageptek bij gehandicapten. Er zijn veel\ndemente ouderen en dat vind ik moeilijk werk.", "pages": [537, 538], "image": null}, {"id": 270, "set": 23, "opdracht_in_set": 6, "title": "Stagiair in supermarkt", "situatie": "U werkt in een supermarkt.\nEr werkt een stagiair bij u.\nU vertelt de stagiair wat hij moet doen.\nKijk naar het plaatje.", "vraag": "", "antwoord": "Je moet de vioer vegen.", "pages": [539, 540], "image": "images/img_270.png"}, {"id": 271, "set": 23, "opdracht_in_set": 7, "title": "Steeds meer wegen", "situatie": "In Nederland worden steeds meer wegen gebouwd.\nEris steeds minder groen.\nVertel wat u van deze ontwikkeling vindt.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind het jammer. Ik houd van de natuur.", "pages": [541, 542], "image": null}, {"id": 272, "set": 23, "opdracht_in_set": 8, "title": "Stemmen", "situatie": "U moet binnenkort stemmen voor de landelijke verkiezingen.\nUw buurmeisje heeft dit nog nooit gedaan.\nZij vraagt aan u hoe dit werkt.\nKijk naar de plaatjes.\nLuister naar uw buurmeisje en reageer.\nGebruik hierbij alle plaatjes.", "vraag": "IK HEB NOG NOOIT GESTEMD. HOE WERKT DAT?", "antwoord": "Oké. Je krijgt een stembiljet. Je moet met een rood potlood op\neen persoon stemmen. En je moet het stembiljet in de stembus\ngoolen.", "pages": [543, 544], "image": "images/img_272.png"}, {"id": 273, "set": 23, "opdracht_in_set": 9, "title": "Stoppen met de opleiding?", "situatie": "U volgt een opleiding voor verpleeghulp.\nUw medecursiste heeft veel problemen met haar stage.\nDaarom wil ze met haar opleiding stoppen.\nU vindt dat geen goed idee.\nLuister naar uw medecursiste en reageer.", "vraag": "HET GAAT HELEMAAL NIET GOED MET MIJN STAGE. IK OENK DAT IK BETER MET OE OPLEIDING KAN STOPPEN.", "antwoord": "Nee joh, dat moet je niet doen. Het komt goed!", "pages": [545, 546], "image": null}, {"id": 274, "set": 23, "opdracht_in_set": 10, "title": "Storm", "situatie": "Eris een flinke storm geweest.\nU belt de verzekering omdat er veel kapot is gegaan aan uw\nhuis.\nKijk naar de plaatjes.\nVertel de medewerker van de verzekering wat er kapot is.\nGebruik hierbij alle plaatjes.\nU hoort eerst de medewerker.", "vraag": "U HEEFT DUS OOK LAST GEHAD VAN DE STORM. WAT VERVELEND. WAT IS ER KAPOT?", "antwoord": "Een boom is tegen het huis gewaaild. Er zit een gat in het raam.\nEr zit een gat in het dak. En de schutting is ook kapot door de\nstorm,", "pages": [547, 548], "image": "images/img_274.png"}, {"id": 275, "set": 23, "opdracht_in_set": 11, "title": "Strand", "situatie": "Het was heel mooi weer afgelopen weekend.\nU bent naar het strand geweest.\nU komt uw buurvrouw tegen.\nZe vraagt wat u hebt gedaan.\nKijk naar het plaatje.\nVertel wat u hebt gedaan op het strand.\nU hoort eerst uw buurvrouw.", "vraag": "WAT HEB JE OP HET STRAND GEDAAN?", "antwoord": "Ik heb gezwommen in de zee.", "pages": [549, 550], "image": "images/img_275.png"}, {"id": 276, "set": 23, "opdracht_in_set": 12, "title": "Stratenmaker", "situatie": "U werkt als stratenmaker.\nU moet een opdracht opnieuw doen.\nUw baas belt u op en vraagt waarom u de opdracht opnieuw\nmoet doen.\nKijk naar het plaatje.\nVertel uw baas wat er is gebeurd.\nGebruik daarbij het plaatije.\nU hoort eerst uw baas.", "vraag": "WAAROM MOET JE DE OPDRACHT OPNIEUW DOEN?", "antwoord": "Iemand is over het natte cement gelopen.", "pages": [551, 552], "image": "images/img_276.png"}, {"id": 277, "set": 24, "opdracht_in_set": 1, "title": "Student landbouwschool", "situatie": "U bent student op een landbouwschool.\n's Avonds belt een vriend u op.\nHij vraagt wat u vandaag allemaal hebt gedaan op school.\nKijk naar de plaatjes.\nVertel uw vriend wat u vandaag hebt gedaan.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw vriend.", "vraag": "HOI, MET MIKE. WAT HEB JE VANDAAG ALLEMAAL GEDAAN OP SCHOOL?", "antwoord": "We hebben theorieles gehad. We hebben plantjes geplant.\nEn we hebben de plantjes water gegeven.", "pages": [553, 554], "image": "images/img_277.png"}, {"id": 278, "set": 24, "opdracht_in_set": 2, "title": "Studeren in de schoolbibliotheek", "situatie": "U volgt een opleiding.\nU hebt binnenkort een toets.\nU gaat hiervoor samen met uw medestudent studeren.\nUw medestudent wil gaan studeren in de schoolbibliotheek.\nU vindt dit geen goed idee.\nKijk naar de plaatjes.\nOvertuig uw medestudent ervan dat het geen goed idee is om\nIn de schoolbibliotheek te gaan studeren.\nU moet hierbij alle plaatjes gebruiken.\nU hoort eerst uw medestudent.", "vraag": "ZULLEN WE IN DE SCHOOLBIBLIOTHEEK GAAN ZITTEN?", "antwoord": "Nee, dat vind ik geen goed idee. Iedereen zit daar te kletsen.\nHet is er heel druk. En je hebt daar last van de zon.", "pages": [555, 556], "image": "images/img_278.png"}, {"id": 279, "set": 24, "opdracht_in_set": 3, "title": "Studieadviseur", "situatie": "U wilt een opleiding gaan volgen.\nU hebt een gesprek met een studieadviseur.\nDe studieadviseur helpt u bij het zoeken naar een opleiding.\nZe heeft wel een idee voor u.\nKijk naar het plaatje.\nVertel de studieadviseur of de opleiding bij u past.\nVertel ook waarom wel of niet.", "vraag": "PAST DEZE OPLEIDING BIJ JOU, DENK JE?", "antwoord": "Ja, het lijkt me leuk. Ik vind moot haar belangrijk.", "pages": [557, 558], "image": "images/img_279.png"}, {"id": 280, "set": 24, "opdracht_in_set": 4, "title": "Studievrienden maken", "situatie": "U volgt een mbo-opleiding.\nU praat met een nieuwe medestudent.\nHij kent nog niet veel mensen bij de opleiding.\nHij vraagt wat hij kan doen om vrienden te maken bij de\nopleiding.\nVertel de medestudent wat hij het beste kan doen om vrienden\nte maken.\nVertel ook waarom u dat adviseert.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medestudent en reageer.\nU hoort eerst uw studieadviseur.", "vraag": "WAT KAN IK HET BESTE DOEN OM VRIENDEN TE MAKEN, HIER?", "antwoord": "Je moet op vrijdagmiddag naar school komen. Dan gaan veel\nstudenten samen naar het café.", "pages": [559, 560], "image": null}, {"id": 281, "set": 24, "opdracht_in_set": 5, "title": "Taalcursus", "situatie": "U volgt een taalcursus.\nEr komt een nieuwe cursiste in uw groep.\nZij vraagt hoeveel zij moet studeren.\nU vertelt de cursiste wat zij elke week moet doen.\nKijk naar de plaatjes.\nLuister naar de cursiste en reageer.", "vraag": "WAT MOET JE DAN ALLEMAAL DOEN TIJDENS DEZE CURSUS?", "antwoord": "Je moet elke week 2 uur luisteren in een speciale cabine. Je\nmoet 2 uur per dag met je boek studeren. En je moet 2 uur per\nweek oefenen op de computer.", "pages": [561, 562], "image": "images/img_281.png"}, {"id": 282, "set": 24, "opdracht_in_set": 6, "title": "Tandartsassistent", "situatie": "U werkt als tandartsassistent.\nDe tandartsenpraktijk stuurt een mail naar patiénten om ze aan\nhun afspraak te herinneren.\nUw collega heeft voorgesteld om hiermee te stoppen.\nVertel haar wat u hiervan vindt.\nVertel ook waarom u dat vindt.\nU hoort eerst uw collega.", "vraag": "IK VIND ECHT DAT WE MOETEN STOPPEN MET DIE MAILS, WAT VIND JIJ? T ™", "antwoord": "Ik vind dat geen goed idee. Mensen vergeten hun afspraak, als\nwij stoppen met die mails.", "pages": [563, 564], "image": null}, {"id": 283, "set": 24, "opdracht_in_set": 7, "title": "Tandartsbezoek", "situatie": "Uw vriend heeft pijn aan zijn tanden.\nHij durft niet naar de tandarts te gaan.\nOvertuig uw vriend ervan dat hij wel naar de tandarts moet\ngaan.\nU hoort eerst uw vriend.", "vraag": "IK GA NIET NAAR DE TANDARTS, HOOR. DAT DURF IK NIET...", "antwoord": "Ik zou maar gaan. Als je niet gaat, wordt de pijn erger en erger.", "pages": [565, 566], "image": null}, {"id": 284, "set": 24, "opdracht_in_set": 8, "title": "Tapijtwinkel", "situatie": "U werkt in een tapijtwinkel.\nEen klant wil misschien een tapijt kopen, maar hij weet het nog\nniet zeker.\nU wilt hem overtuigen het tapijt bij u te kopen.\nKijk naar de plaatjes.\nVertel de klant waarom hij het beste bij u het tapijt kan kopen.\nLuister naar de klant en geef hem drie redenen om het tapijt bij", "vraag": "TJA, HET IS WEL EEN MOOI TAPIJT. MAAR TOCH ... IK WEET HET NIET ZEKER ...", "antwoord": "Wij brengen het tapijt gratis bij u thuls. Wij leggen het tapijt\ngratis op de vioer. En u krijgt ook 10% korting.", "pages": [567, 568], "image": "images/img_284.png"}, {"id": 285, "set": 24, "opdracht_in_set": 9, "title": "Te dik", "situatie": "In Nederland zijn kinderen steeds vaker te dik.\nDit is een probleem, want dik zijn is slecht voor de gezondheid.\nWat is volgens u de oorzaak van het probleem?\nEn hoe moet het probleem volgens u worden opgelost?\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Kinderen eten te veel slechte dingen. En ze zitten de hele dag\nop de iPad. Ze moeten groente en fruit eten. En ze moeten\nmeer buiten spelen.", "pages": [569, 570], "image": null}, {"id": 286, "set": 24, "opdracht_in_set": 10, "title": "Te laat", "situatie": "U volgt een opleiding.\nEen medestudent reist naar school met de trein.\nHij komt vaak te laat.\nHij vindt dat hij er niets aan kan doen dat hij vaak te laat is.\nU bent het niet met hem eens.\nVertel uw medestudent wat hij kan doen om op tijd te komen.\nU hoort eerst uw medestudent.", "vraag": "HET IS TOCH NIET MIJN SCHULD DAT IK TE LAAT KOM... IK KAN ER OOK NIETS AAN DOEN...", "antwoord": "Je moet een trein eerder nemen.", "pages": [571, 572], "image": null}, {"id": 287, "set": 24, "opdracht_in_set": 11, "title": "Te weinig kopieén", "situatie": "U werkt bij een computerfirma.\nVandaag bent u voorzitter van een vergadering.\nU ziet dat u te weinig kopieén hebt van enkele belangrijke\nU roept uw assistent.\nLuister naar uw assistent en vertel wat hij voor u moet doen.", "vraag": "", "antwoord": "WAT KAN iK VOOR U DOEN?\nJa, wil Je nog wat kopieén maken, alsjeblieft?", "pages": [573, 574], "image": null}, {"id": 288, "set": 24, "opdracht_in_set": 12, "title": "Teammiddag", "situatie": "U werkt op een kantoor.\nU gaat met een collega een teammiddag aan zee organiseren.\nUw collega heeft twee ideeén bedacht.\nKijk naar de plaatjes.\nVertel uw collega wat u van deze ideeén vindt.\nVertel ook waarom.\nGebruik hiervoor beide plaatjes.\nU hoort eerst uw collega.", "vraag": "WAT VIND JE VAN DEZE IDEEEN?", "antwoord": "Hartstikke goed. En ook sportief: volleyball, zwemmen en\nwandelen!", "pages": [575, 576], "image": "images/img_288.png"}, {"id": 289, "set": 25, "opdracht_in_set": 1, "title": "Telefonist", "situatie": "U volgt een opleiding voor telefonist.\nU moet een stageplaats kiezen.\nUw docent vraagt waar u het liefst zou willen werken: bij een\nklein bedrijf of bij een heel groot bedrijf.\nVertel waar u het liefst wil stage lopen.\nVertel ook waarom.\nU hoort eerst uw docent.", "vraag": "EN ... WAAR WIL JIJ HET LIEFSTE STAGE GAAN LOPEN?", "antwoord": "Ik kies voor een groot bedrijf. Dan is het werk als telefonist\nniet saai.", "pages": [577, 578], "image": null}, {"id": 290, "set": 25, "opdracht_in_set": 2, "title": "Theater", "situatie": "U werkt in een theater.\nU moet vanavond werken.\nUw collega vraagt aan u wat u het leukst vindt van dit werk.\nKijk naar de plaatjes.\nVertel uw collega wat u het leukst vindt van uw werk.\nKies een van de plaatjes.\nVertel ook waarom u dat het leukst vindt.\nU hoort eerst uw collega.", "vraag": "WAT VIND JE HET LEUKST VAN DIT WERK?", "antwoord": "Ik vind het leuk om de mensen naar hun ptek te brengen.\nDe bezoekers vinden dat fijn.", "pages": [579, 580], "image": "images/img_290.png"}, {"id": 291, "set": 25, "opdracht_in_set": 3, "title": "Themadag in bibliotheek", "situatie": "U volgt een opleiding tot bibliotheekmedewerker.\nU loopt stage in een bibliotheek.\nBinnenkort is er voor kinderen een themadag over dieren.\nU hebt drie dingen bedacht om met de kinderen te gaan doen.\nKijk naar de plaatjes.\nVertel uw docent welke dingen u hebt bedacht.\nU moet hierbij alle plaatjes gebruiken.\nU hoort eerst uw docent.", "vraag": "DUS JE HEBT BEDACHT: EEN THEMADAG - WAT LEUK! - WAT WIL JE GAAN DOEN MET DE KINDEREN?", "antwoord": "Kinderen vertellen over hun favoriete dier. Ik lees voor over\ndieren. En de kinderen kunnen boeken over dieren zoeken in\nde bibliotheek.", "pages": [581, 582], "image": "images/img_291.png"}, {"id": 292, "set": 25, "opdracht_in_set": 4, "title": "Thuisonderwijs", "situatie": "In Nederland moeten alle kinderen verplicht naar school. In\nsommige landen kan je thuis onderwijs volgen. Daar mogen\nouders hun kinderen lesgeven of leren kinderen via internet.\nWat vindt u van thuisonderwijs voor kinderen?\nVertel ook waarom u dat vindt. U krijgt eerst de tijd om uw\nantwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Thuisonderwijs is prima, als je een groot huis hebt. Dan is er\nrust in huis.", "pages": [583, 584], "image": null}, {"id": 293, "set": 25, "opdracht_in_set": 5, "title": "Thuiswerken", "situatie": "U werkt op de salarisadministratie van een groot bedrijf.\nU werkt vijf dagen op kantoor.\nU wilt één dag in de week thuiswerken.\nU hebt een gesprek met uw leidinggevende.\nVertel uw leidinggevende waarom u één dag in de week thuis\nwilt werken.\nU hoort eerst uw leidinggevende.", "vraag": "WAAROM WIL JE EEN DAG THUIS GAAN WERKEN?", "antwoord": "Het is op kantoor vaak heel druk. Thuis kan ik rustig werken.", "pages": [585, 586], "image": null}, {"id": 294, "set": 25, "opdracht_in_set": 6, "title": "Thuiszorg", "situatie": "U loopt stage als medewerker in de thuiszorg.\nU werkt bij iemand thuis die ziek is.\nUw stagebegeleider vraagt wat u daar vandaag hebt gedaan.\nKijk naar de plaatjes.\nVertel uw stagebegeleider wat u vandaag hebt gedaan.\nGebruik hierbij beide plaatjes.\nU hoort eerst uw stagebegeleider.", "vraag": "WAT VOOR WERK HEB JE VANDAAG GEDAAN BIJ DIE KLANT?", "antwoord": "Ik heb de lakens gestreken. En ik heb het bed opgemaakt.", "pages": [587, 588], "image": "images/img_294.png"}, {"id": 295, "set": 25, "opdracht_in_set": 7, "title": "Tips tegen spanning", "situatie": "U volgt een koksopleiding.\nVoor een opdracht moeten de studenten een nieuwe menukaart\npresenteren.\nEen medestudent is erg gespannen voor zijn presentatie.\nU weet wat hij kan doen tegen de spanning.\nVertel uw medestudent wat hij kan doen tegen de spanning.\nGeef uw medestudent twee tips.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medestudent en reageer.", "vraag": "IK BEN ZO GESPANNEN VOOR DIE PRESENTATIE ... WAT KAN IK DAARTEGEN DOEN?", "antwoord": "Luister, ik begrijp je. Doe voor de presentatie 10 minuten yoga.\nEn drink daarna een kopje thee. Dan kom je tot rust.", "pages": [589, 590], "image": null}, {"id": 296, "set": 25, "opdracht_in_set": 8, "title": "Toeristische folder", "situatie": "U volgt een mbo-opleiding Toerisme.\nVoor een opdracht moet u een folder maken voor toeristen in\nNederland.\nEen medestudent heeft twee ideeén.\nHet eerste idee is een folder over Amsterdam.\nHet tweede idee is een folder met informatie over minder\nbekende plaatsen in Nederland.\nVertel uw medestudent wat u het beste idee vindt.\nVertel ook waarom.\nGeef hiervoor twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medestudent en geef antwoord.", "vraag": "WAT VIND JIJ HET BESTE IDEE? EEN FOLDER OVER AMSTERDAM, OF EEN FOLDER OVER MINDER BEKENDE PLAATSEN IN NEDERLAND?", "antwoord": "Een folder over minder bekende plaatsen in Nederland vind ik\nbeter. Nedertand is groter dan Amsterdam. Andere plaatsen\ngijn vaak ook heel mool.", "pages": [591, 592], "image": null}, {"id": 297, "set": 25, "opdracht_in_set": 9, "title": "Toneelstuk", "situatie": "Het is feest in uw buurt.\nU helpt kinderen uit de buurt bij het maken van een toneelstuk.\nU vertelt ze wat ze moeten doen.\nKijk naar de plaatjes.\nVertel de kinderen wat ze vandaag moeten doen.\nU moet daarbij alle plaatjes gebruiken. U hoort eerst een kind.", "vraag": "WAT GAAN WE VANDAAG ALLEMAAL DOEN?", "antwoord": "Jultie moeten dingen op het toneel zetten. Jullie moeten tekst\nult het hoofd feren. En jullie moeten je omkleden.", "pages": [593, 594], "image": "images/img_297.png"}, {"id": 298, "set": 25, "opdracht_in_set": 10, "title": "Trui ruilen", "situatie": "U werkt in een kledingwinkel.\nEr komt een klant binnen.\nZe heeft een trui gekocht die ze terug wil brengen.\nZe zegt dat de trui niet past.\nKijk naar het plaatje.\nVertel de klant waarom u de trui niet terug kunt nemen.", "vraag": "GOEDEMIDDAG. IK KOM DEZE TRUI TERUGBRENGEN. HIJ PAST ME NIET.", "antwoord": "Nee, mevrouw. Dat kan niet. De trui is kapot en vies.", "pages": [595, 596], "image": "images/img_298.png"}, {"id": 299, "set": 25, "opdracht_in_set": 11, "title": "Tuincentrum", "situatie": "U werkt in een tuincentrum.\nHet is al vroeg erg druk in het tuincentrum.\nDaarom komt een collega u helpen.\nUw collega vraagt wat hij allemaal moet doen.\nKijk naar de plaatjes.\nLeg uw collega uit wat hij moet gaan doen.\nU moet daarbij alle plaatjes gebruiken.\nU hoort eerst uw collega.", "vraag": "NOU, HET WORDT INDERDAAD AL DRUK. ZEG HET MAAR, WAARMEE KAN IK JE HELPEN?", "antwoord": "Je moet planten buiten zetten. Je moet zakken met aarde in de\nwinkel leggen. En je moet bij de kassa werken.", "pages": [597, 598], "image": "images/img_299.png"}, {"id": 300, "set": 25, "opdracht_in_set": 12, "title": "Twee dingen meebrengen", "situatie": "U volgt een opleiding voor sporttrainer.\nUw docent vraagt u om morgen twee dingen mee te brengen.\nKijk naar het plaatje.\nVertel uw medecursist welke twee dingen hij morgen mee moet\nbrengen.\nU hoort eerst uw medecursist.", "vraag": "JA, MORGEN BEN IK ER WEER. [IS ER NOG IETS BIJZONDERS, MORGEN?", "antwoord": "Ja. Je moet een zwembroek meenemen. En ook een handdoek.", "pages": [599, 600], "image": "images/img_300.png"}, {"id": 301, "set": 26, "opdracht_in_set": 1, "title": "Twee manieren van leren", "situatie": "U volgt een opleiding autotechniek.\nU leert hoe een auto werkt.\nTijdens de opleiding leert u op twee manieren.\nEen medestudent vraagt welke manier u fijner vindt.\nKijk naar de plaatjes.\nVertel uw medestudent welke manier van leren u fijner vindt.\nVertel ook waarom.\nGeef twee redenen,\nU hoort eerst uw medestudent.", "vraag": "WELKE MANIER VAN LEREN VIND JIJ FIJNER?", "antwoord": "Ik vind praktijkles fijner. Ik werk graag met mijn handen. En ik\nkan niet goed studeren.", "pages": [601, 602], "image": "images/img_301.png"}, {"id": 302, "set": 26, "opdracht_in_set": 2, "title": "Twee plannen", "situatie": "U doet een opleiding in Utrecht.\nEén keer per jaar gaan de studenten samen iets leuks doen.\nDit jaar zijn er twee plannen bedacht.\nJullie kunnen gaan wandelen in het bos of eten in een\nrestaurant.\nU praat hierover met uw docent.\nVertel uw docent welk plan u het leukst vindt en waarom.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw docent en reageer.", "vraag": "VERTEL, WELK PLAN VIND JE HET LEUKST? WANDELEN IN HET BOS OF ETEN IN EEN RESTAURANT?", "antwoord": "Ik kies voor wandelen in het bos. Ik ben graag buiten. En ik\nvind een restaurant te duur.", "pages": [603, 604], "image": null}, {"id": 303, "set": 26, "opdracht_in_set": 3, "title": "Uit eten", "situatie": "Een klasgenoot vertelt dat zij in een restaurant gegeten heeft.\nEet u liever in een restaurant of eet u liever thuis?\nVertel wat u kiest.\nVertel ook waarom u dat kiest.", "vraag": "", "antwoord": "Ik eet liever thuis. Ik vind een restaurant te duur.", "pages": [605, 606], "image": null}, {"id": 304, "set": 26, "opdracht_in_set": 4, "title": "Uitgaan", "situatie": "U hebt een afspraak met een kennis om uit te gaan.\nJullie kunnen naar de film of naar een café waar muziekgroep\n‘SingSing’ optreedt.\nUw kennis vraagt wat u het liefste wilt doen.\nLuister naar uw kennis en vertel wat u het liefste wilt doen.\nVertel ook waarom.", "vraag": "WAT WIL JIJ HET LIEFSTE DOEN?", "antwoord": "Ik kies voor een concert in een café. Ik kijk liever thuls op\nde televisie naar een film.", "pages": [607, 608], "image": null}, {"id": 305, "set": 26, "opdracht_in_set": 5, "title": "Vacature hotel", "situatie": "U zoekt werk.\nOp internet ziet u een vacature voor een baan in een hotel.\nIn de vacature staat informatie over de werkzaamheden en\nhet salaris, maar niets over het hotel zelf.\nU hebt een vraag over het hotel en belt de eigenaar.\nStel een vraag aan de eigenaar over het hotel.\nU hoort eerst de eigenaar.", "vraag": "GOEDEMIDDAG, HOTEL DE SPAAN - MET MONICA MORALES...", "antwoord": "Waar staat het hotel eigeniljk?\nrend", "pages": [609, 610], "image": null}, {"id": 306, "set": 26, "opdracht_in_set": 6, "title": "Vakantie", "situatie": "U bent vorige week op vakantie geweest.\nU praat hierover met uw buurvrouw.\nKijk naar het plaatje.\nVertel uw buurvrouw wat u op vakantie hebt gedaan.\nU hoort eerst uw buurvrouw.", "vraag": "WAT HEB JE GEDAAN OP VAKANTIE?", "antwoord": "Ik was met mijn vrouw en mijn kinderen op het strand.\nWe hebben op het strand gespeeld.", "pages": [611, 612], "image": "images/img_306.png"}, {"id": 307, "set": 26, "opdracht_in_set": 7, "title": "Vakantiepark", "situatie": "U bent met uw kinderen naar een vakantiepark geweest.\nKijk naar het plaatje.\nLuister naar uw buurvrouw en reageer.", "vraag": "H€, HALLOI JE BENT TOCH NAAR EEN VAKANTIEPARK GEWEEST? WAT IS ER ALLEMAAL TE DOEN VOOR DE KINOEREN?", "antwoord": "Ja, heel veel. Ze kunnen zwemmen. En er is een speettuin.", "pages": [613, 614], "image": "images/img_307.png"}, {"id": 308, "set": 26, "opdracht_in_set": 8, "title": "Veiligheid in vliegtuigen", "situatie": "U volgt een opleiding bij een vliegtuigmaatschappij.\nU moet uw medestudenten iets vertellen over de veiligheid in\nvliegtuigen.\nKijk naar de plaatjes.\nVertel uw medestudenten wat reizigers moeten doen, voordat\nhet vliegtuig vertrekt.", "vraag": "", "antwoord": "De passagiers moeten de gordel vastmaken. Zij moeten hun\nbagage niet onder de stoel zetten. En zij moeten de stoel\nrechtop zetten.", "pages": [615, 616], "image": "images/img_308.png"}, {"id": 309, "set": 26, "opdracht_in_set": 9, "title": "Verboad op mobiele teletoons", "situatie": "Steeds vaker verbieden opleidingen het gebruik van mobiele\ntelefoons tijdens de les.\nWat vindt u ervan dat opleidingen steeds vaker mobiele\ntelefoons verbieden tijdens de les?\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind dat prima. Studenten kunnen de telefoon in de pauze\ngebruiken.", "pages": [617, 618], "image": null}, {"id": 310, "set": 26, "opdracht_in_set": 10, "title": "Verf kopen", "situatie": "U staat samen met een vriend in een verfwinkel.\nUw vriend wil rode verf kopen om de muren van zijn kamer te\nverven.\nUw vriend wil weten wat u daarvan vindt.\nLuister naar uw vriend en reageer.", "vraag": "WAT VIND JE VAN DEZE RODE VERF VOOR MIJN KAMER?", "antwoord": "Ik vind rood niet mooi.", "pages": [619, 620], "image": null}, {"id": 311, "set": 26, "opdracht_in_set": 11, "title": "Verffabriek", "situatie": "U werkt in een verffabriek.\nVandaag komt er een gast naar de fabriek kijken.\nU zult hem de fabriek laten zien.\nDe gast moet eerst speciale kleding aantrekken.\nHij vraagt waarom dat moet.\nKijk naar het plaatje.\nLuister naar de gast en geef antwoord.", "vraag": "TJONGE, WAAROM MOET IK DIT PAK AAN?", "antwoord": "Overal is verf in deze fabriek. De verf kan op je kleding komen.", "pages": [621, 622], "image": "images/img_311.png"}, {"id": 312, "set": 26, "opdracht_in_set": 12, "title": "Vergeten paraplu", "situatie": "U werkt als chauffeur in een bus.\nVandaag heeft u een groep toeristen rondgereden.\nIemand uit de groep is vergeten zijn paraplu mee te nemen\nnaar huis.\nU belt met de begeleider van de groep.\nKijk naar het plaatje.\nNoem twee dingen.\nGebruik daarbij het plaatje.\nU hoort eerst de begeleider van de groep.", "vraag": "FIJN, DAT U BELT ... HOE ZIET DE PARAPLU ERUIT?", "antwoord": "De paraplu is rood met zwarte stippen.", "pages": [623, 624], "image": "images/img_312.png"}, {"id": 313, "set": 27, "opdracht_in_set": 1, "title": "Verhuisbedrijf", "situatie": "U werkt voor een verhuisbedrijf.\nVandaag werkt u samen met een nieuwe collega.\nU moet hem vertellen wat hij moet doen.\nKijk naar de plaatjes.\nVertel uw collega wat hij moet doen.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw collega.", "vraag": "WAT MOET IK DOEN?", "antwoord": "Je moet spullen in dozen doen. Je moet samen met mij de\ndozen in de auto zetten. En je moet met de auto naar het\nnieuwe adres rijden.", "pages": [625, 626], "image": "images/img_313.png"}, {"id": 314, "set": 27, "opdracht_in_set": 2, "title": "Verjaardag |", "situatie": "U bent jarig geweest.\nU praat hierover met een collega.\nKijk naar de plaatjes.\nVertel uw collega hoe uw verjaardag was.\nGebruik de plaatjes. U hoort eerst uw collega.", "vraag": "HOE WAS JE VERJAARDAG?", "antwoord": "Ik was gisteren jarig, ja. Ik heb veel cadeautjes van mijn\nkinderen gekregen.", "pages": [627, 628], "image": "images/img_314.png"}, {"id": 315, "set": 27, "opdracht_in_set": 3, "title": "Versiag", "situatie": "U volgt een opleiding tot administratief medewerker.\nEen medestudent heeft een versiag gemaakt.\nHij vraagt u hoe hij het verslag bij de docent moet inleveren.\nKijk naar de plaatjes.\nLuister naar uw medestudent en reageer.\nGebruik de plaatjes.", "vraag": "WAT VERVELEND DAT IK HET VERSLAG NIET MAG MAILEN. HOE MOET IK HET DAN INLEVEREN?", "antwoord": "Je moet het verslag printen. En je moet het versiag op papier\naan de docent geven.", "pages": [629, 630], "image": "images/img_315.png"}, {"id": 316, "set": 27, "opdracht_in_set": 4, "title": "Verslag kwijt", "situatie": "U volgt een opleiding.\nUw medestudent vertelt u dat haar computer gisteravond kapot\nIs gegaan.\nHierdoor is zij een belangrijk versiag kwijtgeraakt.\nZij moet dat verslag morgen al inleveren.\nZij vraagt u wat zij nu het beste kan doen.\nVertel uw medestudent wat zij volgens u het beste kan doen.\nVertel ook waarom u dat de beste oplossing vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medestudent en reageer.", "vraag": "MIJN HELE VERSLAG IS WEG. EN MORGEN MOET IK HET AL INLEVEREN. WAT MOET IK NU DOEN?", "antwoord": "Je moet snel contact opnemen met de docent. De docent zegt\nwat je moet doen.", "pages": [631, 632], "image": null}, {"id": 317, "set": 27, "opdracht_in_set": 5, "title": "Vertellen aan politie", "situatie": "U woont in een buurt met veel jongeren.\nU ziet dat er buiten iets gebeurt.\nKijk naar het plaatje.\nLuister naar de politieagent en vertel hem wat u gezien hebt.", "vraag": "WAT HEEFT U PRECIES GEZIEN?", "antwoord": "Ik heb twee jongens bij de bushalte gezien. Zij hebben met\nstokken de bushalte kapot gemaakt.", "pages": [633, 634], "image": "images/img_317.png"}, {"id": 318, "set": 27, "opdracht_in_set": 6, "title": "Vervelende taak", "situatie": "U werkt bij de administratie van een grote vereniging.\nU moet samen met een collega nieuwsbrieven naar de leden\nUw collega heeft hier geen zin in.\nZe wil de taak pas volgende week doen.\nU wilt het liever vandaag doen.\nVerte! uw collega dat u de taak liever vandaag doet.\nVertel ook waarom.\nU hoort eerst uw collega.", "vraag": "WE KUNNEN DIE TAAK TOCH OOK VOLGENDE WEEK DOEN?", "antwoord": "We kunnen het beter vandaag doen. Jij hebt volgende week\nmisschien óók geen zin.", "pages": [635, 636], "image": null}, {"id": 319, "set": 27, "opdracht_in_set": 7, "title": "Verzorgingstehuis", "situatie": "U werkt drie ochtenden per week in een verzorgingstehuis.\nUw buurvrouw vraagt wat u daar allemaal doet.\nKijk naar de plaatjes.\nVertel uw buurvrouw wat u doet.\nGebruik daarbij alle plaatjes. U hoort eerst uw buurvrouw.", "vraag": "DUS JE WERKT IN EEN VERZORGINGSTEHUIS. WAT DOE JE DAAR PRECIES?", "antwoord": "Ik moet de kamers stofzuigen. En ik geef de planten water.", "pages": [637, 638], "image": "images/img_319.png"}, {"id": 320, "set": 27, "opdracht_in_set": 8, "title": "Vijver aanleggen", "situatie": "U werkt als tuinman.\nU maakt een vijver in de tuin van een klant.\nHet 2-jarige kind van de klant loopt steeds alleen door de tuin.\nU wilt de klant iets verzoeken.\nDoe een verzoek aan de klant.\nLeg ook uit waarom u dit verzoekt.\nGeef hiervoor twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar de klant en reageer.", "vraag": "WAT WILDE U VRAGEN?", "antwoord": "Wilt u het kind in het huis houden? Ik kan niet goed werken zo.\nEn uw kind wordt heel vies in de tuin.", "pages": [639, 640], "image": null}, {"id": 321, "set": 27, "opdracht_in_set": 9, "title": "Voetbalvereniging", "situatie": "Uw zoon voetbalt bij een voetbalvereniging.\nU bent vrijwilliger bij de vereniging.\nDe voetbalvereniging zoekt nog meer vrijwilligers.\nOp een vergadering legt u uit welke functies er zijn voor\nvrijwilligers.\nKijk naar de plaatjes.\nVertel welke drie functies er zijn bij de voetbalvereniging.\nU moet hierbij alle plaatjes gebruiken.\nU hoort eerst de voorzitter van de voetbalvereniging.", "vraag": "KUN JE NOG EVEN UITLEGGEN WELKE FUNCTIES ER ZIJN VOOR VRIJWILLIGERS?", "antwoord": "We zoeken mensen die de nieuwsbrief kunnen schrijven. We\nzoeken trainers. En we zoeken mensen die in de kantine\nhelpen.", "pages": [641, 642], "image": "images/img_321.png"}, {"id": 322, "set": 27, "opdracht_in_set": 10, "title": "Voorlichting politie", "situatie": "U werkt bij de politie.\nU gaat samen met collega’s op scholen informatie geven over\nhet werk van een politieagent.\nU kunt kiezen uit informatie geven op basisscholen of op\nmiddelbare scholen.\nUw collega vraagt naar welk soort school u liever gaat.\nVertel uw collega naar welk soort school u liever gaat: een\nbasisschool of naar een middelbare school.\nVertel ook waarom,\nU hoort eerst uw collega.", "vraag": "NAAR WELK SOORT SCHOOL GA JIJ LIEVER?", "antwoord": "Ik ga liever naar de basisschool. Kleine kinderen luisteren goed\nNaar mij en grote kinderen luisteren niet goed naar mij.", "pages": [643, 644], "image": null}, {"id": 323, "set": 27, "opdracht_in_set": 11, "title": "Vraag in restaurant", "situatie": "U werkt in een restaurant.\nEen klant stelt u een vraag.\nDe klant wil weten hoe het werkt.\nKijk naar het plaatje.\nVertel aan de klant hoe het werkt.\nGebruik het plaatje.\nU hoort eerst de klant.", "vraag": "IK WIL GRAAG WAT TE ETEN. MAAR IK BEGRIJP NIET HOE HET WERKT. KUNT U HET MIJ UITLEGGEN?", "antwoord": "U pakt eerst een bord. Dan pakt u dingen die u wilt eten. En\ndan moet u betalen bij de kassa.", "pages": [645, 646], "image": "images/img_323.png"}, {"id": 324, "set": 27, "opdracht_in_set": 12, "title": "Vrachtwagenchauffeur", "situatie": "U bent vrachtwagenchauffeur bij een groot bedrijf.\nU kunt uit verschillende soorten ritten kiezen.\nU kunt in een grote stad korte afstanden rijden of u kunt lange\nafstanden naar het buitenland rijden.\nWilt u liever korte afstanden of lange afstanden rijden?\nGeef hiervoor ten minste twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik rijd liever lange afstanden. Ik wil graag andere landen zien.\nEn i rijd ook graag op de snelweg. Ik rijd niet graag met een\nvrachtwagen in een stad.", "pages": [647, 648], "image": null}, {"id": 325, "set": 28, "opdracht_in_set": 1, "title": "Vrij moeten nemen", "situatie": "U werkt op een kantoor.\nDe laatste week van het jaar is het kantoor gesloten.\nAlle werknemers moeten die week vrij nemen.\nUw collega vraagt wat u van die regel vindt.\nVertel uw collega wat u van die regel vindt.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw collega en reageer.", "vraag": "NU MOETEN WE ALLEMAAL VRIJ NEMEN DE LAATSTE WEEK VAN HET JAAR... WAT VIND JIJ DAAR EIGENLIJK VAN?", "antwoord": "Ik vind het prima. Ik ben graag thuis tijdens de feestdagen.", "pages": [649, 650], "image": null}, {"id": 326, "set": 28, "opdracht_in_set": 2, "title": "Vrij vragen", "situatie": "Uw beste vriendin woont in het buitenland.\nIn de zomer komt ze een week bij u op bezoek.\nDaarom wilt u in die week vrij hebben van uw werk.\nU praat daarover met uw baas.\nLuister naar uw baas en reageer.", "vraag": "DUS JE WILT DIE WEEK VRIJ HEBBEN. MAAR DAT IS DE DRUKSTE WEEK VAN DE ZOMER...", "antwoord": "Ja, maar mijn beste vriendin komt op bezoek uit het\nbuitenland. Ik wil heel graag met haar dingen doen.", "pages": [651, 652], "image": null}, {"id": 327, "set": 28, "opdracht_in_set": 3, "title": "Vrijwilligerswerk", "situatie": "Uw vriend kan geen werk vinden.\nU vindt het een goed idee als hij vrijwilligerswerk gaat doen, tot\nhij wel werk heeft.\nVertel waarom u vindt dat hij vrijwilligerswerk moet gaan doen.\nGeef hiervoor ten minste twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw vriend en reageer.", "vraag": "WAAROM ZOU IK VRIJWILLIGERS WERK GAAN DOEN?", "antwoord": "Luister: je krijgt dan werkervaring. En thuisblijven is ook saai.", "pages": [653, 654], "image": null}, {"id": 328, "set": 28, "opdracht_in_set": 4, "title": "Vroege of late dienst", "situatie": "U werkt van maandag tot en met donderdag in een fabriek.\nU gaat vanaf volgende maand ook op vrijdag werken.\nUw leidinggevende wil weten of u dan de vroege of de late\ndienst wilt werken.\nDe vroege dienst start om zeven uur ‘s ochtends en de late\ndienst start om twee uur ‘s middags.\nVertel waarvoor u kiest: de vroege dienst of de late dienst.\nVertel ook waarom.\nGeef twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw leidinggevende en reageer.", "vraag": "WELKE DIENST KIES JE? DE VROEGE OF DE LATE?", "antwoord": "Ik kies voor de vroege dienst. Ik ben dan extra vroeg thuis\nbij mijn kinderen. En ik wil ook extra lang genieten van het\nweekend.", "pages": [655, 656], "image": null}, {"id": 329, "set": 28, "opdracht_in_set": 5, "title": "Waar meelopen?", "situatie": "U volgt de opleiding tot verkoopmedewerker.\nU mag een dag meelopen in een winkel.\nU kunt meelopen met iemand die in een kledingwinkel werkt of\nmet iemand die in een computerwinkel werkt.\nVertel wat u kiest.\nVertel ook waarom u dat kiest.", "vraag": "", "antwoord": "Ik kies voor meelopen in de kledingwinkel. Ik houd van\nkleding en ik weet niets van computers.", "pages": [657, 658], "image": null}, {"id": 330, "set": 28, "opdracht_in_set": 6, "title": "Wandelen in de pauze", "situatie": "Steeds meer bedrijven willen dat werknemers in hun lunchtijd\neen wandeling gaan maken.\nVertel wat u van wandelen in de pauze vindt.\nVertel ook waarom u dat vindt.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik vind wandelen in de pauze prima. Wandelen is gezond.", "pages": [659, 660], "image": null}, {"id": 331, "set": 28, "opdracht_in_set": 7, "title": "Wandeling door het bos", "situatie": "U volgt de opleiding Bos- en Natuurbeheer.\nVoor een stage-opdracht moet u een wandeling organiseren\ndoor het bos.\nU kunt kiezen tussen een wandeling voor kinderen van een\nbasisschool en een wandeling voor volwassenen.\nVoor wie organiseert u het liefst een wandeling door het bos?\nGeef twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nBegin na de pieptoon met spreken.", "vraag": "", "antwoord": "Ik kies voor een wandeling met volwassenen. Kinderen houden\nniet van wandelen, zij willen spelen. En volwassenen wandelen\nveel beter.", "pages": [661, 662], "image": null}, {"id": 332, "set": 28, "opdracht_in_set": 8, "title": "Wel naar de toets", "situatie": "U volgt een opleiding.\nMorgen is er een toets.\nEen medestudent wil niet naar de toets gaan.\nDe medestudent denkt dat hij niet zal slagen.\nU vindt dat hij wel moet gaan.\nVertel uw medestudent waarom hij wel moet gaan.\nU hoort eerst uw medestudent.", "vraag": "NOU, IK DENK DAT IK MORGEN NIET NAAR DE TOETS GA. IK SLAAG VAST NIET.", "antwoord": "Kom op! Je moet het gewoon proberen. Misschien slaag je\ntoch!", "pages": [663, 664], "image": null}, {"id": 333, "set": 28, "opdracht_in_set": 9, "title": "Welke sport", "situatie": "U praat met vrienden over sport.\nDe ene vriend zwemt veel en de andere vriend gaat vaak\nhardlopen.\nZij vragen u welke van deze sporten u graag zou doen.\nVertel uw vrienden welke van deze twee sporten u graag zou\nVertel ook waarom u deze sport kiest.\nGeef hiervoor ten minste twee redenen.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw vriend en reageer.", "vraag": "ALS JE MOET KIEZEN, KIES JE DAN VOOR ZWEMMEN OF VOOR HARDLOPEN?", "antwoord": "Ik ktes voor hardlopen. Ik houd niet van water en ik kan niet\nheel goed zwemmen.", "pages": [665, 666], "image": null}, {"id": 334, "set": 28, "opdracht_in_set": 10, "title": "Welke sport met kinderen", "situatie": "U volgt de mbo-opleiding Sport en Bewegen.\nVoor een opdracht moet u samen met een medestudent gaan\nsporten met kinderen.\nUw medestudent stelt voor om te gaan zwemmen.\nU vindt dat jullie beter kunnen gaan voetballen.\nOvertuig uw medestudent ervan dat voetballen een betere\nkeuze is.\nGeef hiervoor twee argumenten.\nU krijgt eerst de tijd om uw antwoord voor te bereiden.\nLuister daarna naar uw medestudent en reageer.", "vraag": "WAAROM DENK JE DAT VOETBALLEN EEN BETERE KEUZE IS?", "antwoord": "We kunnen met de kinderen beter voetballen. Veel kinderen\nkunnen niet goed zwemmen. En alle kinderen houden van\nvoetballen", "pages": [667, 668], "image": null}, {"id": 335, "set": 28, "opdracht_in_set": 11, "title": "Werk kiezen", "situatie": "U zoekt werk.\nDaarom hebt u een afspraak bij het uitzendbureau.\nHet uitzendbureau helpt u bij het zoeken naar werk.\nDe medewerker wil weten wat voor opleiding of beroep het best\nbij u past.\nDaarom moet u een beroepskeuzetest doen.\nKijk naar de plaatjes.\nVertel welk beroep u zou kiezen.\nZeg ook waarom u dat beroep kiest.\nGebruik hierbij beide plaatjes.\nU hoort eerst de medewerker.", "vraag": "WELKE OPLEIDING OF BAAN PAST HET BEST BIJ U7", "antwoord": "Ik kies voor het beroep: boer. Ik wil graag op een tractor rijden.", "pages": [669, 670], "image": "images/img_335.png"}, {"id": 336, "set": 28, "opdracht_in_set": 12, "title": "Werken bij een restaurant", "situatie": "U werkt in een restaurant.\nEr gaat iets mis.\nKijk naar het plaatje.", "vraag": "WAT IS ER?", "antwoord": "Ik heb mij gesneden. Wil je een pleister voor mij halen?", "pages": [671, 672], "image": "images/img_336.png"}, {"id": 337, "set": 29, "opdracht_in_set": 1, "title": "Werken in het park", "situatie": "U loopt stage bij de gemeente.\nVandaag werkt u met een medestudent in het stadspark.\nUw medestudent weet niet meer wat jullie vandaag moeten\ndoen.\nKijk naar de plaatjes.\nVertel uw medestudent wat jullie vandaag gaan doen.\nGebruik hierbij beide plaatjes.\nLuister naar uw medestudent en reageer.", "vraag": "WAT MOESTEN WE VANDAAG OOK AL WEER DOEN?", "antwoord": "We moeten biaderen vegen. En we moeten de bladeren in een\ncontainer goolen.", "pages": [673, 674], "image": "images/img_337.png"}, {"id": 338, "set": 29, "opdracht_in_set": 2, "title": "Werken in het weekend", "situatie": "Uw vriend vertelt dat hij graag meer wil werken in het weekend.\nHij krijgt dan meer geld.\nVertel uw vriend waarom u dit géén goed idee vindt.\nU hoort eerst uw vriend.", "vraag": "WAAROM ZOU IK HET NIET OOENT IK KRIJG IN HET WEEKENO MEER BETAALD...", "antwoord": "Je moet niet in het weekend werken. Je moet genieten van je\nvrije tijd. Vrije tijd is belangrijk.", "pages": [675, 676], "image": null}, {"id": 339, "set": 29, "opdracht_in_set": 3, "title": "Werken met kinderen", "situatie": "U werkt op een kinderdagverblijf.\nEris vandaag een nieuw jongetje.\n*s Middags vraagt zijn moeder wat haar zoontje heeft gedaan.\nKijk naar de plaatjes.\nVertel de moeder wat haar zoontje heeft gedaan.\nGebruik hierbij alle plaatjes.\nU hoort eerst de moeder.", "vraag": "WAT HEEFT HIJ VANDAAG GEDAAN?", "antwoord": "Hij heeft gezongen met de andere kinderen. Hij heeft gespeeld\nmet de brandweerauto. En hij heeft ruzie gemaakt met een\nandere jongen.", "pages": [677, 678], "image": "images/img_339.png"}, {"id": 340, "set": 29, "opdracht_in_set": 4, "title": "Werken of studeren", "situatie": "U volgt een taalcursus.\nU hebt een gesprek met uw begeleider over wat u gaat doen na\nde taallessen.\nU hebt twee mogelijkheden.\nU probeert zo snel mogelijk werk te vinden of u gaat nog een\njaar naar school om een diploma te halen.\nVertel wat u het liefste doet: direct gaan werken of eerst een\ndiploma halen.\nVertel ook waarom u dat wilt.", "vraag": "", "antwoord": "Ik wil direct gaan werken. Ik wil graag geld verdienen.", "pages": [679, 680], "image": null}, {"id": 341, "set": 29, "opdracht_in_set": 5, "title": "Werkstuk", "situatie": "U volgt een opleiding tot dierverzorger.\nEen medestudente heeft een probleem.\nVolgende week moet ze een werkstuk inleveren, maar ze is een\npaar dagen ziek geweest.\nGeef uw medestudente advies.\nU hoort eerst uw medestudente.", "vraag": "IK BEN HET HELE WEEKEND ZIEK GEWEEST. HOE MOET IK NU ALLES AF KRIJGEN? WAT ZOU JIJ DOEN?", "antwoord": "Je moet zo snel mogelijk contact opnemen met je docent. Hij\nweet een oplossing.", "pages": [681, 682], "image": null}, {"id": 342, "set": 29, "opdracht_in_set": 6, "title": "Werkstuk maken", "situatie": "U volgt een opleiding.\nU hebt samen met een medecursist een werkstuk gemaakt.\nHet is nog niet helemaal af.\nKijk naar de plaatjes.\nVertel haar precies wat ze nog kan doen.", "vraag": "", "antwoord": "Je kunt plaatjes plakken in het document. Je kunt het\ndocument kopiéren. En je kunt dan boekjes maken van de\nkopleén.", "pages": [683, 684], "image": "images/img_342.png"}, {"id": 343, "set": 29, "opdracht_in_set": 7, "title": "Werkzaamheden collega", "situatie": "U werkt bij een bouwbedrijf.\nVanmiddag hebt u vrij.\nUw collega moet een paar dingen voor u afmaken.\nKijk naar de plaatjes.\nVertel uw collega wat hij vandaag kan doen.\nGebruik hierbij alle plaatjes.\nU hoort eerst uw collega.", "vraag": "DUS JE GAAT NAAR HUIS. WAAR KAN IK VANMIDDAG HET BESTE MEE VERDERGAAN?", "antwoord": "Je moet de deur terugzetten. Je moet een slot op de deur\nmaken. En je moet nog een bel naast de deur monteren.", "pages": [685, 686], "image": "images/img_343.png"}, {"id": 344, "set": 29, "opdracht_in_set": 8, "title": "Woorden onthouden", "situatie": "U volgt de opleiding Toerisme.\nVoor het vak Engels moet u veel nieuwe woorden leren.\nEen medestudent vindt dat moeilijk: hij vergeet de woorden\nsteeds.\nHij vraagt wat hij kan doen om de nieuwe woorden beter te\nonthouden.\nVertel uw medestudent wat hij kan doen om de nieuwe\nwoorden te onthouden.\nU hoort eerst uw medestudent.", "vraag": "WAT KAN IK DOEN OM DE NIEUWE WOORDEN BETER TE ONTHOUDEN?", "antwoord": "Je moet nieuwe woorden altijd met pen op papier schrijven.\nDan vergeet je de woorden niet zo snel.", "pages": [687, 688], "image": null}, {"id": 345, "set": 29, "opdracht_in_set": 9, "title": "Yoga", "situatie": "U volgt met een vriendin een cursus yoga.\nU heeft vandaag een nieuwe oefening geleerd.\nUw vriendin heeft de les gemist.\nZe vraagt of u haar de oefening kunt uitleggen.\nDat wilt u wel doen.\nKijk naar de plaatjes.\nLeg uw vriendin uit hoe zij de oefening moet doen.\nGebruik hierbij alle plaatj", "vraag": "MOET DOEN?", "antwoord": "KUN JIJ ME VERTELLEN HOE IK DiE NIEUWE OEFENING\nJe zit op de grond. Als een kleermaker, je weet wel. Dan moet\nje met de linkerhand de rechterknie aanraken. Daama moet je\nmet de rechterhand de linkerknie aanraken.", "pages": [689, 690], "image": "images/img_345.png"}, {"id": 346, "set": 29, "opdracht_in_set": 10, "title": "Zaterdag of zondag?", "situatie": "U werkt in een schoenenwinkel.\nDe winkel is ook op zondag open.\nUw baas wil dat u één dag in het weekend komt werken.\nU kunt kiezen of u op zaterdag of op zondag komt werken.\nVertel uw baas welke dag u kiest.\nVertel ook waarom u die dag kiest.\nU hoort eerst uw baas.", "vraag": "WIL JE IN DE WEEKENDEN OP ZATERDAG OF OP ZONDAG WERKEN?", "antwoord": "Ik kies voor de zondag. Op zaterdag ga ik sporten.\nhod", "pages": [691, 692], "image": null}, {"id": 347, "set": 29, "opdracht_in_set": 11, "title": "Ziekenhuisbed", "situatie": "U werkt in een ziekenhuis.\nVandaag moet u een bed van de ene afdeling naar een andere\nbrengen.\nEris een probleem.\nKijk naar het plaatje.", "vraag": "JA, MET ELLEN VEENSTRA VAN DE TECHNISCHE DIENST?", "antwoord": "wiel. Kun je even langskomen?", "pages": [693, 694], "image": "images/img_347.png"}, {"id": 348, "set": 29, "opdracht_in_set": 12, "title": "Ziekenhuiskeuken", "situatie": "U werkt in de keuken van een ziekenhuis.\nVandaag komt er een stagiair.\nKijk naar het plaatje.\nLuister naar uw stagiair en reageer.", "vraag": "WAT MOET IK DOEN VANDAAG?", "antwoord": "Ja, hol ... je moet vandaag heel veel groente snijden.", "pages": [695, 696], "image": "images/img_348.png"}, {"id": 349, "set": 30, "opdracht_in_set": 1, "title": "Zorghulp |", "situatie": "U bent zorghulp.\nEen zorghulp werkt bij zieke mensen thuis.\nVandaag gaat een nieuwe collega naar mevrouw Melders.\nKijk naar de plaatjes.\nLuister naar uw collega en reageer.", "vraag": "WAT MOET IK DOEN BIJ MEVROUW MELDERS?", "antwoord": "Oké, je moet mevrouw Meiders wassen. En je moet mevrouw\nMelders aankleden.", "pages": [697, 698], "image": "images/img_349.png"}, {"id": 350, "set": 30, "opdracht_in_set": 2, "title": "Zwemles", "situatie": "Uw kind gaat iedere week op woensdagmiddag naar zwemles.\nEen medewerkster van het zwembad vertelt u dat de tijden van\nde zwemlessen worden gewijzigd.\nVanaf volgende maand is de zwemles van uw kind op\nzaterdagochtend.\nVertel wat u van deze wijziging vindt.\nVertel ook waarom u dat vindt.\nU hoort eerst de medewerkster.", "vraag": "WE GAAN DE TIJDEN VAN DE ZWEMLESSEN AANPASSEN. VANAF VOLGENDE MAAND !S DE LES VAN UW KIND NIET MEER OP WOENSOAGMIDDAG MAAR OP ZATERDAGOCHTEND.", "antwoord": "Oh, dat is niet fijn.\nOp zaterdagochtend moet mijn kind voetballen.", "pages": [699, 700], "image": null}];
